insert into public.questions (id, topic, source, q, opts, ans_idx, exp, category, category_icon, is_active)
values
(8304, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is the most accurate definition of research?', '["A systematic, rigorous and logical process of inquiry that seeks to answer questions and generate new knowledge", "The act of reading widely around a clinical topic before writing a report", "Any opinion a nurse forms after observing a patient once", "A collection of anecdotes gathered from colleagues about a clinical practice"]'::jsonb, 0, 'Research is formally defined as a systematic, rigorous, and logical process of scientific inquiry undertaken to discover facts, answer questions, or generate new knowledge.', 'Pre-Council', '🎓', true),
(8305, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Basic (pure) research differs from applied research mainly because basic research is primarily aimed at', '["Generating or expanding general scientific knowledge and theory without immediate practical application", "Solving an immediate, specific clinical problem in a particular ICU", "Evaluating whether a new hospital policy improved patient outcomes", "Testing a new nursing protocol for direct bedside implementation"]'::jsonb, 0, 'Basic research seeks to expand fundamental knowledge and theory for its own sake, whereas applied research is directed at solving practical, real-world problems.', 'Pre-Council', '🎓', true),
(8306, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Applied research in Critical Care Nursing is best described as research that', '["Uses findings to solve practical clinical problems and improve patient care directly", "Is conducted only in university laboratories", "Has no relevance to nursing practice", "Is concerned solely with building abstract theoretical models"]'::jsonb, 0, 'Applied research takes existing knowledge and theory and applies it to solve practical problems encountered in real clinical settings such as the ICU.', 'Pre-Council', '🎓', true),
(8307, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Quantitative research is characterized by', '["Collection and statistical analysis of numerical data to test hypotheses or describe variables objectively", "In-depth exploration of lived experiences using words and narratives without numbers", "Reliance solely on the researcher''s personal opinion", "Avoidance of any form of measurement"]'::jsonb, 0, 'Quantitative research emphasizes objective measurement and statistical, mathematical analysis of numerical data.', 'Pre-Council', '🎓', true),
(8308, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Qualitative research is best suited to studies that aim to', '["Explore and understand the meaning, experiences, and perspectives of individuals in depth", "Determine the statistical correlation between two numerically measured variables", "Test a hypothesis using a large randomly selected sample and inferential statistics", "Measure the precise incidence rate of a disease in a population"]'::jsonb, 0, 'Qualitative research explores phenomena in depth through non-numerical data such as words, focusing on meaning and lived experience rather than statistical measurement.', 'Pre-Council', '🎓', true),
(8309, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A study that describes the characteristics of ventilator-associated pneumonia rates in an ICU without manipulating any variable is an example of', '["Descriptive research", "True experimental research", "Quasi-experimental research", "Historical research"]'::jsonb, 0, 'Descriptive research simply observes and describes characteristics of a phenomenon as it naturally occurs, without manipulating variables.', 'Pre-Council', '🎓', true),
(8310, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which type of research involves the researcher deliberately manipulating an independent variable and randomly assigning subjects to groups to determine cause and effect?', '["True experimental research", "Descriptive research", "Historical research", "Case study research"]'::jsonb, 0, 'True experimental research is distinguished by manipulation of the independent variable, use of a control group, and random assignment of subjects, allowing causal inference.', 'Pre-Council', '🎓', true),
(8311, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Historical research in nursing is primarily concerned with', '["Systematically collecting and evaluating data related to past events to understand their influence on the present", "Predicting future patient outcomes using statistical models", "Manipulating an intervention to observe its immediate effect", "Describing current staffing patterns in an ICU"]'::jsonb, 0, 'Historical research systematically examines and interprets past events, records, and documents to understand their significance and influence on present nursing practice.', 'Pre-Council', '🎓', true),
(8312, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The overall purpose of research in nursing can best be summarized as', '["To generate, refine, and expand knowledge that improves nursing practice and patient outcomes", "To fulfil an academic requirement with no further use", "To criticize the work of other clinicians", "To increase hospital administrative paperwork"]'::jsonb, 0, 'The fundamental purpose of nursing research is the systematic generation and application of knowledge to improve the quality of patient care and advance the profession.', 'Pre-Council', '🎓', true),
(8313, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following best distinguishes exploratory research from other research purposes?', '["It is conducted to investigate a little-understood phenomenon in order to gain insight before more structured study", "It is used only to confirm a well-established theory", "It always uses randomized controlled trial designs", "It never involves any form of data collection"]'::jsonb, 0, 'Exploratory research is undertaken when a phenomenon is poorly understood, aiming to gain preliminary insight and generate ideas for further investigation.', 'Pre-Council', '🎓', true),
(8314, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A research purpose focused on determining whether an increase in nurse-to-patient ratio causes a reduction in medication errors is best described as', '["Explanatory (causal) research", "Purely descriptive research", "Historical research", "Exploratory research with no measurable variables"]'::jsonb, 0, 'Explanatory research seeks to establish cause-and-effect relationships between variables, such as staffing ratio and medication error rates.', 'Pre-Council', '🎓', true),
(8315, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which statement correctly differentiates a research ''design'' from a research ''method''?', '["Design is the overall plan or blueprint for conducting the study, while method refers to the specific techniques used to collect and analyze data", "Design and method mean exactly the same thing and are interchangeable", "Method is broader than design and encompasses the entire study", "Design refers only to statistical tests used"]'::jsonb, 0, 'Research design is the overarching blueprint guiding the whole study, while research methods are the specific tools and techniques (e.g., questionnaires, interviews) used within that design.', 'Pre-Council', '🎓', true),
(8316, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The primary significance of research to Critical Care Nursing practice is that it', '["Provides evidence-based knowledge that improves the quality and safety of care for critically ill patients", "Increases the cost of running an intensive care unit without any benefit", "Replaces the need for clinical judgment entirely", "Is only relevant to nurse educators, not bedside practitioners"]'::jsonb, 0, 'Research generates the evidence base that underpins safe, effective, and high-quality nursing interventions for critically ill patients.', 'Pre-Council', '🎓', true),
(8317, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Evidence-based practice (EBP) in the ICU is best described as', '["The conscientious integration of the best available research evidence with clinical expertise and patient values", "Relying only on tradition and personal experience regardless of current evidence", "Following hospital policy without ever questioning its basis", "A practice based purely on statistical data with no consideration of the patient"]'::jsonb, 0, 'Evidence-based practice integrates the best current research evidence, clinical expertise, and patient preferences to guide clinical decision-making.', 'Pre-Council', '🎓', true),
(8318, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Research helps Critical Care Nurses to do all of the following EXCEPT', '["Eliminate the need for continuing professional education", "Validate and refine nursing interventions used in critically ill patients", "Identify best practices for preventing complications such as ventilator-associated pneumonia", "Build a scientific body of knowledge unique to critical care nursing"]'::jsonb, 0, 'Research complements rather than eliminates continuing education; it is one of several means by which nurses keep their knowledge and skills current.', 'Pre-Council', '🎓', true),
(8319, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'One major significance of research is that it enables Critical Care Nurses to', '["Justify and defend nursing interventions with scientific evidence during multidisciplinary decision-making", "Avoid documentation of patient care", "Ignore patient outcomes data when planning care", "Depend solely on physicians'' orders without independent clinical reasoning"]'::jsonb, 0, 'A strong evidence base allows nurses to confidently justify their interventions and contribute meaningfully to multidisciplinary care decisions.', 'Pre-Council', '🎓', true),
(8320, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Why is research particularly significant in reducing complications such as central line-associated bloodstream infections (CLABSI) in the ICU?', '["Research identifies and validates effective evidence-based bundles of care that reduce such complications", "Research has no role in infection prevention", "CLABSI rates are unrelated to nursing care", "Only physicians can use research findings to reduce infection rates"]'::jsonb, 0, 'Research has generated evidence-based ''care bundles'' (e.g., insertion and maintenance bundles) that nurses use to significantly reduce CLABSI rates.', 'Pre-Council', '🎓', true),
(8321, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Research contributes to professional accountability in Critical Care Nursing by', '["Providing a scientific rationale that nurses can use to justify their practice decisions to patients, employers and regulatory bodies", "Removing the nurse''s responsibility for patient outcomes", "Making documentation unnecessary", "Shifting all accountability to hospital management"]'::jsonb, 0, 'Research-based evidence strengthens professional accountability by giving nurses a defensible, scientific rationale for their clinical decisions.', 'Pre-Council', '🎓', true),
(8322, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following best illustrates the significance of research in advancing the nursing profession''s status?', '["Building a distinct, scientifically validated body of nursing knowledge that distinguishes nursing as an autonomous profession", "Copying protocols used exclusively by other professions without adaptation", "Avoiding publication of nursing studies to protect proprietary knowledge", "Discouraging nurses from pursuing postgraduate education"]'::jsonb, 0, 'A unique, research-generated body of knowledge is a hallmark of a mature profession and strengthens nursing''s professional identity and autonomy.', 'Pre-Council', '🎓', true),
(8323, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Cost-effectiveness in critical care units can be improved through research primarily because research', '["Identifies interventions that produce the best patient outcomes at appropriate resource use, reducing wasteful practices", "Always increases the length of ICU stay", "Focuses only on maximizing hospital revenue regardless of patient welfare", "Has no bearing on resource allocation decisions"]'::jsonb, 0, 'By identifying which interventions are truly effective, research helps eliminate low-value or wasteful practices, improving cost-effectiveness of ICU care.', 'Pre-Council', '🎓', true),
(8324, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Florence Nightingale''s work during the Crimean War is widely regarded as an early foundation of nursing research because she', '["Systematically collected and analyzed mortality statistics to demonstrate the effect of sanitation on patient outcomes", "Was the first nurse to obtain a PhD in nursing science", "Established the first randomized controlled trial in nursing history", "Invented the modern mechanical ventilator"]'::jsonb, 0, 'Nightingale''s meticulous statistical documentation of mortality rates and their relationship to sanitary conditions is considered one of the earliest examples of nursing research.', 'Pre-Council', '🎓', true),
(8325, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The modern concept of intensive/critical care units began to develop significantly during which period?', '["The mid-20th century, particularly following advances made during and after World War II and the polio epidemics", "The 18th century, during the Industrial Revolution", "Ancient Egyptian times", "The 21st century only"]'::jsonb, 0, 'Modern critical care units emerged largely in the mid-20th century, spurred by advances in resuscitation, respiratory support (notably during polio epidemics), and post-war surgical care.', 'Pre-Council', '🎓', true),
(8326, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The introduction of positive-pressure ventilation during the 1952 Copenhagen polio epidemic is historically significant to critical care because it', '["Demonstrated that organized, continuous ventilatory support and nursing observation could dramatically reduce mortality, spurring the growth of ICUs", "Marked the end of nursing research in respiratory care", "Had no influence on the later development of intensive care units", "Was solely a surgical, not a nursing, achievement"]'::jsonb, 0, 'The Copenhagen polio epidemic response, which relied heavily on continuous manual and mechanical ventilation with close nursing observation, is credited as a key event leading to the development of the modern ICU model.', 'Pre-Council', '🎓', true),
(8327, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Early Critical Care Nursing research in the mid-20th century was primarily driven by the need to', '["Improve survival and outcomes for critically ill and injured patients through closer monitoring and specialized interventions", "Reduce the number of nurses employed in hospitals", "Eliminate the use of technology in patient care", "Focus exclusively on administrative hospital budgeting"]'::jsonb, 0, 'The growth of critical care nursing research was driven by the clinical need to improve survival outcomes through closer monitoring, rapid intervention, and specialized technology use.', 'Pre-Council', '🎓', true),
(8328, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The formation of professional critical care nursing organizations, such as the American Association of Critical-Care Nurses (AACN) in 1969, was historically important because it', '["Provided a structured platform for developing standards, promoting research, and advancing specialty knowledge in critical care nursing", "Discouraged nurses from conducting further research", "Was created to replace physicians in the ICU", "Had no impact on the development of critical care nursing as a specialty"]'::jsonb, 0, 'Specialty organizations such as AACN promoted standard setting, certification, continuing education, and research dissemination, which strengthened critical care nursing as a distinct specialty.', 'Pre-Council', '🎓', true),
(8329, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The shift from a purely task-oriented, physician-directed model to an evidence-based, more autonomous critical care nursing role occurred largely as a result of', '["The growth of nursing research and specialized education that empowered nurses with an independent scientific knowledge base", "A decrease in the number of critically ill patients", "The abolition of intensive care units", "A decline in the use of technology in patient monitoring"]'::jsonb, 0, 'As nursing research and specialty education advanced, critical care nurses developed an independent, evidence-based scope of practice rather than functioning merely as physician assistants.', 'Pre-Council', '🎓', true),
(8330, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which development is historically credited with enabling continuous physiological monitoring, a major advance underpinning critical care nursing research and practice?', '["The invention and refinement of electronic bedside monitoring technology (e.g., cardiac monitors)", "The abolition of nursing documentation", "The elimination of laboratory testing in hospitals", "The discontinuation of nurse training programs"]'::jsonb, 0, 'The development of electronic bedside monitors allowing continuous tracking of vital signs and cardiac rhythms was a pivotal technological advance that shaped modern critical care nursing.', 'Pre-Council', '🎓', true),
(8331, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'In Nigeria, the growth of Critical Care Nursing as a recognized post-basic specialty has been closely linked to', '["The establishment of formal post-basic critical care nursing training programmes and increasing research into local ICU practice", "The complete removal of nursing councils and regulatory bodies", "A ban on the use of research findings in clinical practice", "The exclusion of nurses from intensive care units"]'::jsonb, 0, 'The development of structured post-basic critical care nursing training programmes, along with growing local research, has been central to establishing critical care nursing as a recognized specialty in Nigeria.', 'Pre-Council', '🎓', true),
(8332, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A key historical trend in critical care nursing research over recent decades has been the shift toward', '["Multidisciplinary, evidence-based practice supported by rigorously conducted clinical nursing research", "Complete reliance on unwritten tradition with no formal evidence", "Reducing nurse-led research to the bare minimum", "Abandoning collaboration with other health professionals"]'::jsonb, 0, 'Contemporary critical care nursing research emphasizes rigorous, evidence-based, multidisciplinary approaches to patient care, replacing earlier reliance on tradition alone.', 'Pre-Council', '🎓', true),
(8333, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Why is knowledge of the history of Critical Care Nursing research important for a nurse preparing for council examinations?', '["It provides context for understanding how current evidence-based practices, standards, and the specialty itself evolved over time", "It has no relevance to contemporary clinical practice or examinations", "It replaces the need to understand current research methods", "It is only useful for nurses pursuing a career in history, not nursing"]'::jsonb, 0, 'Understanding the historical evolution of critical care nursing research helps nurses appreciate the foundations of current evidence-based standards and practices, which is relevant to comprehensive exam preparation.', 'Pre-Council', '🎓', true),
(8334, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'In research terminology, a ''variable'' is best defined as', '["A characteristic or attribute of a person, object, or situation that can take on different values or vary", "A fixed number that never changes throughout a study", "The written report of the study findings", "A statistical test used to analyze qualitative data"]'::jsonb, 0, 'A variable is any attribute or characteristic that can vary or take on different values among the subjects being studied, such as age, blood pressure, or anxiety level.', 'Pre-Council', '🎓', true),
(8335, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Validity'' in research refers to', '["The extent to which an instrument accurately measures what it is intended to measure", "The extent to which an instrument gives consistent results on repeated use", "The total number of subjects included in a study", "The statistical significance level chosen by the researcher"]'::jsonb, 0, 'Validity concerns whether an instrument truly measures the concept it claims to measure, distinct from reliability, which concerns consistency.', 'Pre-Council', '🎓', true),
(8336, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Reliability'' of a research instrument refers to', '["The consistency and stability with which the instrument produces the same results on repeated administration", "The degree to which the instrument measures the intended concept accurately", "The cost of producing and distributing the instrument", "The number of items contained in a questionnaire"]'::jsonb, 0, 'Reliability is concerned with the consistency or repeatability of a measuring instrument''s results over repeated use under similar conditions.', 'Pre-Council', '🎓', true),
(8337, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''hypothesis'' in research is best defined as', '["A tentative, testable statement predicting the relationship between two or more variables", "A confirmed fact that requires no further testing", "The final conclusion drawn after data analysis", "A list of references used in a study"]'::jsonb, 0, 'A hypothesis is a tentative prediction or educated guess about the relationship between variables, which is then tested empirically.', 'Pre-Council', '🎓', true),
(8338, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The term ''population'' in research refers to', '["The entire group of individuals or elements that meet specified criteria and about whom the researcher wishes to draw conclusions", "Only the subjects who actually participate in the study", "The statistical software used to analyze data", "The geographic location where the study is conducted"]'::jsonb, 0, 'The population is the complete set of individuals or elements sharing common defining characteristics, from which a sample may be drawn for study.', 'Pre-Council', '🎓', true),
(8339, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''sample'' in research is', '["A subset of the population selected to participate in a study, intended to represent the larger population", "The entire population under study", "The instrument used to collect data", "A synonym for the research hypothesis"]'::jsonb, 0, 'A sample is a smaller, selected portion of the population that is studied in order to draw conclusions or make inferences about the whole population.', 'Pre-Council', '🎓', true),
(8340, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Operational definition'' of a variable refers to', '["A precise description of how a variable will be measured or manipulated in a specific study", "A dictionary definition of the term unrelated to the study context", "The theoretical meaning of a concept found in textbooks only", "The name of the statistical test applied to the variable"]'::jsonb, 0, 'An operational definition specifies exactly how a variable will be measured, observed, or manipulated within the context of a particular study, ensuring clarity and replicability.', 'Pre-Council', '🎓', true),
(8341, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Generalizability'' (external validity) in research refers to', '["The extent to which study findings can be applied to settings or populations beyond those studied", "The extent to which an instrument measures what it claims to measure", "The number of statistical tests performed", "The precision of the wording used in the research title"]'::jsonb, 0, 'Generalizability, or external validity, is the degree to which findings from a sample can be extended or applied to the broader population or other settings.', 'Pre-Council', '🎓', true),
(8342, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''construct'' in research is best described as', '["An abstract concept that is deliberately invented or adopted for scientific purposes, such as ''anxiety'' or ''quality of life''", "A physical instrument used to collect data", "A statistical formula for calculating sample size", "A synonym for a research design"]'::jsonb, 0, 'A construct is an abstract idea or concept, formed by combining simpler concepts, that researchers use to explain phenomena that cannot be directly observed (e.g., stress, motivation).', 'Pre-Council', '🎓', true),
(8343, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Bias'' in research refers to', '["Any systematic error that distorts the study findings and threatens the accuracy of the results", "The correct and expected outcome of a well-designed study", "A term describing a very large sample size", "A synonym for the research hypothesis"]'::jsonb, 0, 'Bias refers to any systematic (non-random) error in the design, conduct, or analysis of a study that distorts the results away from the truth.', 'Pre-Council', '🎓', true),
(8344, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The term ''extraneous variable'' refers to a variable that', '["Is not the focus of the study but may influence the dependent variable and confound the results if not controlled", "Is deliberately manipulated by the researcher as the main variable of interest", "Always improves the accuracy of the study findings", "Refers only to variables measured using qualitative methods"]'::jsonb, 0, 'Extraneous (confounding) variables are variables outside the researcher''s primary interest that can influence the outcome and must be controlled to avoid distorting results.', 'Pre-Council', '🎓', true),
(8345, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Data'' in the context of research refers to', '["The pieces of information collected during a study, which may be numerical or non-numerical", "Only numerical figures generated by statistical software", "The final published article", "The list of references cited in a study"]'::jsonb, 0, 'Data refers to the raw pieces of information (numeric or narrative) collected by the researcher during the course of a study, which are later analyzed.', 'Pre-Council', '🎓', true),
(8346, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following correctly represents the FIRST step in the research process?', '["Identifying and formulating the research problem", "Collecting data from respondents", "Writing the final report", "Selecting the statistical test for analysis"]'::jsonb, 0, 'The research process begins with identifying and clearly formulating a researchable problem, which guides all subsequent steps.', 'Pre-Council', '🎓', true),
(8347, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'After identifying the research problem, which step typically follows next in the research process?', '["Reviewing the related literature", "Disseminating the findings", "Collecting the data", "Writing recommendations"]'::jsonb, 0, 'A thorough review of related literature follows problem identification, helping the researcher understand existing knowledge and refine the study.', 'Pre-Council', '🎓', true),
(8348, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'In the sequence of the research process, formulation of the research hypothesis or research questions typically occurs', '["After the literature review and development of a theoretical/conceptual framework, but before choosing the research design", "After the data has already been collected and analyzed", "Before the research problem has been identified", "Only after the final report has been written"]'::jsonb, 0, 'Hypotheses or research questions are formulated once the problem is clear and the literature/theoretical framework has been reviewed, guiding the choice of design and methods that follow.', 'Pre-Council', '🎓', true),
(8349, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is the correct order of steps in the research process?', '["Problem identification, literature review, hypothesis formulation, research design, data collection, data analysis, reporting", "Data analysis, data collection, literature review, problem identification, reporting", "Reporting, data collection, problem identification, literature review", "Research design, reporting, problem identification, data analysis"]'::jsonb, 0, 'The logical, generally accepted sequence of the research process moves from identifying the problem, through review and design, to data collection, analysis, and finally reporting.', 'Pre-Council', '🎓', true),
(8350, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Selecting the research design and determining the population and sampling technique are steps that occur', '["After the hypothesis/research questions have been formulated and before data collection begins", "After the data has been collected and analyzed", "Before the research problem is identified", "Only after the report has been submitted for publication"]'::jsonb, 0, 'Once hypotheses or research questions are set, the researcher selects an appropriate design and sampling plan in order to guide data collection.', 'Pre-Council', '🎓', true),
(8351, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Data collection in the research process directly precedes which of the following steps?', '["Data analysis and interpretation", "Formulation of the research problem", "Literature review", "Development of the theoretical framework"]'::jsonb, 0, 'Once data have been collected, the next logical step is organizing and analyzing the data to draw meaningful interpretations.', 'Pre-Council', '🎓', true),
(8352, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The final step of the research process is typically considered to be', '["Disseminating or reporting the research findings to relevant audiences", "Formulating the research hypothesis", "Reviewing related literature", "Selecting the sample"]'::jsonb, 0, 'Reporting and disseminating findings — through publication, presentation, or other means — is the culminating step that allows the research to inform practice and further knowledge.', 'Pre-Council', '🎓', true),
(8353, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Why is the research process described as ''cyclical'' rather than strictly linear?', '["Because findings and recommendations from one study often generate new research problems, and steps may be revisited as work proceeds", "Because every research study must be repeated exactly the same way every year", "Because the same sample must be reused indefinitely", "Because literature review must always be the very last step"]'::jsonb, 0, 'Research is cyclical because new findings often raise new questions, and researchers frequently revisit earlier steps (e.g., refining the problem or literature review) as understanding deepens.', 'Pre-Council', '🎓', true),
(8354, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A nurse researcher notices a rising rate of pressure ulcers in immobile ICU patients and decides to investigate the issue. This scenario best illustrates the research process step of', '["Problem identification", "Reporting research findings", "Data analysis", "Formulating recommendations"]'::jsonb, 0, 'Noticing and defining a gap or issue in practice worth investigating is the problem identification step, the starting point of the research process.', 'Pre-Council', '🎓', true),
(8355, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Pilot testing a newly developed questionnaire before the main study is best classified as part of which step of the research process?', '["Instrument development and preparation for data collection", "Literature review", "Formulating the theoretical framework", "Writing the summary and conclusion"]'::jsonb, 0, 'Pilot testing evaluates and refines a data collection instrument before its full use, which falls under preparing for data collection.', 'Pre-Council', '🎓', true),
(8356, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Obtaining ethical approval from an institutional review board or research ethics committee is a step that must occur', '["Before data collection begins, once the research design and instruments have been finalized", "Only after the study has been published", "Before the research problem has even been thought of", "After the data has already been analyzed and interpreted"]'::jsonb, 0, 'Ethical approval must be secured after the study protocol and instruments are finalized but before any data collection from human subjects begins.', 'Pre-Council', '🎓', true),
(8357, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'In the research process, ''defining and determining the variables'' of the study is a step that logically follows', '["Formulation of the theoretical/conceptual framework and precedes formulation of hypotheses", "Publication of the final report", "Collection of data from respondents", "Presentation of results at a conference"]'::jsonb, 0, 'Once the theoretical/conceptual framework clarifies key concepts, the researcher defines and operationalizes the variables before stating testable hypotheses.', 'Pre-Council', '🎓', true),
(8358, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which step of the research process involves condensing raw data into tables, charts, and summary statistics to make it more understandable?', '["Organisation and analysis of data", "Problem identification", "Literature review", "Formulation of research questions"]'::jsonb, 0, 'Organizing and analyzing data involves reducing and summarizing raw data into a manageable, interpretable form such as tables and charts.', 'Pre-Council', '🎓', true),
(8359, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Writing a research proposal occurs at which point in the overall research process?', '["Before data collection begins, as a plan outlining the problem, objectives, literature, and proposed methodology", "After the study has already been completed and published", "Only after data analysis is finished", "As the very last step, replacing the final report"]'::jsonb, 0, 'A research proposal is a detailed plan prepared before the study is carried out, describing the problem, objectives, review of literature, and intended methodology.', 'Pre-Council', '🎓', true),
(8360, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher who returns to refine the literature review after preliminary data collection reveals an unanticipated variable demonstrates which key feature of the research process?', '["Its iterative and flexible nature, allowing revisiting of earlier steps as new insights emerge", "That the research process is completely rigid and steps can never be revisited", "That literature review is unnecessary once data collection starts", "That ethical approval is no longer required"]'::jsonb, 0, 'Although research follows a general sequence, it is often iterative, and researchers may revisit earlier steps such as the literature review when new insights emerge.', 'Pre-Council', '🎓', true),
(8361, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''researchable problem'' is best described as', '["A gap in knowledge or an unresolved issue that can be investigated using scientific methods to generate empirical evidence", "Any personal complaint a nurse has about her working hours", "A problem that has already been completely solved by earlier researchers", "A question that cannot be answered using any form of data"]'::jsonb, 0, 'A researchable problem is a specific, answerable gap in knowledge or unresolved clinical/theoretical issue that lends itself to systematic scientific investigation.', 'Pre-Council', '🎓', true),
(8362, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is the MOST common source of research problems for a Critical Care Nurse?', '["Everyday clinical practice and observation of recurring patient care issues", "Random guessing without any clinical basis", "Numbers generated arbitrarily by a computer", "Personal financial records of the hospital"]'::jsonb, 0, 'Clinical practice is the richest and most common source of nursing research problems, as nurses observe recurring issues, puzzling outcomes, or gaps in care firsthand.', 'Pre-Council', '🎓', true),
(8363, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A well-stated research problem should possess all of the following characteristics EXCEPT', '["Being so broad and vague that it can mean different things to different readers", "Being clear, specific, and researchable", "Being significant and relevant to the field of study", "Being feasible to investigate given available time and resources"]'::jsonb, 0, 'A good research problem must be clear and specific, not broad or vague; vagueness makes a problem difficult to study systematically and interpret consistently.', 'Pre-Council', '🎓', true),
(8364, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following criteria is used to evaluate whether a research problem is ''feasible''?', '["Whether the researcher has adequate time, resources, expertise, and access to subjects needed to carry out the study", "Whether the problem sounds impressive when spoken aloud", "Whether the topic has never been mentioned by anyone before", "Whether the researcher personally dislikes the topic"]'::jsonb, 0, 'Feasibility considers practical factors such as time, cost, availability of subjects, expertise, and equipment needed to successfully complete the study.', 'Pre-Council', '🎓', true),
(8365, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A nurse wants to study ''health'' in general with no further specification. The main weakness of this research problem is that it is', '["Too broad and lacks the specificity needed to be researched systematically", "Too narrow to be meaningful", "Already fully answered in existing literature so requires no study", "Unethical to investigate under any circumstances"]'::jsonb, 0, 'A problem stated as broadly as ''health'' lacks the specificity required to design a focused, researchable study; it must be narrowed to a specific, measurable issue.', 'Pre-Council', '🎓', true),
(8366, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The ''significance of the problem'' section of a research proposal primarily addresses', '["Why the problem is important and what value the findings will add to nursing knowledge or practice", "The exact statistical test that will be used", "The list of references consulted", "The demographic characteristics of the sample"]'::jsonb, 0, 'The significance of the study explains the importance of investigating the problem and the potential contribution of the findings to knowledge, policy, or practice.', 'Pre-Council', '🎓', true),
(8367, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which source would be considered LEAST appropriate as the primary basis for identifying a nursing research problem?', '["Unsubstantiated rumors or hearsay with no observable basis in practice", "Gaps identified in the existing literature", "Recurring problems observed in clinical practice", "Recommendations for further research from previous studies"]'::jsonb, 0, 'Sound research problems should stem from credible sources such as clinical observation, literature gaps, or theory — not unsubstantiated rumors lacking any factual basis.', 'Pre-Council', '🎓', true),
(8368, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The primary purpose of a literature review in the research process is to', '["Identify what is already known about the topic, reveal gaps, and provide a foundation for the current study", "Replace the need for the researcher to collect any new data", "Serve only as a formality with no real influence on the study", "List every book in the hospital library regardless of relevance"]'::jsonb, 0, 'A literature review surveys existing knowledge on the topic, helping the researcher identify gaps, avoid duplication, and build a rationale and framework for the new study.', 'Pre-Council', '🎓', true),
(8369, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A primary source in a literature review refers to', '["An original report of a study written by the researcher(s) who actually conducted it", "A textbook summarizing several other people''s research", "A newspaper article about a general health topic", "An encyclopedia entry with no citations"]'::jsonb, 0, 'A primary source is a first-hand account of research or theory written by those who conducted the original work, as opposed to a secondary source that summarizes or interprets others'' work.', 'Pre-Council', '🎓', true),
(8370, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A secondary source in a literature review is best exemplified by', '["A review article or textbook chapter that summarizes and synthesizes findings from several original studies", "The original journal article reporting a specific randomized controlled trial", "The raw dataset collected by the researcher", "An unpublished doctoral thesis reporting the author''s own study"]'::jsonb, 0, 'Secondary sources interpret, summarize, or comment on primary research (e.g., textbooks, review articles) rather than presenting original findings first-hand.', 'Pre-Council', '🎓', true),
(8371, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'When conducting a literature review, why should a researcher generally prioritize recent sources (e.g., within the last 5-10 years)?', '["To ensure the review reflects current knowledge, practices, and evidence in the rapidly evolving field of critical care", "Because older sources are always factually incorrect", "Because journals do not allow citation of sources older than one year", "Because recent sources never need to be critically appraised"]'::jsonb, 0, 'Prioritizing recent literature helps ensure the review reflects current evidence and practices, which is especially important in a fast-evolving field like critical care.', 'Pre-Council', '🎓', true),
(8372, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Critical appraisal of literature during a review involves', '["Evaluating the quality, validity, and relevance of each source before including it in the review", "Accepting every published article at face value without question", "Only counting the number of pages in each article", "Ignoring the methodology used in previous studies"]'::jsonb, 0, 'Critical appraisal requires the researcher to judge the rigor, validity, and relevance of a source''s methodology and findings before incorporating it into the review.', 'Pre-Council', '🎓', true),
(8373, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'One key function of the literature review is to help the researcher', '["Avoid unnecessary duplication of a study that has already been thoroughly investigated with consistent findings", "Guarantee that the new study will always find identical results to prior studies", "Eliminate the need to state a research problem", "Skip the process of developing a theoretical framework"]'::jsonb, 0, 'A thorough literature review reveals whether a question has already been adequately answered, helping the researcher avoid needless duplication and instead identify a genuine gap.', 'Pre-Council', '🎓', true),
(8374, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Plagiarism during a literature review can best be avoided by', '["Properly citing and referencing all ideas, data, and direct quotations taken from other authors'' works", "Copying sentences from journal articles without acknowledging the original author", "Paraphrasing another author''s ideas and presenting them as one''s own without citation", "Avoiding all citation styles entirely"]'::jsonb, 0, 'Proper citation and referencing of all borrowed ideas, quotations, and data are essential to giving credit to original authors and avoiding plagiarism.', 'Pre-Council', '🎓', true),
(8375, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A literature review that is organized by grouping studies according to recurring topics or findings, rather than simply listing them chronologically, is following a', '["Thematic organization approach", "Purely alphabetical listing with no analysis", "Random and unstructured approach", "Approach that ignores all study findings"]'::jsonb, 0, 'Thematic organization groups related studies and findings around key concepts or themes, producing a more coherent and analytical review than a simple list.', 'Pre-Council', '🎓', true),
(8376, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following best describes an appropriate use of a database such as PubMed or CINAHL in a literature review?', '["Searching for relevant peer-reviewed research articles related to the topic using appropriate keywords", "Downloading random unrelated articles regardless of topic", "Using it only to check personal email", "Avoiding it in favor of exclusively non-academic websites"]'::jsonb, 0, 'Databases such as PubMed and CINAHL allow researchers to systematically search for peer-reviewed literature relevant to their topic using targeted keywords and search terms.', 'Pre-Council', '🎓', true),
(8377, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''theoretical framework'' in research refers to', '["A structure of interrelated concepts and propositions, based on an existing theory, that guides the study and interpretation of findings", "The physical equipment used to collect data in a laboratory", "The list of references cited at the end of a report", "A synonym for the research design"]'::jsonb, 0, 'A theoretical framework applies an existing, established theory to structure the study''s variables, guide hypothesis formulation, and interpret findings.', 'Pre-Council', '🎓', true),
(8378, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''conceptual framework'' differs from a theoretical framework mainly in that a conceptual framework', '["Is developed by the researcher from a set of related concepts drawn from multiple sources, rather than being based on a single established theory", "Is always identical in content to a theoretical framework", "Can never be used to guide a nursing study", "Is only relevant to qualitative studies and never to quantitative ones"]'::jsonb, 0, 'While a theoretical framework is grounded in one existing formal theory, a conceptual framework is usually constructed by the researcher by linking concepts from various sources relevant to the specific study.', 'Pre-Council', '🎓', true),
(8379, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Roy''s Adaptation Model, when used to guide a study on patients'' coping with mechanical ventilation, serves as an example of', '["A theoretical framework grounded in an established nursing theory", "A sampling technique", "A type of data collection instrument", "A statistical test for analyzing data"]'::jsonb, 0, 'Using an established, named theory (such as Roy''s Adaptation Model) to guide the variables and relationships studied is a classic example of a theoretical framework.', 'Pre-Council', '🎓', true),
(8380, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The main purpose of including a theoretical or conceptual framework in a research study is to', '["Provide a logical structure that explains the relationships among the study''s key concepts and guides interpretation of findings", "Increase the length of the proposal without adding any value", "Replace the need for a literature review entirely", "Serve only as a decorative diagram with no functional role"]'::jsonb, 0, 'A theoretical or conceptual framework gives the study a coherent logical structure, showing how key concepts and variables are believed to relate, which then guides data interpretation.', 'Pre-Council', '🎓', true),
(8381, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following statements about a conceptual framework is TRUE?', '["It can be represented visually using a diagram (schematic model) showing the relationships among key concepts", "It must always be exactly the same as another researcher''s framework", "It cannot include any concept unless it appears in a published theory", "It has no bearing on how the research variables are interpreted"]'::jsonb, 0, 'Conceptual frameworks are often depicted schematically (e.g., as a diagram or model) to visually represent the presumed relationships among the study''s key concepts.', 'Pre-Council', '🎓', true),
(8382, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher studying burnout among ICU nurses adopts Maslach''s concept of burnout with its three dimensions (emotional exhaustion, depersonalization, reduced personal accomplishment) to structure her study variables. This is an example of using', '["A theoretical/conceptual framework to guide variable selection and interpretation", "A sampling frame", "A method of data collection", "A type of research design"]'::jsonb, 0, 'Adopting an established conceptual model of burnout to organize and interpret the study''s key variables demonstrates the function of a theoretical/conceptual framework.', 'Pre-Council', '🎓', true),
(8383, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The ''independent variable'' in a research study is', '["The variable that is manipulated or presumed to cause a change in another variable", "The variable that is measured as the outcome of the study", "A variable that has no relationship to any other variable in the study", "The variable used only to describe demographic characteristics"]'::jsonb, 0, 'The independent variable is the presumed cause — the one manipulated by the researcher or considered to influence the dependent (outcome) variable.', 'Pre-Council', '🎓', true),
(8384, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The ''dependent variable'' in a research study is', '["The outcome variable that is measured to determine the effect of the independent variable", "The variable that is manipulated by the researcher", "A variable unrelated to the study''s central question", "A synonym for the sample size"]'::jsonb, 0, 'The dependent variable is the outcome or response variable that is measured to assess the effect of the independent variable.', 'Pre-Council', '🎓', true),
(8385, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher studies the effect of a structured early mobilization protocol on the length of ICU stay. In this study, the independent variable is', '["The structured early mobilization protocol", "The length of ICU stay", "The age of the patients", "The name of the hospital"]'::jsonb, 0, 'The early mobilization protocol is the intervention being manipulated by the researcher, making it the independent variable; length of ICU stay is the outcome (dependent variable).', 'Pre-Council', '🎓', true),
(8386, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'In a study examining whether hand hygiene compliance among ICU nurses affects the rate of hospital-acquired infections, the dependent variable is', '["The rate of hospital-acquired infections", "Hand hygiene compliance", "The number of nurses working in the unit", "The type of hospital where the study is conducted"]'::jsonb, 0, 'The rate of hospital-acquired infections is the outcome being measured, making it the dependent variable, while hand hygiene compliance is the independent variable presumed to influence it.', 'Pre-Council', '🎓', true),
(8387, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'An ''extraneous (confounding) variable'' in a study of the effect of noise levels on patient sleep quality in the ICU could be', '["Use of sedative medication, which could also affect sleep quality independent of noise levels", "The noise level itself, since it is the independent variable", "Sleep quality, since it is the dependent variable", "The researcher''s personal name"]'::jsonb, 0, 'Sedative medication use is an extraneous variable because it could independently influence the dependent variable (sleep quality), potentially confounding the relationship being studied unless controlled.', 'Pre-Council', '🎓', true),
(8388, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''demographic variable'' typically refers to', '["A background characteristic of study subjects such as age, gender, marital status, or educational level", "The main outcome variable of every study", "A variable that can never be measured", "A synonym for the independent variable in every study"]'::jsonb, 0, 'Demographic variables describe background characteristics of the sample (e.g., age, sex, education) and are often used to characterize the study population.', 'Pre-Council', '🎓', true),
(8389, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''discrete variable'' is one that', '["Can only take on distinct, separate values, typically whole numbers, such as the number of children a person has", "Can take on any value along a continuum, including fractions and decimals", "Cannot be measured under any circumstances", "Always refers to a qualitative characteristic that cannot be counted"]'::jsonb, 0, 'A discrete variable takes on distinct, countable values (e.g., number of ICU admissions), unlike a continuous variable which can take any value within a range.', 'Pre-Council', '🎓', true),
(8390, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''continuous variable'' is best exemplified by', '["Body temperature, which can take any value within a range, including decimals", "The number of siblings a patient has", "Marital status (single, married, divorced)", "Blood group (A, B, AB, O)"]'::jsonb, 0, 'Continuous variables can theoretically take any value along a continuum, including fractional values, such as temperature (e.g., 37.4°C), unlike discrete or categorical variables.', 'Pre-Council', '🎓', true),
(8391, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'In a study testing whether a new antiseptic solution (compared to a standard solution) affects catheter-related bloodstream infection rates, correctly operationalizing the dependent variable would involve', '["Clearly specifying the precise diagnostic criteria and timeframe used to define and count a catheter-related bloodstream infection", "Simply stating ''infection'' without any further detail", "Leaving the definition open to each data collector''s personal judgment", "Defining only the independent variable and ignoring the dependent variable entirely"]'::jsonb, 0, 'Operationalizing a variable requires a precise, measurable definition — here, clear diagnostic criteria and timeframe for what counts as a catheter-related bloodstream infection — to ensure consistent, reliable measurement.', 'Pre-Council', '🎓', true),
(8392, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''moderating variable'' is one that', '["Affects the strength or direction of the relationship between the independent and dependent variables", "Is always identical to the dependent variable", "Has no influence whatsoever on the study''s outcome", "Refers only to variables measured before the study begins with no further role"]'::jsonb, 0, 'A moderating variable influences the strength or direction of the relationship between the independent and dependent variables, essentially interacting with the independent variable.', 'Pre-Council', '🎓', true),
(8393, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''null hypothesis'' (H0) states that', '["There is no statistically significant relationship or difference between the variables being studied", "There is definitely a significant relationship between the variables", "The researcher''s prediction is automatically correct", "Data collection is unnecessary"]'::jsonb, 0, 'The null hypothesis is a statement of no relationship or no difference between variables; statistical testing determines whether there is enough evidence to reject it.', 'Pre-Council', '🎓', true),
(8394, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'An ''alternative (research) hypothesis'' (H1) states that', '["There is a statistically significant relationship or difference between the variables being studied", "There is no relationship between any variables under any circumstances", "The study has no purpose", "Only qualitative data can be used to test it"]'::jsonb, 0, 'The alternative hypothesis, often the researcher''s actual prediction, proposes that a significant relationship or difference does exist between the variables.', 'Pre-Council', '🎓', true),
(8395, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''directional hypothesis'' is one that', '["Specifies the expected direction of the relationship between variables, such as ''higher X leads to lower Y''", "States only that a relationship exists without specifying its direction", "Can never be tested statistically", "Is used exclusively in historical research"]'::jsonb, 0, 'A directional hypothesis predicts not just that a relationship exists, but the specific direction of that relationship (e.g., an increase or decrease).', 'Pre-Council', '🎓', true),
(8396, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''non-directional hypothesis'' is one that', '["States that a relationship or difference exists between variables without specifying the direction of that relationship", "Always specifies exactly which variable will increase and which will decrease", "Cannot be used in quantitative research", "Is identical in meaning to a null hypothesis"]'::jsonb, 0, 'A non-directional hypothesis predicts that a relationship exists between variables but does not specify whether the relationship will be positive or negative.', 'Pre-Council', '🎓', true),
(8397, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Structured critical care nurse-led mobilization reduces the incidence of ICU-acquired weakness compared to standard care'' is an example of a', '["Directional research hypothesis", "Null hypothesis", "Research question rather than a hypothesis", "Non-directional hypothesis"]'::jsonb, 0, 'This statement predicts a specific direction of effect (a reduction in ICU-acquired weakness), making it a directional hypothesis.', 'Pre-Council', '🎓', true),
(8398, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Research questions are generally used instead of hypotheses when', '["The study is exploratory or descriptive in nature and there is insufficient existing knowledge to predict a specific relationship", "The researcher wants to test a precise cause-and-effect relationship with an experimental design", "The study must always involve statistical hypothesis testing", "Qualitative research is strictly prohibited from using questions"]'::jsonb, 0, 'Research questions are typically favored in exploratory, descriptive, or qualitative studies where too little is known to justify predicting a specific directional relationship.', 'Pre-Council', '🎓', true),
(8399, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A well-formulated hypothesis should possess which of the following characteristics?', '["It should be clear, testable, and state an expected relationship between two or more variables", "It should be vague enough to accommodate any possible outcome", "It should never be based on existing theory or literature", "It should avoid mentioning any variable"]'::jsonb, 0, 'A good hypothesis is clear, specific, testable through data collection, and articulates the expected relationship between defined variables.', 'Pre-Council', '🎓', true),
(8400, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is correctly written as a testable research hypothesis?', '["There is a significant relationship between nurses'' years of ICU experience and their competence in ventilator management", "ICU nursing is important", "What are the challenges faced by ICU nurses?", "Ventilators are complex machines"]'::jsonb, 0, 'A testable hypothesis states a specific, measurable relationship between defined variables (years of experience and ventilator management competence) that can be statistically examined.', 'Pre-Council', '🎓', true),
(8401, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher writes: ''What are the lived experiences of family members of patients admitted to the ICU?'' This is best classified as a', '["Qualitative research question", "Directional hypothesis", "Null hypothesis", "Statistical hypothesis requiring inferential testing"]'::jsonb, 0, 'This open-ended question exploring lived experience is characteristic of qualitative research questions rather than a hypothesis, which requires measurable variables and predicted relationships.', 'Pre-Council', '🎓', true),
(8402, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''research design'' can best be defined as', '["The overall plan that specifies how a study will be conducted, including how subjects will be selected, data collected, and analyzed", "The final list of references included in a study", "A synonym for the research problem", "The specific brand of statistical software used"]'::jsonb, 0, 'A research design is the comprehensive blueprint or strategy for conducting a study, guiding sampling, data collection, and analysis to answer the research question.', 'Pre-Council', '🎓', true),
(8403, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which design involves random assignment of subjects to an experimental group and a control group, with manipulation of the independent variable?', '["True experimental design", "Quasi-experimental design", "Descriptive design", "Correlational design"]'::jsonb, 0, 'True experimental designs are characterized by manipulation of the independent variable, use of a control group, AND random assignment of subjects to groups.', 'Pre-Council', '🎓', true),
(8404, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A quasi-experimental design differs from a true experimental design mainly because it', '["Lacks random assignment of subjects to groups, though it may still involve manipulation of the independent variable", "Never involves any form of intervention", "Always has a larger sample size than true experiments", "Cannot be used to study cause-and-effect relationships at all"]'::jsonb, 0, 'Quasi-experimental designs involve manipulation of an independent variable (an intervention) but lack random assignment of subjects to groups, unlike true experiments.', 'Pre-Council', '🎓', true),
(8405, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A study comparing infection rates between an ICU that adopted a new hand hygiene protocol and a similar ICU that continued standard practice, without randomly assigning patients or units to groups, is an example of a', '["Quasi-experimental design", "True experimental design", "Phenomenological design", "Historical design"]'::jsonb, 0, 'Because units (not individual subjects) were not randomly assigned to intervention and comparison groups, this reflects a quasi-experimental (non-randomized) design.', 'Pre-Council', '🎓', true),
(8406, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''correlational design'' is used primarily to', '["Examine the relationship between two or more variables without manipulating any of them", "Establish definite cause-and-effect relationships between variables", "Randomly assign subjects to a treatment and control group", "Explore lived experiences using in-depth interviews only"]'::jsonb, 0, 'Correlational designs measure the strength and direction of relationships between variables as they naturally occur, without manipulation, and cannot establish causation.', 'Pre-Council', '🎓', true),
(8407, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A study measuring both nurses'' workload and their reported levels of burnout to determine whether the two are related, without manipulating either variable, uses a', '["Correlational design", "True experimental design", "Case-control design with random assignment", "Historical design"]'::jsonb, 0, 'This design examines the naturally occurring association between two measured variables (workload and burnout) without manipulation, characteristic of a correlational design.', 'Pre-Council', '🎓', true),
(8408, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A cross-sectional study design involves', '["Collecting data from a population or sample at a single point in time", "Following the same group of subjects over an extended period with repeated measurements", "Manipulating the independent variable with random assignment", "Reviewing historical documents only"]'::jsonb, 0, 'Cross-sectional designs capture data at one specific point in time, providing a ''snapshot'' of the population, as opposed to longitudinal designs that follow subjects over time.', 'Pre-Council', '🎓', true),
(8409, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A longitudinal study design is characterized by', '["Collecting data from the same subjects repeatedly over an extended period of time", "Collecting data only once from each subject", "Never following up with the same subjects again", "Being usable only for qualitative research"]'::jsonb, 0, 'Longitudinal designs involve repeated data collection from the same subjects over time, allowing researchers to study changes or trends.', 'Pre-Council', '🎓', true),
(8410, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''descriptive research design'' is most appropriate when the researcher''s main goal is to', '["Accurately observe, describe, and document characteristics of a phenomenon as it naturally exists", "Establish a definite cause-and-effect relationship between two variables", "Randomly assign subjects to different treatment conditions", "Test a null hypothesis using an experimental intervention"]'::jsonb, 0, 'Descriptive designs aim to accurately portray characteristics of a population, situation, or phenomenon without manipulating variables or establishing causation.', 'Pre-Council', '🎓', true),
(8411, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A survey of ICU nurses'' knowledge and attitudes toward pain assessment in non-verbal patients, without any intervention, best exemplifies a', '["Descriptive research design", "True experimental research design", "Quasi-experimental research design with two groups", "Case-control design"]'::jsonb, 0, 'This study simply describes existing knowledge and attitudes without manipulating any variable, which is the hallmark of a descriptive design.', 'Pre-Council', '🎓', true),
(8412, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A retrospective (ex post facto) research design involves', '["Looking backward at existing records or past events to examine relationships between variables that have already occurred", "Manipulating the independent variable to observe a future outcome", "Randomly assigning current subjects to future treatment groups", "Collecting data prospectively as events unfold in real time"]'::jsonb, 0, 'Retrospective designs examine data or records from past events to identify relationships between variables that have already occurred, rather than following subjects forward in time.', 'Pre-Council', '🎓', true),
(8413, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A prospective research design involves', '["Identifying subjects and following them forward in time to observe outcomes that will occur in the future", "Reviewing historical documents from decades past", "Analyzing only data that was previously collected for other purposes", "Excluding any form of follow-up after baseline data collection"]'::jsonb, 0, 'Prospective designs identify a cohort at the outset and follow them forward in time to observe the development of outcomes.', 'Pre-Council', '🎓', true),
(8414, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A phenomenological research design, a type of qualitative design, is primarily used to', '["Explore and describe the lived experiences and meanings that individuals attach to a particular phenomenon", "Statistically test hypotheses using large, randomly selected samples", "Manipulate an independent variable under controlled experimental conditions", "Analyze numerical trends in large population datasets"]'::jsonb, 0, 'Phenomenology, a qualitative approach, seeks to understand and describe the lived experiences and subjective meanings individuals assign to a phenomenon.', 'Pre-Council', '🎓', true),
(8415, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'An ''ethnographic'' research design focuses on', '["Studying the culture, beliefs, and practices of a particular group through immersion and observation over time", "Testing the statistical significance of an intervention using a control group", "Reviewing quantitative survey data collected via mailed questionnaires only", "Randomly assigning subjects to experimental conditions"]'::jsonb, 0, 'Ethnography is a qualitative design in which the researcher immerses in and observes a cultural group to understand its beliefs, values, and practices.', 'Pre-Council', '🎓', true),
(8416, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''case study'' research design is most appropriate when the researcher wants to', '["Conduct an in-depth, intensive investigation of a single individual, group, or unit", "Survey a very large, randomly selected sample using a structured questionnaire", "Randomly assign hundreds of subjects to two treatment arms", "Analyze only pre-existing national statistical databases"]'::jsonb, 0, 'Case studies involve an intensive, in-depth exploration of a single case (a person, family, unit, or event), often generating detailed, contextual understanding.', 'Pre-Council', '🎓', true),
(8417, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is the main limitation of a quasi-experimental design compared to a true experimental design?', '["The absence of random assignment increases the risk that group differences (confounding variables), not the intervention alone, explain the results", "It always requires a larger budget than true experiments", "It cannot be used in clinical or hospital settings", "It never involves an intervention or independent variable"]'::jsonb, 0, 'Without random assignment, pre-existing differences between groups may confound results, making it harder to attribute outcomes solely to the intervention, which weakens causal inference compared to true experiments.', 'Pre-Council', '🎓', true),
(8418, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher wants to determine whether a new sedation protocol reduces delirium in ICU patients and has the ability to randomly assign eligible patients to receive either the new protocol or standard care. The MOST appropriate design is', '["A randomized controlled trial (true experimental design)", "A purely descriptive survey design", "A historical design using archival records", "A phenomenological design"]'::jsonb, 0, 'Since random assignment to intervention and control groups is possible along with manipulation of the independent variable, a randomized controlled trial (true experimental design) is most appropriate.', 'Pre-Council', '🎓', true),
(8419, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''comparative design'' in research is used to', '["Examine differences between two or more naturally occurring groups on one or more variables", "Randomly assign subjects to groups and manipulate an intervention", "Explore lived experiences using unstructured interviews only", "Analyze historical archives exclusively"]'::jsonb, 0, 'Comparative designs examine differences between existing, naturally occurring groups (e.g., day-shift vs night-shift nurses) on selected variables, without manipulation or random assignment.', 'Pre-Council', '🎓', true),
(8420, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Internal validity of a research design refers to', '["The degree to which the design allows the researcher to confidently attribute observed effects to the independent variable rather than to other factors", "The extent to which findings can be generalized to other populations", "The number of pages in the final research report", "The cost of conducting the study"]'::jsonb, 0, 'Internal validity concerns whether the study design adequately rules out alternative explanations, allowing confidence that the independent variable caused the observed effect on the dependent variable.', 'Pre-Council', '🎓', true),
(8421, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''target population'' in research refers to', '["The entire group of individuals or elements that meet the researcher''s specified inclusion criteria and to whom findings are meant to generalize", "Only the subjects who are conveniently available on a given day", "The statistical package used for data analysis", "A synonym for the research instrument"]'::jsonb, 0, 'The target population is the complete set of individuals/elements that fit the study''s criteria, and to whom the researcher ultimately intends to generalize the findings.', 'Pre-Council', '🎓', true),
(8422, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'An ''accessible population'' differs from a ''target population'' in that the accessible population is', '["The portion of the target population that is realistically available to the researcher for sampling", "Always larger than the target population", "A synonym for the research sample itself", "Composed only of subjects who have already died"]'::jsonb, 0, 'The accessible population is the subset of the broader target population that the researcher can realistically reach and sample from, given practical constraints.', 'Pre-Council', '🎓', true),
(8423, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A ''sampling frame'' is best described as', '["A complete list of all elements or subjects in the accessible population from which a sample will be drawn", "The theoretical framework guiding the study", "The final report describing the study''s results", "A synonym for the research design"]'::jsonb, 0, 'A sampling frame is the actual list (e.g., a patient register or staff roster) from which individual sample elements are selected.', 'Pre-Council', '🎓', true),
(8424, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Simple random sampling is a technique in which', '["Every member of the population has an equal and independent chance of being selected for the sample", "The researcher selects only subjects who are readily available", "Subjects are grouped into strata before random selection within each group", "Existing subjects recruit other subjects known to them"]'::jsonb, 0, 'Simple random sampling gives every element in the population an equal, independent chance of selection, typically using random number generation or a lottery method.', 'Pre-Council', '🎓', true),
(8425, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Stratified random sampling is most appropriate when the researcher wants to', '["Ensure proportional representation of specific subgroups (strata) that vary on an important characteristic within the population", "Select whichever subjects happen to be easiest to reach", "Avoid any structured or systematic selection method", "Recruit friends and colleagues of the researcher only"]'::jsonb, 0, 'Stratified sampling divides the population into meaningful subgroups (strata), such as ICU cadre or years of experience, then samples from each to ensure proportional representation.', 'Pre-Council', '🎓', true),
(8426, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher divides ICU nurses into strata based on years of experience (0-2, 3-5, 6+ years) and then randomly selects a proportional number of nurses from each stratum. This is an example of', '["Stratified random sampling", "Simple random sampling", "Purposive sampling", "Convenience sampling"]'::jsonb, 0, 'Dividing the population into meaningful subgroups (strata) and randomly sampling proportionally from each is the defining feature of stratified random sampling.', 'Pre-Council', '🎓', true),
(8427, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Systematic sampling involves', '["Selecting every kth element from a list after a random starting point", "Choosing subjects purely based on the researcher''s personal judgment of who is ''typical''", "Selecting subjects based only on their convenient availability", "Allowing existing participants to recruit further participants"]'::jsonb, 0, 'Systematic sampling selects every kth element from an ordered sampling frame, beginning from a randomly chosen starting point.', 'Pre-Council', '🎓', true),
(8428, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Cluster sampling is most useful when', '["The population is large and geographically dispersed, so naturally occurring groups (clusters) are randomly selected rather than individuals directly", "The researcher wants to select only participants known personally to them", "A complete list of every individual element in the population is readily and easily available", "The study requires only two participants in total"]'::jsonb, 0, 'Cluster sampling is efficient for large, dispersed populations where individual listing is impractical; instead, naturally occurring groups (e.g., hospitals or wards) are randomly selected.', 'Pre-Council', '🎓', true),
(8429, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Convenience (accidental) sampling involves', '["Selecting subjects simply because they are readily available and accessible to the researcher", "Randomly selecting subjects using a computer-generated list", "Dividing the population into strata before sampling", "Selecting participants based on specific pre-defined characteristics relevant to the research question"]'::jsonb, 0, 'Convenience sampling selects whichever subjects are easiest to access at the time, without any random or purposeful selection process, making it a non-probability method.', 'Pre-Council', '🎓', true),
(8430, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Purposive (judgmental) sampling involves', '["Deliberately selecting participants who possess specific characteristics or knowledge relevant to the research question", "Selecting subjects entirely at random from the full population", "Selecting subjects based purely on convenience or availability", "Using existing participants to recruit their acquaintances into the study"]'::jsonb, 0, 'Purposive sampling is a non-probability technique where the researcher deliberately selects participants believed to be information-rich or representative of characteristics important to the study.', 'Pre-Council', '🎓', true),
(8431, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Snowball sampling is a technique especially useful for studying', '["Hard-to-reach or hidden populations, where existing participants refer the researcher to other potential participants they know", "Extremely large populations with a complete and accessible sampling frame", "Populations where random selection using computer software is straightforward", "Only populations with fewer than five known members in existence"]'::jsonb, 0, 'Snowball sampling relies on referrals from initial participants to reach further participants, making it especially valuable for hidden or hard-to-access populations.', 'Pre-Council', '🎓', true),
(8432, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Quota sampling is best described as a non-probability technique in which', '["The researcher selects a predetermined number of subjects from specific subgroups, but not through random selection", "Every element of the population has a known, equal chance of selection", "Subjects are selected using a random number table", "Participants are selected using a formal, complete sampling frame with random starting points"]'::jsonb, 0, 'Quota sampling sets target numbers (''quotas'') for specific subgroups but fills those quotas through non-random, convenient selection, distinguishing it from stratified random sampling.', 'Pre-Council', '🎓', true),
(8433, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'The key distinction between probability and non-probability sampling techniques is that', '["In probability sampling every element has a known, non-zero chance of selection, while in non-probability sampling this chance is unknown", "Non-probability sampling always produces a larger sample size than probability sampling", "Probability sampling is only used in qualitative research", "Non-probability sampling always yields more generalizable findings than probability sampling"]'::jsonb, 0, 'Probability sampling techniques give each population element a known, calculable chance of selection, enabling generalization, whereas non-probability techniques do not guarantee this, limiting generalizability.', 'Pre-Council', '🎓', true),
(8434, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A major advantage of probability sampling techniques over non-probability techniques is that probability sampling', '["Reduces selection bias and increases the likelihood that the sample is representative, supporting generalization to the population", "Is always faster and cheaper to carry out than non-probability sampling", "Guarantees a 100% response rate from selected subjects", "Eliminates the need for informed consent"]'::jsonb, 0, 'Because probability sampling gives every element a known chance of selection, it minimizes selection bias and better supports generalizing findings to the broader population.', 'Pre-Council', '🎓', true),
(8435, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher wants to explore in depth the coping strategies of five ICU nurses who have personally experienced a patient''s cardiac arrest during their shift, deliberately selecting nurses with this specific experience. This is an example of', '["Purposive sampling", "Simple random sampling", "Systematic sampling", "Cluster sampling"]'::jsonb, 0, 'Deliberately selecting participants because they possess a specific, relevant experience (surviving a patient cardiac arrest event) is characteristic of purposive sampling.', 'Pre-Council', '🎓', true),
(8436, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher studying illicit drug users, a population without an available formal list or registry, asks initial participants to refer other drug users they know. This sampling technique is called', '["Snowball sampling", "Stratified random sampling", "Systematic sampling", "Quota sampling"]'::jsonb, 0, 'Recruiting participants for a hidden or hard-to-locate population through referrals from existing participants is the defining characteristic of snowball sampling.', 'Pre-Council', '🎓', true),
(8437, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A nurse researcher numbers all 200 patient files in an ICU register and uses a random number generator to select 40 files for chart review. This is an example of', '["Simple random sampling", "Convenience sampling", "Purposive sampling", "Quota sampling"]'::jsonb, 0, 'Assigning numbers to all elements and using a random selection method (like a random number generator) to choose the sample is the standard procedure for simple random sampling.', 'Pre-Council', '🎓', true),
(8438, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'A researcher selects every 5th patient admitted to the ICU, starting from a randomly chosen first patient, until the desired sample size is reached. This sampling technique is', '["Systematic sampling", "Stratified random sampling", "Snowball sampling", "Purposive sampling"]'::jsonb, 0, 'Selecting every kth element (here, every 5th patient) from an ordered list after a random start defines systematic sampling.', 'Pre-Council', '🎓', true),
(8439, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Sample size determination in quantitative research is influenced by all of the following EXCEPT', '["The researcher''s personal preference for a round number with no statistical justification", "The desired level of statistical power to detect an effect", "The expected effect size of the variable being studied", "The acceptable margin of error and confidence level"]'::jsonb, 0, 'Sample size should be determined using statistical considerations such as power, effect size, and margin of error — not arbitrary personal preference.', 'Pre-Council', '🎓', true),
(8440, 'Research Process', 'CCN Curriculum — Applied Research Methodology', '''Sampling error'' refers to', '["The difference between a sample statistic and the true population parameter due to the sample not perfectly representing the population", "A mistake made by the researcher in recording data", "The total number of subjects who refused to participate in the study", "An error that occurs only in qualitative research"]'::jsonb, 0, 'Sampling error is the natural, expected discrepancy between a value calculated from a sample and the true value in the population, arising because a sample is not a perfect mirror of the population.', 'Pre-Council', '🎓', true),
(8441, 'Research Process', 'CCN Curriculum — Applied Research Methodology', 'Inclusion and exclusion criteria in a sampling plan are used to', '["Define the specific characteristics that qualify or disqualify potential subjects from participating in the study", "Determine the statistical test that will be applied to the data", "Decide which references will be cited in the literature review", "Determine how the final report will be formatted"]'::jsonb, 0, 'Inclusion and exclusion criteria specify the eligibility requirements a subject must meet (or must not have) to be included in the study sample, ensuring the sample matches the target population.', 'Pre-Council', '🎓', true),
(8442, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'In statistics, what is a "population"?', '["The entire group of individuals or items that a researcher is interested in studying", "A small subset selected from a larger group", "The average value of a data set", "A graphical representation of data"]'::jsonb, 0, 'A population is the complete set of individuals or items of interest to the researcher; a sample is a subset drawn from it.', 'Pre-Council', '🎓', true),
(8443, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "sample" in statistics is best defined as:', '["The entire group under study", "A subset of a population selected for study", "A statistical test of significance", "The range of values in a data set"]'::jsonb, 1, 'A sample is a subset of the population chosen to represent the whole group in a study.', 'Pre-Council', '🎓', true),
(8444, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "variable" in statistics refers to:', '["A fixed constant value that never changes", "Any characteristic or attribute that can take different values among subjects", "The average of a data set", "A method of collecting data"]'::jsonb, 1, 'A variable is any attribute (e.g., age, blood pressure) that can vary or take different values between subjects.', 'Pre-Council', '🎓', true),
(8445, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "parameter" is a numerical value that describes:', '["A sample", "A population", "A graph", "A questionnaire"]'::jsonb, 1, 'A parameter describes a characteristic of an entire population, whereas a statistic describes a sample.', 'Pre-Council', '🎓', true),
(8446, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "statistic" (in the technical sense) refers to a numerical value that describes:', '["A population", "A sample", "A hypothesis", "An ethical principle"]'::jsonb, 1, 'A statistic is a numerical value calculated from sample data, used to estimate the corresponding population parameter.', 'Pre-Council', '🎓', true),
(8447, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Data" in research refers to:', '["Raw facts and figures collected during research before being processed", "The final conclusions of a study", "The title of a research report", "A method of random sampling"]'::jsonb, 0, 'Data are the raw facts, figures, or observations collected, which are later organised and analysed to produce findings.', 'Pre-Council', '🎓', true),
(8448, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The term "frequency" in statistics refers to:', '["The average value of a variable", "The number of times a particular value or category occurs in a data set", "The spread of scores around the mean", "The correlation between two variables"]'::jsonb, 1, 'Frequency is a count of how often a specific value or category appears in a data set.', 'Pre-Council', '🎓', true),
(8449, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Statistics" as a discipline can be defined as:', '["The branch of mathematics dealing with collection, organisation, analysis, interpretation, and presentation of data", "The study of disease patterns and causes in populations", "A method for testing new drugs on animals", "The process of writing research reports only"]'::jsonb, 0, 'Statistics is the science concerned with collecting, organising, analysing, interpreting, and presenting numerical data.', 'Pre-Council', '🎓', true),
(8450, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "discrete variable" is one that:', '["Can take any value within a range, including fractions", "Can only take whole number/countable values, such as number of patients admitted", "Is always a qualitative, non-numeric variable", "Cannot be measured or counted at all"]'::jsonb, 1, 'Discrete variables take on distinct, countable whole-number values, for example the number of admissions in a day.', 'Pre-Council', '🎓', true),
(8451, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "continuous variable" is one that:', '["Can take any value, including fractions or decimals, within a given range, such as body temperature", "Can only be classified into unordered categories", "Can only take whole-number counted values", "Has no numerical meaning at all"]'::jsonb, 0, 'Continuous variables, such as temperature or weight, can take any value along a scale, including decimal values.', 'Pre-Council', '🎓', true),
(8452, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The basic purpose of statistics in research is to:', '["Summarise, analyse, and interpret numerical data to draw meaningful conclusions", "Collect only qualitative opinions with no numerical analysis", "Replace clinical judgement in patient care decisions", "Design hospital equipment and infrastructure"]'::jsonb, 0, 'Statistics provides tools to organise, summarise, and interpret data so that meaningful, evidence-based conclusions can be drawn.', 'Pre-Council', '🎓', true),
(8453, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following best describes "quantitative data"?', '["Data expressed in numerical form that can be measured or counted", "Data expressed in words or categories describing qualities", "Data collected only through unstructured interviews", "Data that cannot be analysed using statistics"]'::jsonb, 0, 'Quantitative data are numerical and can be measured, counted, and analysed statistically, e.g., heart rate values.', 'Pre-Council', '🎓', true),
(8454, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Qualitative data" is best described as:', '["Numerical measurements such as blood pressure readings", "Non-numerical data describing qualities or characteristics, e.g., a patient''s mood", "Data that must always be converted to percentages before use", "Data obtained only from laboratory investigations"]'::jsonb, 1, 'Qualitative data describe characteristics, qualities, or categories rather than numerical quantities.', 'Pre-Council', '🎓', true),
(8455, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A hypothesis in research is best described as:', '["A proven fact that requires no further testing", "A tentative, testable statement about the relationship between two or more variables", "A summary of all data collected in a study", "A specific method of sampling participants"]'::jsonb, 1, 'A hypothesis is a tentative prediction about the relationship between variables that a study is designed to test.', 'Pre-Council', '🎓', true),
(8456, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The "null hypothesis" (H0) states that:', '["There is a significant difference or relationship between the variables studied", "There is no significant difference or relationship between the variables being studied", "The sample size used was too small to be valid", "The research design used was invalid"]'::jsonb, 1, 'The null hypothesis is the default position that there is no true difference or relationship, which statistical tests attempt to reject or fail to reject.', 'Pre-Council', '🎓', true),
(8457, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'An "alternative hypothesis" (H1) proposes that:', '["There is no relationship between variables", "There is a significant relationship or difference between the variables studied", "The study should be abandoned before completion", "Data collection procedures were flawed"]'::jsonb, 1, 'The alternative hypothesis is the statement a researcher seeks to support, proposing that a real relationship or difference exists.', 'Pre-Council', '🎓', true),
(8458, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'In statistics, "sampling" refers to:', '["Studying every member of a population without exception", "The process of selecting a subset of individuals from a population to represent the whole", "Rounding off numerical data for easier reporting", "Testing whether a result is statistically significant"]'::jsonb, 1, 'Sampling is the process of selecting a representative subset (sample) from a larger population for study.', 'Pre-Council', '🎓', true),
(8459, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Random sampling" is a technique in which:', '["The researcher selects only volunteers who are easiest to reach", "Every member of the population has an equal chance of being selected", "Only the most severely ill patients are chosen", "Participants choose themselves based on personal interest"]'::jsonb, 1, 'Random sampling gives every member of the population an equal chance of selection, reducing selection bias.', 'Pre-Council', '🎓', true),
(8460, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following reflects a basic principle guiding sound statistical practice in research?', '["Data should be accurate, relevant, and collected using appropriate, consistent methods before analysis", "Any data collected, however inaccurate, is acceptable for statistical analysis", "Statistical results never require consideration of the study context", "Sample size has no bearing on the reliability of statistical results"]'::jsonb, 0, 'Sound statistical practice depends on accurate, relevant data collected through appropriate methods; poor data quality undermines any analysis.', 'Pre-Council', '🎓', true),
(8461, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A variable that can only take on unordered categories with no numeric value, such as blood group (A, B, AB, O), is called a:', '["Continuous variable", "Categorical (qualitative) variable", "Ratio-level variable", "Discrete quantitative variable"]'::jsonb, 1, 'Blood group is a categorical (nominal) variable because its values are unordered labels rather than quantities.', 'Pre-Council', '🎓', true),
(8462, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which scale of measurement classifies data into categories with no inherent order, such as blood group (A, B, AB, O)?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 0, 'Nominal scales simply label or categorise data with no meaningful order or numeric relationship between categories.', 'Pre-Council', '🎓', true),
(8463, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A patient''s pain level rated as "mild, moderate, severe" is an example of which scale of measurement?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 1, 'Ordinal scales rank categories in a meaningful order, but the intervals between ranks are not necessarily equal.', 'Pre-Council', '🎓', true),
(8464, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Body temperature measured in degrees Celsius is an example of which scale of measurement?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 2, 'Celsius temperature has equal intervals between units but no true zero point (0 degrees C is not the absence of temperature), making it an interval scale.', 'Pre-Council', '🎓', true),
(8465, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A patient''s body weight measured in kilograms is an example of which scale of measurement?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 3, 'Weight has a true zero point (0 kg means no weight) and equal intervals, making it a ratio scale that allows statements like ''twice as heavy''.', 'Pre-Council', '🎓', true),
(8466, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which scale of measurement has a true (absolute) zero point, allowing statements such as "twice as much"?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 3, 'Only the ratio scale has a true zero, which permits meaningful ratio comparisons such as one value being twice another.', 'Pre-Council', '🎓', true),
(8467, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Assigning the codes 1 = male and 2 = female purely for data entry purposes is an example of which scale of measurement?', '["Ratio scale", "Nominal scale", "Interval scale", "Ordinal scale"]'::jsonb, 1, 'The numbers are arbitrary labels for unordered categories with no numeric or ranking meaning, which is characteristic of a nominal scale.', 'Pre-Council', '🎓', true),
(8468, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The Glasgow Coma Scale (GCS) score, which ranks a patient''s level of consciousness from 3 to 15, is best classified as which scale of measurement?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 1, 'The GCS ranks levels of consciousness in order, but the difference between successive scores does not represent an equal clinical interval, making it an ordinal scale.', 'Pre-Council', '🎓', true),
(8469, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is the correct order of scales of measurement from least to most mathematically sophisticated?', '["Ratio, interval, ordinal, nominal", "Nominal, ordinal, interval, ratio", "Ordinal, nominal, ratio, interval", "Interval, ratio, nominal, ordinal"]'::jsonb, 1, 'The scales increase in mathematical sophistication in the order nominal, ordinal, interval, then ratio.', 'Pre-Council', '🎓', true),
(8470, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Serum potassium level measured in mmol/L is an example of which scale of measurement?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 3, 'Serum potassium has a true zero (0 mmol/L means none present) and equal intervals, making it a ratio scale.', 'Pre-Council', '🎓', true),
(8471, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The New York Heart Association (NYHA) functional classification (Class I-IV) for heart failure severity is an example of which scale of measurement?', '["Nominal scale", "Ordinal scale", "Interval scale", "Ratio scale"]'::jsonb, 1, 'NYHA class ranks increasing severity of symptoms in order, but the classes do not represent equal, measurable intervals, so it is ordinal.', 'Pre-Council', '🎓', true),
(8472, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following statements about interval scales is TRUE?', '["They have a true zero point", "They have equal intervals between values but no true zero point", "They only classify data into unordered categories", "They cannot be used to calculate a mean"]'::jsonb, 1, 'Interval scales have equal, meaningful distances between values but lack an absolute zero, so ratio statements are not valid, though a mean can still be calculated.', 'Pre-Council', '🎓', true),
(8473, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A patient''s marital status (single, married, divorced, widowed) recorded in a research questionnaire is measured on which scale?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 0, 'Marital status categories have no inherent numeric order, making this a nominal-level variable.', 'Pre-Council', '🎓', true),
(8474, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Number of ICU admissions per month at a hospital is an example of which scale of measurement?', '["Nominal", "Ordinal", "Interval", "Ratio"]'::jsonb, 3, 'A count of admissions has a true zero (no admissions) and equal intervals between counts, making it a ratio-level (discrete) variable.', 'Pre-Council', '🎓', true),
(8475, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is a primary method of data collection in nursing research?', '["Reviewing previously published unrelated textbooks only", "Direct observation, interview, questionnaire, or physiological measurement of subjects", "Guessing values based on personal experience", "Copying data from an unrelated prior study"]'::jsonb, 1, 'Primary data collection methods gather original data directly from subjects through observation, interview, questionnaires, or measurement.', 'Pre-Council', '🎓', true),
(8476, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Secondary data refers to data that:', '["Is collected firsthand by the researcher for the current study", "Was collected previously by someone else for another purpose and is reused by the researcher", "Cannot be trusted for use in research", "Is always more accurate than primary data"]'::jsonb, 1, 'Secondary data was originally collected for another purpose (e.g., hospital records) and is subsequently used by a different researcher for a new study.', 'Pre-Council', '🎓', true),
(8477, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A questionnaire is best described as:', '["A set of written questions used to collect data from respondents", "A statistical formula used to calculate significance", "A graph showing a frequency distribution", "A method used only for random sampling"]'::jsonb, 0, 'A questionnaire is a structured data-collection tool consisting of written questions administered to respondents.', 'Pre-Council', '🎓', true),
(8478, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is an advantage of using a structured questionnaire for data collection?', '["It allows unlimited open-ended responses that are difficult to compare", "It is easy to administer to large numbers of respondents and simplifies quantitative analysis", "It always eliminates researcher and respondent bias", "It requires no pilot testing before use"]'::jsonb, 1, 'Structured questionnaires with fixed-response options are efficient to administer to large samples and produce data that is straightforward to code and analyse statistically.', 'Pre-Council', '🎓', true),
(8479, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A frequency distribution table organises raw data by:', '["Showing how often each value or category occurs in a data set", "Listing data only in the order it was originally collected", "Directly calculating the standard deviation", "Showing only the mean and mode of a data set"]'::jsonb, 0, 'A frequency distribution table arranges data to show the number of occurrences (frequency) of each value or category.', 'Pre-Council', '🎓', true),
(8480, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Grouping continuous data into class intervals (e.g., 20-29, 30-39, 40-49 years) before tabulation is done mainly to:', '["Make large data sets easier to summarise and interpret", "Eliminate the need for any summary table", "Increase the overall sample size", "Convert nominal data into ratio data"]'::jsonb, 0, 'Grouping continuous data into class intervals condenses large ranges of values into manageable categories, aiding summary and interpretation.', 'Pre-Council', '🎓', true),
(8481, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is a common graphical method for organising and presenting categorical data?', '["Scatter plot only", "Bar chart or pie chart", "Calculation of standard deviation", "A regression line"]'::jsonb, 1, 'Bar charts and pie charts are standard graphical tools used to display and compare frequencies of categorical data.', 'Pre-Council', '🎓', true),
(8482, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A histogram differs from a bar chart mainly because a histogram:', '["Is used only for nominal data, with gaps between bars", "Displays continuous numerical data with adjoining bars representing continuous class intervals", "Cannot be used to show the frequency of data", "Is used only in qualitative research designs"]'::jsonb, 1, 'A histogram represents continuous, grouped numerical data with bars touching to show the continuous nature of the class intervals, unlike a bar chart used for discrete categories.', 'Pre-Council', '🎓', true),
(8483, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Before a data collection tool (such as a questionnaire) is used in the main study, it should first undergo:', '["Pilot testing to check its clarity, validity, and reliability", "Immediate distribution to all participants without review", "Translation into as many languages as possible regardless of relevance", "Full statistical analysis of anticipated results"]'::jsonb, 0, 'Pilot testing on a small group prior to the main study helps identify problems with clarity, validity, and reliability of the instrument before full-scale use.', 'Pre-Council', '🎓', true),
(8484, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Editing" of collected data before analysis mainly involves:', '["Deleting all data that disagrees with the researcher''s hypothesis", "Checking data for completeness, accuracy, and consistency", "Publishing the raw data immediately", "Recruiting additional participants to the study"]'::jsonb, 1, 'Data editing is the process of reviewing collected data to identify and correct errors, omissions, and inconsistencies before analysis.', 'Pre-Council', '🎓', true),
(8485, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Coding" of data in research refers to:', '["Assigning numerical or symbolic values to responses to facilitate statistical analysis", "Writing the final research report", "Selecting a random sample of participants", "Testing a result for statistical significance"]'::jsonb, 0, 'Coding converts responses (especially categorical ones) into numerical or symbolic values so that data can be entered and analysed statistically.', 'Pre-Council', '🎓', true),
(8486, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following best describes a well-organised approach to data collection and management in a critical care unit research study?', '["Collecting data haphazardly and organising it only after all analysis is complete", "Using standardised tools, ensuring consistent recording procedures, and safely storing/organising data as it is collected", "Allowing multiple different data collection formats to be used interchangeably by different research assistants", "Skipping data verification prior to analysis"]'::jsonb, 1, 'Standardised tools and consistent, ongoing organisation of data reduce errors and support accurate, timely analysis.', 'Pre-Council', '🎓', true),
(8487, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Descriptive statistics are used to:', '["Summarise and describe the main features of a data set, such as mean and frequency", "Make generalisations or predictions about a population from a sample", "Test hypotheses about differences between groups", "Calculate p-values for hypothesis testing"]'::jsonb, 0, 'Descriptive statistics summarise and organise the characteristics of the data actually collected, without generalising beyond it.', 'Pre-Council', '🎓', true),
(8488, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Inferential statistics are used to:', '["Only describe data collected from a sample", "Draw conclusions and make generalisations about a population based on sample data", "Organise raw data into tables", "Replace the need for a research hypothesis"]'::jsonb, 1, 'Inferential statistics use sample data to make inferences, estimates, or generalisations about the wider population from which the sample was drawn.', 'Pre-Council', '🎓', true),
(8489, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The "mean" of a data set is:', '["The most frequently occurring value", "The middle value when data are arranged in order", "The sum of all values divided by the number of values", "The difference between the highest and lowest values"]'::jsonb, 2, 'The mean (arithmetic average) is calculated by summing all values and dividing by the total number of values.', 'Pre-Council', '🎓', true),
(8490, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The "median" of a data set is:', '["The average of all values in the set", "The middle value when data are arranged in ascending or descending order", "The value that occurs most frequently", "The square root of the variance"]'::jsonb, 1, 'The median is the middle value of an ordered data set, dividing it into two equal halves.', 'Pre-Council', '🎓', true),
(8491, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The "mode" of a data set is:', '["The middle value of the data set", "The value that occurs most frequently in the data set", "The sum of all values divided by their count", "The range of the data set"]'::jsonb, 1, 'The mode is simply the most frequently occurring value or category in a data set.', 'Pre-Council', '🎓', true),
(8492, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which measure of central tendency is most appropriate for a data set with extreme outlier values (a highly skewed distribution)?', '["Mean", "Median", "Mode", "Standard deviation"]'::jsonb, 1, 'The median is less affected by extreme outliers than the mean, making it the more appropriate measure of central tendency for skewed distributions.', 'Pre-Council', '🎓', true),
(8493, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which measure of central tendency is appropriate for nominal (categorical) data, such as the most common blood group among patients in a ward?', '["Mean", "Median", "Mode", "Standard deviation"]'::jsonb, 2, 'The mode is the only measure of central tendency that can meaningfully be applied to nominal categorical data.', 'Pre-Council', '🎓', true),
(8494, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The "range" of a data set is calculated as:', '["The sum of all values in the set", "The highest value minus the lowest value", "The middle value of the ordered data", "The average deviation of scores from the mean"]'::jsonb, 1, 'The range is the simplest measure of spread, obtained by subtracting the smallest value from the largest value in the data set.', 'Pre-Council', '🎓', true),
(8495, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The "standard deviation" is a measure of:', '["The central tendency of a data set", "The average distance or spread of individual values from the mean", "The most frequently occurring value", "The relationship between two variables"]'::jsonb, 1, 'Standard deviation quantifies how much individual data values typically deviate from the mean, indicating the spread or variability of the data.', 'Pre-Council', '🎓', true),
(8496, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A small standard deviation in a set of vital sign readings indicates that:', '["The values are widely spread out from the mean", "The values are clustered closely around the mean", "The mean calculated is incorrect", "There is strong statistical significance"]'::jsonb, 1, 'A small standard deviation means individual values lie close to the mean, indicating low variability in the data.', 'Pre-Council', '🎓', true),
(8497, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Variance" is defined as:', '["The square root of the standard deviation", "The square of the standard deviation, representing the average squared deviation from the mean", "The same measure as the range", "A measure used only for nominal data"]'::jsonb, 1, 'Variance is the standard deviation squared; it expresses the average of the squared deviations of each value from the mean.', 'Pre-Council', '🎓', true),
(8498, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is an example of an inferential statistical technique?', '["Calculating the mean age of patients in a study sample", "A t-test comparing mean blood pressure between two treatment groups to infer a population difference", "Drawing a bar chart of patients'' blood groups", "Calculating the frequency of a symptom within the sample"]'::jsonb, 1, 'A t-test is an inferential technique because it uses sample data to draw conclusions about differences likely to exist in the wider population.', 'Pre-Council', '🎓', true),
(8499, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "p-value" in hypothesis testing represents:', '["The probability that the research/alternative hypothesis is true", "The probability of obtaining the observed result (or a more extreme one) if the null hypothesis were true", "The percentage of patients cured by an intervention", "The sample size needed for a study"]'::jsonb, 1, 'The p-value is the probability of observing data as extreme as, or more extreme than, what was found, assuming the null hypothesis is correct.', 'Pre-Council', '🎓', true),
(8500, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'In most nursing and health research, a result is typically considered "statistically significant" when the p-value is:', '["Greater than 0.05", "Less than or equal to 0.05", "Equal to 1.0", "Greater than 0.5"]'::jsonb, 1, 'A p-value at or below the conventional alpha level of 0.05 is generally interpreted as evidence strong enough to reject the null hypothesis.', 'Pre-Council', '🎓', true),
(8501, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The "level of significance" (alpha level), commonly set at 0.05 in research, means that:', '["There is a 5% risk of concluding a difference exists when it truly does not (a Type I error)", "There is a 95% chance the null hypothesis is true", "The study carries no risk of statistical error", "5% of the sample data must be excluded from analysis"]'::jsonb, 0, 'Setting alpha at 0.05 means the researcher accepts a 5% risk of a Type I error, that is, incorrectly rejecting a true null hypothesis.', 'Pre-Council', '🎓', true),
(8502, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "Type I error" in hypothesis testing occurs when:', '["A true null hypothesis is incorrectly rejected (a false positive)", "A false null hypothesis is not rejected", "The wrong statistical test is applied to the data", "The sample size chosen is too large"]'::jsonb, 0, 'A Type I error is a false positive: concluding there is a significant effect or difference when, in reality, none exists.', 'Pre-Council', '🎓', true),
(8503, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "Type II error" in hypothesis testing occurs when:', '["A true null hypothesis is rejected", "A false null hypothesis is incorrectly accepted or not rejected (a false negative)", "The p-value is exactly 0.05", "The alternative hypothesis is proven true"]'::jsonb, 1, 'A Type II error is a false negative: failing to detect a real effect or difference that actually exists in the population.', 'Pre-Council', '🎓', true),
(8504, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A study comparing two pain-relief protocols reports p = 0.03. The correct interpretation is:', '["There is a 3% chance the treatments are truly different", "The result is statistically significant at the 0.05 level, suggesting the observed difference is unlikely due to chance alone", "The treatments are clinically identical in every respect", "The study should be discarded because the p-value is too low"]'::jsonb, 1, 'Since p = 0.03 is below the conventional 0.05 threshold, the result is statistically significant, meaning the observed difference is unlikely to have occurred by chance alone.', 'Pre-Council', '🎓', true),
(8505, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A study reports p = 0.45 when comparing two nursing interventions. This means:', '["The result is statistically significant", "The result is not statistically significant at the conventional 0.05 level, so the null hypothesis is not rejected", "The intervention being tested definitely does not work at all", "There were 45% fewer patients than expected in the study"]'::jsonb, 1, 'A p-value of 0.45 is well above 0.05, so the observed difference could plausibly be due to chance, and the null hypothesis is not rejected.', 'Pre-Council', '🎓', true),
(8506, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A "confidence interval" (e.g., a 95% CI) provides information about:', '["The exact value of a population parameter with complete certainty", "A range of values within which the true population parameter is likely to lie, at a stated level of confidence", "The p-value obtained from a statistical test", "The exact number of participants needed for a study"]'::jsonb, 1, 'A confidence interval gives a plausible range for the true population value, along with the level of confidence (e.g., 95%) that the range contains it.', 'Pre-Council', '🎓', true),
(8507, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which statistical test is commonly used to compare the means of two independent groups, such as two treatment groups?', '["Chi-square test", "Student''s t-test", "Pearson correlation coefficient", "Frequency distribution table"]'::jsonb, 1, 'The independent-samples t-test is used to compare the means of two separate groups to see if they differ significantly.', 'Pre-Council', '🎓', true),
(8508, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The Chi-square test is most appropriately used to analyse:', '["The relationship or association between two categorical (nominal) variables", "The correlation between two continuous variables", "The mean difference between two groups", "The standard deviation of a single sample"]'::jsonb, 0, 'The Chi-square test of independence assesses whether there is a statistically significant association between two categorical variables.', 'Pre-Council', '🎓', true),
(8509, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Statistical significance found in a study means:', '["The finding is automatically clinically important for patient care", "The observed result is unlikely to have occurred by chance alone, based on the chosen probability threshold", "The sample size used was too small to matter", "The study has no limitations whatsoever"]'::jsonb, 1, 'Statistical significance indicates a result is unlikely due to chance, but this does not automatically mean the finding is large enough or important enough to be clinically significant.', 'Pre-Council', '🎓', true),
(8510, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'When comparing the means of more than two groups simultaneously (e.g., three different ICU sedation protocols), which statistical test is most appropriate?', '["Paired t-test", "Analysis of Variance (ANOVA)", "Chi-square test", "A simple frequency count"]'::jsonb, 1, 'ANOVA is designed to compare means across three or more groups simultaneously while controlling the overall risk of a Type I error.', 'Pre-Council', '🎓', true),
(8511, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Statistics is important in critical care nursing mainly because it helps nurses to:', '["Interpret patient data, monitor trends in vital signs and outcomes, and make evidence-based clinical decisions", "Avoid the need for clinical judgement entirely", "Replace physicians in diagnosing illness", "Eliminate the need for documentation"]'::jsonb, 0, 'Statistical literacy allows critical care nurses to interpret trends and evidence to support sound, evidence-based clinical decision-making.', 'Pre-Council', '🎓', true),
(8512, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'In quality improvement within an ICU, statistics can be used to:', '["Track and analyse infection rates, mortality rates, and complication trends over time to improve care", "Only calculate nurses'' salaries", "Determine the architectural design of the hospital", "Replace individualised nursing care plans"]'::jsonb, 0, 'Statistical tracking of clinical outcome indicators (infection rates, mortality, complications) over time supports quality improvement initiatives in critical care.', 'Pre-Council', '🎓', true),
(8513, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Understanding basic statistics helps a critical care nurse to:', '["Critically appraise research evidence before applying it to practice", "Avoid reading research literature altogether", "Diagnose diseases independently of physicians", "Prescribe medications without following protocols"]'::jsonb, 0, 'A working knowledge of statistics enables nurses to critically evaluate the quality and applicability of research evidence before using it in practice.', 'Pre-Council', '🎓', true),
(8514, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is an example of the practical use of statistics in a critical care unit?', '["Calculating the average length of stay and readmission rate of ICU patients to evaluate care quality", "Deciding visiting hours purely based on staff preference", "Choosing the colour of hospital uniforms", "Setting the hospital''s annual holiday calendar"]'::jsonb, 0, 'Metrics like average length of stay and readmission rate are statistical indicators used to evaluate and improve the quality of critical care.', 'Pre-Council', '🎓', true),
(8515, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Statistical monitoring of patient vital sign trends (e.g., blood pressure and oxygen saturation over time) in critical care primarily supports:', '["Early identification of deterioration and timely clinical intervention", "Replacing the need for continuous nursing assessment", "Hospital billing purposes only", "Hospital marketing activities"]'::jsonb, 0, 'Tracking trends in vital signs statistically helps clinicians detect early signs of deterioration and intervene promptly.', 'Pre-Council', '🎓', true),
(8516, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A critical care unit wants to determine whether a new ventilator weaning protocol reduces weaning time compared with the old protocol. This question is best answered using:', '["Descriptive statistics alone, with no inferential testing", "Inferential statistics, such as a t-test, to compare mean weaning times between the two protocol groups", "Only unstructured qualitative interviews with staff", "A pie chart showing staff opinions on the protocols"]'::jsonb, 1, 'Comparing mean weaning times between two groups to determine whether an observed difference reflects a true population effect requires inferential statistics, such as a t-test.', 'Pre-Council', '🎓', true),
(8517, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Informed consent" in research requires that participants:', '["Are given full information about the study and voluntarily agree to participate without coercion", "Sign a consent form without any explanation of the study", "Are paid a fee to guarantee their participation", "Are only informed about the study after it has been completed"]'::jsonb, 0, 'Valid informed consent requires that participants receive adequate information about the study and agree to participate voluntarily, free from coercion.', 'Pre-Council', '🎓', true),
(8518, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is an essential element of valid informed consent in research involving critically ill patients?', '["Consent obtained from the patient or a legally authorised representative when the patient lacks decision-making capacity", "Assuming consent because the patient is unconscious", "Verbal consent from a family member with no documentation at all", "Skipping consent because the study is believed to benefit the patient"]'::jsonb, 0, 'When a critically ill patient cannot consent for themselves, valid consent must be obtained from a legally authorised representative, following appropriate ethical and legal safeguards.', 'Pre-Council', '🎓', true),
(8519, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The principle of "beneficence" in research ethics means that researchers must:', '["Maximise possible benefits and minimise possible harm to participants", "Ensure all participants are paid an identical fee", "Publish results even when they may harm participants", "Recruit as many participants as possible regardless of risk"]'::jsonb, 0, 'Beneficence obliges researchers to design studies that maximise potential benefit while minimising risk of harm to participants.', 'Pre-Council', '🎓', true),
(8520, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The principle of "non-maleficence" in research ethics primarily requires the researcher to:', '["Avoid causing harm to research participants", "Guarantee a cure for all participants involved", "Withhold important information from participants", "Increase the sample size beyond what is scientifically necessary"]'::jsonb, 0, 'Non-maleficence is the ethical obligation to avoid inflicting harm on research participants.', 'Pre-Council', '🎓', true),
(8521, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Confidentiality" in research means that:', '["A participant''s identity and personal data are protected and not disclosed without permission", "All data collected must be made public immediately after collection", "Only the researcher''s supervisor is allowed to know the study results", "Participants'' names must be published alongside the findings"]'::jsonb, 0, 'Confidentiality obliges the researcher to protect participants'' identities and personal information from unauthorised disclosure.', 'Pre-Council', '🎓', true),
(8522, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Anonymity" in research differs from confidentiality in that anonymity means:', '["The researcher knows participants'' identities but promises not to disclose them", "Even the researcher cannot link collected data back to the identity of the participant", "Data is shared publicly with participants'' names attached", "Only quantitative data is being collected in the study"]'::jsonb, 1, 'Anonymity means participant identities are never recorded or known, even to the researcher, whereas confidentiality means identities are known but protected from disclosure.', 'Pre-Council', '🎓', true),
(8523, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'The ethical principle of "justice" in research requires that:', '["The benefits and burdens of research are distributed fairly among different groups in society", "Only wealthy participants are recruited into studies", "Vulnerable populations are always excluded from all research", "Researchers select participants based purely on convenience"]'::jsonb, 0, 'Justice requires fair selection of participants and equitable distribution of the benefits and burdens of research across populations.', 'Pre-Council', '🎓', true),
(8524, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Plagiarism" in research refers to:', '["Presenting another person''s work, ideas, or words as one''s own without proper acknowledgement", "Correctly citing all sources used in a report", "Collecting primary data directly from participants", "Peer-reviewing a colleague''s manuscript"]'::jsonb, 0, 'Plagiarism is the act of using someone else''s ideas, words, or work without giving proper credit, which is a serious form of academic and research misconduct.', 'Pre-Council', '🎓', true),
(8525, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is considered research misconduct?', '["Fabricating or falsifying data to support a desired outcome", "Obtaining ethical approval before starting a study", "Reporting all findings, including those that do not support the hypothesis", "Properly citing all sources used"]'::jsonb, 0, 'Fabrication or falsification of data is a major form of research misconduct that undermines the validity and trustworthiness of research.', 'Pre-Council', '🎓', true),
(8526, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Before conducting a research study involving human participants, a researcher should first obtain approval from:', '["An Institutional Review Board or Research Ethics Committee", "The hospital''s catering department", "The participants'' employers only", "No approval is needed if the study is for academic purposes only"]'::jsonb, 0, 'Ethical approval from an Institutional Review Board or Research Ethics Committee is required before research involving human participants can proceed, regardless of the study''s purpose.', 'Pre-Council', '🎓', true),
(8527, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A participant''s "right to withdraw" from a research study means that:', '["Once enrolled, a participant must complete the entire study regardless of circumstances", "A participant may discontinue participation at any time without penalty or loss of usual care", "Only the researcher can decide when a participant leaves the study", "Withdrawal is only permitted before data collection begins"]'::jsonb, 1, 'Ethical research practice requires that participants retain the right to withdraw at any point without penalty or any negative effect on their standard care.', 'Pre-Council', '🎓', true),
(8528, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following best protects research data confidentiality when using patient records in a critical care study?', '["De-identifying or coding patient data and storing it securely with restricted access", "Leaving patient files openly accessible on a shared computer", "Publishing raw, identifiable patient records alongside the study", "Discussing individual patient data openly in public forums"]'::jsonb, 0, 'De-identifying data and restricting access are standard practices for protecting participant confidentiality when using clinical records for research.', 'Pre-Council', '🎓', true),
(8529, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Vulnerable populations (e.g., unconscious ICU patients, children, cognitively impaired persons) in research require:', '["No special ethical consideration since they cannot consent", "Additional ethical safeguards, such as consent from a legally authorised representative and extra protections against exploitation", "Automatic exclusion from all forms of healthcare research", "Consent obtained from any staff member present at the time"]'::jsonb, 1, 'Vulnerable populations require additional protections, including surrogate consent and extra safeguards, to prevent exploitation while still allowing beneficial research to occur.', 'Pre-Council', '🎓', true),
(8530, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which historical document/code first established key ethical principles, particularly voluntary informed consent, for research involving human subjects, largely in response to unethical experimentation during World War II?', '["The Nuremberg Code", "The APA Publication Manual", "The Vancouver referencing style guidelines", "The Iowa Model of research utilisation"]'::jsonb, 0, 'The Nuremberg Code (1947) was the first major international statement establishing ethical principles, especially voluntary informed consent, for human subjects research, following the post-war trials of Nazi war criminals.', 'Pre-Council', '🎓', true),
(8531, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A researcher discovers during data analysis that changing a few outlier values would make results reach statistical significance, and does so without justification. This is an example of:', '["Acceptable statistical practice", "Data fabrication/falsification, a form of research misconduct", "Standard data cleaning procedure", "Proper application of inferential statistics"]'::jsonb, 1, 'Altering data values without a valid, documented, methodological reason to achieve a desired result constitutes data falsification, a serious ethical violation.', 'Pre-Council', '🎓', true),
(8532, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'When critiquing a research report, the "problem statement" should be evaluated for:', '["Clarity, significance, and whether it is researchable", "The total number of pages in the report", "The font size used in the document", "The publisher''s reputation alone"]'::jsonb, 0, 'A good problem statement should be clear, significant to the field, and framed in a way that can actually be investigated through research.', 'Pre-Council', '🎓', true),
(8533, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A well-written literature review in a research report should:', '["Include only studies that agree with the researcher''s hypothesis", "Critically synthesise relevant, current studies to show the gap the current study addresses", "Be omitted entirely to save space in the report", "Contain no citations to previous work"]'::jsonb, 1, 'A strong literature review critically synthesises existing relevant research to justify the need for the current study and situate it within the existing body of knowledge.', 'Pre-Council', '🎓', true),
(8534, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'When critiquing the methodology section of a research report, a reviewer should assess:', '["Whether the research design, sample, and data collection methods are appropriate and clearly described", "Only the length of the discussion section", "The number of authors listed on the report", "The colour scheme of the published journal"]'::jsonb, 0, 'Evaluating the methodology involves judging whether the design, sampling, and data collection procedures are appropriate, rigorous, and clearly reported.', 'Pre-Council', '🎓', true),
(8535, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Validity" of a research instrument refers to:', '["The consistency of results obtained over repeated measurements", "The extent to which an instrument accurately measures what it is intended to measure", "The monetary cost of using the instrument", "The number of questions contained in the instrument"]'::jsonb, 1, 'Validity concerns whether an instrument truly measures the concept it claims to measure.', 'Pre-Council', '🎓', true),
(8536, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', '"Reliability" of a research instrument refers to:', '["The extent to which an instrument produces consistent, repeatable results", "Whether the instrument measures the intended underlying concept", "The ethical approval status of the study", "The sample size used in the study"]'::jsonb, 0, 'Reliability concerns the consistency and repeatability of measurements obtained using the same instrument.', 'Pre-Council', '🎓', true),
(8537, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'When critiquing a research report''s sample and sampling method, a reviewer should ask whether:', '["The sample size and sampling technique were appropriate and representative of the target population", "The sample was chosen based only on the researcher''s personal friends", "Sampling method is irrelevant to the quality of research findings", "A larger sample always guarantees valid conclusions regardless of method used"]'::jsonb, 0, 'Appropriate, representative sampling is essential to the validity and generalisability of research findings, so this must be carefully evaluated during critique.', 'Pre-Council', '🎓', true),
(8538, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'In critiquing the results/findings section of a report, a reviewer should check whether:', '["Statistical analyses used are appropriate for the data and hypotheses, and results are clearly presented", "Only positive findings supporting the hypothesis are reported", "Tables and figures are excluded to shorten the report", "The results reflect the researcher''s personal opinion rather than the data"]'::jsonb, 0, 'A sound results section uses statistical methods appropriate to the data type and hypotheses and presents findings clearly and objectively.', 'Pre-Council', '🎓', true),
(8539, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'A limitation section in a research report is important because it:', '["Identifies weaknesses or constraints of the study that may affect interpretation or generalisability of findings", "Is only included to make the report appear longer", "Proves that the study has no scientific value at all", "Replaces the need for a discussion section"]'::jsonb, 0, 'Acknowledging limitations helps readers appropriately judge how far the findings can be trusted and generalised.', 'Pre-Council', '🎓', true),
(8540, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'When evaluating whether findings of a study can be generalised, a critical reader should consider:', '["Whether the sample and setting are representative of the wider population the findings are meant to apply to", "Only whether the abstract sounds convincing", "Whether the study was published in a well-known journal, regardless of its methods", "The number of statistical tests used regardless of appropriateness"]'::jsonb, 0, 'Generalisability depends on whether the study sample and setting adequately represent the broader population to which the findings will be applied.', 'Pre-Council', '🎓', true),
(8541, 'Statistics and Research Communication', 'CCN Curriculum — Applied Research Methodology', 'Which of the following is a red flag suggesting a research report may be of low quality or questionable rigor?', '["A clear ethical approval statement and detailed, appropriate methodology", "Vague methodology, unclear sampling procedures, and conclusions not supported by the presented data", "A well-referenced discussion connecting findings to existing literature", "Explicitly stated study limitations"]'::jsonb, 1, 'Vague or poorly described methods, unclear sampling, and conclusions unsupported by the data are warning signs of low-quality or unreliable research.', 'Pre-Council', '🎓', true),
(8542, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following best defines nutrition as a physiological process?', '["The sum of processes by which an organism takes in and utilises food substances for growth, repair, and maintenance of body functions", "The act of chewing and swallowing food", "The storage of excess calories as adipose tissue", "The prescription of therapeutic diets by a dietitian"]'::jsonb, 0, 'Nutrition is the overall process of ingestion, digestion, absorption, transport, utilisation, and excretion of food substances required for growth, repair, and maintenance of body functions.', 'Pre-Council', '🎓', true),
(8543, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Nutrients are classified as macronutrients or micronutrients primarily on the basis of which criterion?', '["The chemical charge of the nutrient", "The quantity required daily by the body", "Whether the nutrient is water-soluble or fat-soluble", "Whether the nutrient is synthesised endogenously"]'::jsonb, 1, 'Macronutrients (carbohydrates, proteins, fats) are needed in large (gram) quantities, while micronutrients (vitamins, minerals, trace elements) are needed only in small (milligram or microgram) amounts.', 'Pre-Council', '🎓', true),
(8544, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following is classified as a macronutrient?', '["Zinc", "Vitamin D", "Protein", "Iodine"]'::jsonb, 2, 'Protein, along with carbohydrate and fat, is a macronutrient because it is required in relatively large amounts and provides energy and structural material.', 'Pre-Council', '🎓', true),
(8545, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'An essential nutrient is best described as one that:', '["Cannot be synthesised by the body in adequate amounts and must be obtained from the diet", "Is only required during periods of critical illness", "Provides no caloric value to the body", "Is stored indefinitely in adipose tissue"]'::jsonb, 0, 'Essential nutrients (e.g., essential amino acids, essential fatty acids, most vitamins) cannot be synthesised by the body in sufficient quantity and must be supplied through diet.', 'Pre-Council', '🎓', true),
(8546, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which macronutrient yields the highest amount of energy per gram when oxidised?', '["Carbohydrate", "Protein", "Fat", "Alcohol contributes more than fat"]'::jsonb, 2, 'Fat yields approximately 9 kcal/g, compared with 4 kcal/g for carbohydrate and protein, making it the most energy-dense macronutrient.', 'Pre-Council', '🎓', true),
(8547, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following best distinguishes a simple carbohydrate from a complex carbohydrate?', '["Simple carbohydrates contain nitrogen while complex carbohydrates do not", "Simple carbohydrates are mono- or disaccharides, while complex carbohydrates are polysaccharides made of many sugar units", "Simple carbohydrates cannot be digested by humans", "Complex carbohydrates always have a higher glycaemic index than simple carbohydrates"]'::jsonb, 1, 'Simple carbohydrates consist of one or two sugar units (e.g., glucose, sucrose), whereas complex carbohydrates are polysaccharides such as starch and glycogen composed of many linked sugar units.', 'Pre-Council', '🎓', true),
(8548, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which class of lipid is the primary storage form of fat in adipose tissue and a major dietary energy source?', '["Phospholipids", "Triglycerides", "Cholesterol esters", "Sterols"]'::jsonb, 1, 'Triglycerides, composed of a glycerol backbone with three fatty acid chains, are the main storage and dietary form of fat.', 'Pre-Council', '🎓', true),
(8549, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Proteins are unique among the macronutrients because they contain which element that carbohydrates and fats lack?', '["Carbon", "Hydrogen", "Nitrogen", "Oxygen"]'::jsonb, 2, 'Proteins are composed of amino acids that contain nitrogen in their amino group, distinguishing them structurally from carbohydrates and fats, which contain only carbon, hydrogen, and oxygen.', 'Pre-Council', '🎓', true),
(8550, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Vitamins and minerals are classified as micronutrients mainly because they:', '["Have no role in metabolism", "Are required in small quantities but are essential for regulating metabolic processes", "Provide significant caloric energy", "Can be completely synthesised by the human body"]'::jsonb, 1, 'Micronutrients such as vitamins and minerals do not provide significant calories but are required in small amounts to act as coenzymes and cofactors in metabolic reactions.', 'Pre-Council', '🎓', true),
(8551, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following pairs correctly matches a nutrient with its classification?', '["Iron - macronutrient", "Cholesterol - micronutrient", "Linoleic acid - essential fatty acid (macronutrient)", "Vitamin C - macronutrient"]'::jsonb, 2, 'Linoleic acid is an essential fatty acid that the body cannot synthesise and must obtain from the diet; it is part of the fat macronutrient class.', 'Pre-Council', '🎓', true),
(8552, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Water is often classified alongside the six major nutrient classes because it:', '["Provides 4 kcal/g of energy", "Is essential for metabolic reactions, thermoregulation, and transport of nutrients despite providing no calories", "Is synthesised endogenously in sufficient amounts to meet daily needs", "Is classified as a micronutrient due to small required volume"]'::jsonb, 1, 'Although water yields no energy, it is essential for virtually all metabolic processes, making it one of the six recognised classes of nutrients alongside carbohydrates, proteins, fats, vitamins, and minerals.', 'Pre-Council', '🎓', true),
(8553, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Salivary amylase (ptyalin) begins the digestion of which nutrient in the mouth?', '["Protein", "Starch (carbohydrate)", "Triglycerides", "Cellulose"]'::jsonb, 1, 'Salivary amylase initiates the hydrolysis of starch into smaller polysaccharides and maltose in the mouth, although its action is limited once food reaches the acidic stomach.', 'Pre-Council', '🎓', true),
(8554, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Pepsin, the main proteolytic enzyme of the stomach, is secreted in an inactive form called:', '["Trypsinogen", "Pepsinogen", "Chymotrypsinogen", "Procarboxypeptidase"]'::jsonb, 1, 'Chief cells secrete pepsinogen, which is activated to pepsin by hydrochloric acid from parietal cells and by pepsin itself, allowing it to begin protein digestion in the stomach.', 'Pre-Council', '🎓', true),
(8555, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The majority of digestion and absorption of carbohydrates, proteins, and fats occurs in which part of the gastrointestinal tract?', '["Stomach", "Duodenum and jejunum of the small intestine", "Ileum only", "Ascending colon"]'::jsonb, 1, 'Most enzymatic digestion and nutrient absorption take place in the duodenum and jejunum, where pancreatic enzymes and bile mix with chyme and the mucosal surface area is greatest.', 'Pre-Council', '🎓', true),
(8556, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Pancreatic lipase, which digests dietary triglycerides, requires which substance to emulsify fat for effective enzymatic action?', '["Gastric acid", "Bile salts", "Intrinsic factor", "Secretin alone"]'::jsonb, 1, 'Bile salts, secreted by the liver and stored in the gallbladder, emulsify large fat globules into smaller droplets (micelles), increasing surface area for pancreatic lipase to act upon.', 'Pre-Council', '🎓', true),
(8557, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Vitamin B12 (cobalamin) absorption in the terminal ileum is dependent on binding with which substance produced by gastric parietal cells?', '["Pepsin", "Intrinsic factor", "Gastrin", "Hydrochloric acid alone"]'::jsonb, 1, 'Intrinsic factor, secreted by gastric parietal cells, binds vitamin B12 and enables its receptor-mediated absorption specifically in the terminal ileum.', 'Pre-Council', '🎓', true),
(8558, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which site in the gastrointestinal tract is primarily responsible for the absorption of dietary iron?', '["Stomach", "Duodenum and proximal jejunum", "Ileum", "Colon"]'::jsonb, 1, 'Iron is absorbed mainly in the duodenum and proximal jejunum, where the acidic environment left over from the stomach favours conversion to the more absorbable ferrous (Fe2+) form.', 'Pre-Council', '🎓', true),
(8559, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Bile acids and fat-soluble vitamins that escape absorption in the jejunum are predominantly reabsorbed in which segment?', '["Duodenum", "Terminal ileum", "Sigmoid colon", "Rectum"]'::jsonb, 1, 'The terminal ileum has specific transporters for bile acid reabsorption (enterohepatic circulation) and is also important for absorption of vitamin B12 and residual fat-soluble vitamins.', 'Pre-Council', '🎓', true),
(8560, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Water and electrolytes are absorbed in largest quantity in which region of the gastrointestinal tract?', '["Oesophagus", "Small intestine, primarily jejunum and ileum", "Stomach", "Rectum"]'::jsonb, 1, 'Although the colon absorbs some water, the majority of water and electrolyte absorption (roughly 80-90%) occurs across the small intestine, particularly the jejunum and ileum.', 'Pre-Council', '🎓', true),
(8561, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Proteins are ultimately absorbed into the enterocyte primarily as which end products of digestion?', '["Intact polypeptides only", "Free amino acids and small di- and tripeptides", "Triglycerides", "Monosaccharides"]'::jsonb, 1, 'Pancreatic and brush-border proteases break dietary protein down to free amino acids and small di-/tripeptides, which are transported across the enterocyte by specific carrier systems.', 'Pre-Council', '🎓', true),
(8562, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Fructose is absorbed across the intestinal brush border mainly via which transport mechanism?', '["Sodium-dependent active transport (SGLT1)", "Facilitated diffusion via GLUT5", "Simple passive diffusion through the lipid bilayer", "Endocytosis"]'::jsonb, 1, 'Unlike glucose and galactose, which use the sodium-glucose cotransporter SGLT1, fructose is absorbed by facilitated diffusion via the GLUT5 transporter.', 'Pre-Council', '🎓', true),
(8563, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Chyme entering the duodenum stimulates the release of secretin, whose primary action is to:', '["Stimulate gastric acid secretion", "Stimulate the pancreas to release bicarbonate-rich fluid that neutralises acidic chyme", "Inhibit bile release from the gallbladder", "Increase gastric emptying rate"]'::jsonb, 1, 'Secretin, released by duodenal S cells in response to acidic chyme, stimulates the pancreas to secrete bicarbonate, which neutralises gastric acid and creates an optimal pH for pancreatic enzymes.', 'Pre-Council', '🎓', true),
(8564, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Cholecystokinin (CCK), released from the duodenal mucosa in response to fat and protein in chyme, primarily causes:', '["Gallbladder contraction and release of pancreatic digestive enzymes", "Inhibition of pancreatic enzyme secretion", "Increased salivary secretion", "Relaxation of the pyloric sphincter only"]'::jsonb, 0, 'CCK stimulates gallbladder contraction (releasing bile) and stimulates the pancreas to secrete digestive enzymes, while also slowing gastric emptying to allow adequate digestion time.', 'Pre-Council', '🎓', true),
(8565, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Digestion of dietary starch to maltose and other oligosaccharides is chiefly completed in the small intestine by which enzyme?', '["Salivary amylase", "Pancreatic amylase", "Lactase", "Enterokinase"]'::jsonb, 1, 'Pancreatic amylase, secreted into the duodenum, continues and largely completes the breakdown of starch into maltose, maltotriose, and dextrins, which are then further hydrolysed by brush-border enzymes.', 'Pre-Council', '🎓', true),
(8566, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Enterokinase (enteropeptidase), located on the duodenal brush border, has which key digestive role?', '["Converts trypsinogen to active trypsin, which then activates other pancreatic proenzymes", "Digests dietary fibre", "Emulsifies fat", "Absorbs vitamin B12"]'::jsonb, 0, 'Enterokinase cleaves trypsinogen into active trypsin, which in turn activates chymotrypsinogen, procarboxypeptidase, and other pancreatic zymogens, triggering the protein digestion cascade.', 'Pre-Council', '🎓', true),
(8567, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The colon''s main digestive/absorptive contribution to overall nutrition is:', '["Absorption of amino acids", "Absorption of water, electrolytes, and short-chain fatty acids produced by bacterial fermentation of fibre", "Digestion of triglycerides via colonic lipase", "Absorption of the majority of dietary glucose"]'::jsonb, 1, 'The colon absorbs water and electrolytes and also absorbs short-chain fatty acids generated by bacterial fermentation of undigested fibre, but it plays little role in absorbing the bulk of macronutrients, which occurs in the small intestine.', 'Pre-Council', '🎓', true),
(8568, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'How many kilocalories are provided per gram when carbohydrate is metabolised (Atwater factor)?', '["2 kcal/g", "4 kcal/g", "7 kcal/g", "9 kcal/g"]'::jsonb, 1, 'Using the standard Atwater conversion factors, carbohydrate yields approximately 4 kcal per gram, the same as protein, while fat yields about 9 kcal/g.', 'Pre-Council', '🎓', true),
(8569, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A patient''s enteral feed provides 60 g carbohydrate, 20 g protein, and 15 g fat per serving. Using standard Atwater factors, approximately how many total kilocalories does this serving provide?', '["275 kcal", "395 kcal", "455 kcal", "605 kcal"]'::jsonb, 2, 'Calculation: (60 g CHO x 4) + (20 g protein x 4) + (15 g fat x 9) = 240 + 80 + 135 = 455 kcal.', 'Pre-Council', '🎓', true),
(8570, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The primary molecule that serves as the immediate usable energy currency for cellular metabolic reactions is:', '["Glucose", "Adenosine triphosphate (ATP)", "Glycogen", "Acetyl-CoA"]'::jsonb, 1, 'ATP is generated from the oxidation of macronutrients through glycolysis, the citric acid cycle, and oxidative phosphorylation, and serves as the direct energy source for cellular work.', 'Pre-Council', '🎓', true),
(8571, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Basal metabolic rate (BMR) is best defined as the:', '["Total energy expenditure during vigorous exercise", "Minimum energy required to maintain vital body functions at complete rest in a fasting, thermoneutral state", "Energy used solely for digestion of food", "Energy expended only during sleep with active dreaming"]'::jsonb, 1, 'BMR represents the energy needed to sustain basic physiological functions (respiration, circulation, cellular metabolism) at complete physical and mental rest, typically measured after an overnight fast.', 'Pre-Council', '🎓', true),
(8572, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The thermic effect of food (diet-induced thermogenesis) refers to:', '["Energy expended in physical activity after eating", "The increase in energy expenditure above BMR due to digestion, absorption, and metabolism of ingested nutrients", "The energy lost as heat during exercise", "The caloric value of food as measured by a bomb calorimeter"]'::jsonb, 1, 'The thermic effect of food is the energy cost of digesting, absorbing, transporting, and storing nutrients, and it accounts for roughly 5-10% of total daily energy expenditure, with protein having the highest thermic effect.', 'Pre-Council', '🎓', true),
(8573, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In critical illness, the hypermetabolic stress response (e.g., after major trauma or sepsis) is characterised by:', '["Decreased catecholamine and cortisol levels lowering metabolic rate", "Increased catabolism, elevated resting energy expenditure, and accelerated protein breakdown despite adequate nutrient intake", "Complete cessation of gluconeogenesis", "Uniform decrease in all hormone levels"]'::jsonb, 1, 'The stress response triggers surges in catecholamines, cortisol, and glucagon that increase resting energy expenditure and drive catabolism of muscle protein for gluconeogenesis, even when nutrients are being supplied.', 'Pre-Council', '🎓', true),
(8574, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Glycogenolysis refers to the process by which the body:', '["Synthesises new glucose from amino acids", "Breaks down stored glycogen in the liver and muscle to release glucose", "Converts glucose into fat for storage", "Breaks down triglycerides into fatty acids and glycerol"]'::jsonb, 1, 'Glycogenolysis is the breakdown of stored glycogen (mainly in liver and skeletal muscle) into glucose or glucose-1-phosphate to maintain blood glucose levels, especially during early fasting.', 'Pre-Council', '🎓', true),
(8575, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Gluconeogenesis becomes an increasingly important source of blood glucose during prolonged fasting because:', '["Liver glycogen stores are typically depleted within 24 hours of fasting", "Dietary carbohydrate intake increases during fasting", "Insulin levels rise sharply during fasting", "The kidneys stop filtering glucose"]'::jsonb, 0, 'Hepatic glycogen stores are limited and become largely depleted within about 24 hours of fasting, after which the body increasingly relies on gluconeogenesis from amino acids, lactate, and glycerol to maintain glucose supply.', 'Pre-Council', '🎓', true),
(8576, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which statement best describes the relationship between nutrition and energy utilisation in the body?', '["Energy production is entirely independent of nutrient intake", "Ingested macronutrients are oxidised through metabolic pathways to generate ATP, which powers cellular functions, growth, and repair", "Only carbohydrates can be converted into cellular energy", "Vitamins are the primary source of caloric energy in the diet"]'::jsonb, 1, 'Nutrition supplies the substrates (carbohydrate, fat, protein) that are metabolically oxidised to generate ATP, linking dietary intake directly to the body''s capacity for physiological work, growth, and tissue repair.', 'Pre-Council', '🎓', true),
(8577, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'During prolonged starvation (beyond several days), the body increasingly relies on which fuel source to spare protein and preserve lean body mass?', '["Ketone bodies derived from fatty acid oxidation", "Dietary fibre", "Increased glycogenolysis", "Increased dietary protein intake"]'::jsonb, 0, 'In prolonged starvation, the liver produces ketone bodies from fatty acid breakdown; the brain adapts to use ketones as a major fuel source, reducing the need for muscle protein breakdown via gluconeogenesis.', 'Pre-Council', '🎓', true),
(8578, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'An ''adequate diet'' is best described as one that:', '["Contains only carbohydrates and fats in equal proportion", "Provides sufficient energy and all essential nutrients in amounts needed to maintain health, growth, and normal physiological function", "Is composed exclusively of fruits and vegetables", "Excludes all fats to prevent cardiovascular disease"]'::jsonb, 1, 'An adequate (balanced) diet supplies the correct proportions and amounts of energy, macronutrients, and micronutrients required to maintain health and normal body functioning across the lifespan.', 'Pre-Council', '🎓', true),
(8579, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Vitamins are broadly classified into two categories based on solubility. Which vitamins are fat-soluble?', '["Vitamins B and C", "Vitamins A, D, E, and K", "Vitamin C only", "Folate and thiamine"]'::jsonb, 1, 'Vitamins A, D, E, and K are fat-soluble, requiring dietary fat and bile for absorption, and can be stored in the liver and adipose tissue, unlike the water-soluble B-complex vitamins and vitamin C.', 'Pre-Council', '🎓', true),
(8580, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A deficiency of which vitamin classically causes night blindness and xerophthalmia?', '["Vitamin A", "Vitamin B1 (thiamine)", "Vitamin C", "Vitamin K"]'::jsonb, 0, 'Vitamin A is essential for rhodopsin synthesis in retinal rod cells and for maintaining epithelial integrity of the cornea and conjunctiva; deficiency causes night blindness and can progress to xerophthalmia.', 'Pre-Council', '🎓', true),
(8581, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Vitamin D deficiency in adults primarily results in which condition due to impaired calcium and phosphate absorption?', '["Scurvy", "Osteomalacia", "Pellagra", "Beriberi"]'::jsonb, 1, 'Vitamin D promotes intestinal absorption of calcium and phosphate; deficiency in adults leads to defective bone mineralisation known as osteomalacia (rickets in children).', 'Pre-Council', '🎓', true),
(8582, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which vitamin functions mainly as an antioxidant that protects cell membranes from lipid peroxidation?', '["Vitamin E", "Vitamin B12", "Vitamin K", "Folic acid"]'::jsonb, 0, 'Vitamin E is a lipid-soluble antioxidant that protects polyunsaturated fatty acids within cell membranes from oxidative damage caused by free radicals.', 'Pre-Council', '🎓', true),
(8583, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Vitamin K is essential for normal coagulation because it is required for the hepatic synthesis of which clotting factors?', '["Factors V and VIII only", "Factors II, VII, IX, and X", "Fibrinogen only", "Platelets"]'::jsonb, 1, 'Vitamin K acts as a cofactor for carboxylation of clotting factors II, VII, IX, and X (and proteins C and S) in the liver; deficiency or warfarin therapy impairs this process and prolongs the prothrombin time.', 'Pre-Council', '🎓', true),
(8584, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Thiamine (vitamin B1) deficiency is of particular concern in malnourished or alcoholic patients receiving intravenous glucose because it can precipitate:', '["Scurvy", "Wernicke''s encephalopathy", "Pellagra", "Rickets"]'::jsonb, 1, 'Thiamine is a cofactor for carbohydrate metabolism; administering glucose to a thiamine-deficient patient rapidly depletes remaining thiamine stores and can precipitate Wernicke''s encephalopathy, so thiamine should be given before or with glucose in at-risk patients.', 'Pre-Council', '🎓', true),
(8585, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Vitamin C (ascorbic acid) deficiency classically presents with which clinical syndrome characterised by gum bleeding and poor wound healing?', '["Scurvy", "Beriberi", "Pellagra", "Kwashiorkor"]'::jsonb, 0, 'Vitamin C is essential for collagen synthesis; deficiency causes scurvy, presenting with bleeding gums, perifollicular haemorrhages, poor wound healing, and joint pain.', 'Pre-Council', '🎓', true),
(8586, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Niacin (vitamin B3) deficiency classically causes a syndrome remembered as the ''3 D''s''. What are they?', '["Dyspnoea, dysphagia, diarrhoea", "Dermatitis, diarrhoea, dementia", "Dizziness, dysuria, dehydration", "Dysarthria, dysphagia, diplopia"]'::jsonb, 1, 'Pellagra, caused by niacin deficiency, classically presents with dermatitis, diarrhoea, and dementia, and can progress to death if untreated.', 'Pre-Council', '🎓', true),
(8587, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which trace element is a cofactor essential for wound healing, immune function, and taste perception, and is often supplemented in patients with large wounds or burns?', '["Zinc", "Chromium", "Selenium", "Molybdenum"]'::jsonb, 0, 'Zinc is a cofactor for many enzymes involved in protein synthesis and cell proliferation; deficiency impairs wound healing, immune response, and taste (hypogeusia), so needs increase with burns and large wounds.', 'Pre-Council', '🎓', true),
(8588, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Iron is a trace element primarily required for which physiological function?', '["Synthesis of haemoglobin for oxygen transport", "Bone mineralisation", "Antioxidant defence within the thyroid", "Blood clotting factor synthesis"]'::jsonb, 0, 'Iron is an essential component of haemoglobin (and myoglobin), enabling oxygen binding and transport; deficiency results in iron-deficiency anaemia.', 'Pre-Council', '🎓', true),
(8589, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which trace element is a critical component of the thyroid hormones thyroxine (T4) and triiodothyronine (T3)?', '["Iodine", "Copper", "Manganese", "Fluoride"]'::jsonb, 0, 'Iodine is incorporated into thyroglobulin to form thyroid hormones; deficiency leads to goitre and hypothyroidism, and in pregnancy can cause cretinism in the infant.', 'Pre-Council', '🎓', true),
(8590, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Selenium functions in the body chiefly as a component of which type of enzyme, giving it an antioxidant role?', '["Glutathione peroxidase", "Carbonic anhydrase", "Alkaline phosphatase", "Superoxide dismutase only"]'::jsonb, 0, 'Selenium is incorporated into glutathione peroxidase, an enzyme that protects cells from oxidative damage by reducing peroxides; deficiency has been linked to cardiomyopathy (Keshan disease).', 'Pre-Council', '🎓', true),
(8591, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A balanced adequate diet for a healthy adult should generally derive the majority of total daily calories from which macronutrient?', '["Protein", "Carbohydrate", "Fat", "Alcohol"]'::jsonb, 1, 'General dietary guidelines recommend that carbohydrates provide the largest proportion of total daily energy intake (commonly around 45-65%), with fat and protein making up the remainder.', 'Pre-Council', '🎓', true),
(8592, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'What is the primary aim of nutritional assessment in a critically ill patient?', '["To determine the patient''s food preferences for menu planning", "To identify the presence and severity of malnutrition and establish a baseline to guide individualised nutrition support", "To calculate the hospital''s food budget", "To determine which vitamins the patient dislikes"]'::jsonb, 1, 'The primary aim of nutritional assessment is to detect malnutrition or risk of malnutrition, quantify its severity, and provide a baseline against which to plan and monitor nutrition support interventions.', 'Pre-Council', '🎓', true),
(8593, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A comprehensive nutritional assessment typically integrates which four broad components?', '["Vital signs, medication list, allergy history, and code status", "Anthropometric measurements, biochemical data, clinical/physical examination, and dietary history (the ''ABCD'' approach)", "Blood pressure, pulse, respiration, and temperature", "Only body weight and height"]'::jsonb, 1, 'The classic ''ABCD'' framework of nutritional assessment includes Anthropometric measurements, Biochemical/laboratory data, Clinical examination, and Dietary history, providing a comprehensive picture of nutritional status.', 'Pre-Council', '🎓', true),
(8594, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following is an example of an anthropometric measurement used in nutritional assessment?', '["Serum albumin level", "Mid-upper arm circumference", "White blood cell count", "C-reactive protein level"]'::jsonb, 1, 'Anthropometric measurements assess body size and composition and include height, weight, BMI, mid-upper arm circumference, and triceps skinfold thickness.', 'Pre-Council', '🎓', true),
(8595, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In nutritional assessment, biochemical data such as serum albumin, prealbumin, and transferrin are used mainly to:', '["Directly measure caloric intake", "Provide indirect, though imperfect, indicators of visceral protein status and nutritional risk", "Replace the need for a dietary history", "Diagnose vitamin toxicity exclusively"]'::jsonb, 1, 'Serum visceral proteins are synthesised by the liver and their levels can reflect protein status, though they are also affected by inflammation, hydration, and hepatic/renal function, so they must be interpreted alongside other assessment data.', 'Pre-Council', '🎓', true),
(8596, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A thorough dietary history as part of nutritional assessment should include which of the following?', '["Only the patient''s current body weight", "Usual food intake pattern, recent changes in appetite or intake, food intolerances, and factors affecting oral intake", "The patient''s blood type", "The hospital''s discharge date"]'::jsonb, 1, 'Dietary history captures usual eating patterns, recent changes in intake or appetite, chewing/swallowing difficulty, GI symptoms, and psychosocial or economic barriers to adequate nutrition.', 'Pre-Council', '🎓', true),
(8597, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Clinical (physical) examination in nutritional assessment includes looking for which of the following signs of malnutrition?', '["Muscle wasting, oedema, hair changes, and skin breakdown", "Blood glucose level only", "Serum sodium concentration", "Chest X-ray findings"]'::jsonb, 0, 'Physical examination for nutritional status includes inspection for temporal and limb muscle wasting, subcutaneous fat loss, oedema (which can mask weight loss), and skin, hair, and nail changes suggestive of specific deficiencies.', 'Pre-Council', '🎓', true),
(8598, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The Subjective Global Assessment (SGA) tool classifies nutritional status into which categories?', '["Underweight, normal weight, overweight, obese", "Well-nourished (A), moderately/suspected malnourished (B), and severely malnourished (C)", "Mild, moderate, severe, and critical dehydration", "Grade 1 through Grade 5 sarcopenia"]'::jsonb, 1, 'SGA classifies patients into three categories: SGA-A (well nourished), SGA-B (mild to moderately malnourished or suspected malnutrition), and SGA-C (severely malnourished), based on history and physical findings rather than laboratory values.', 'Pre-Council', '🎓', true),
(8599, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The Subjective Global Assessment (SGA) is based primarily on which two components?', '["Laboratory biochemical markers and imaging studies", "A structured patient history (weight change, dietary intake, GI symptoms, functional capacity, disease effect on nutrition) and a focused physical examination", "Genetic testing and metabolic cart data", "Body mass index alone"]'::jsonb, 1, 'SGA is a clinical, bedside tool relying on a history covering weight change, dietary intake change, GI symptoms, functional capacity, and disease state, combined with a physical exam for muscle wasting, fat loss, and oedema, rather than laboratory tests.', 'Pre-Council', '🎓', true),
(8600, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following is a recognised advantage of the Subjective Global Assessment (SGA) over purely laboratory-based nutritional assessment?', '["It requires no clinician training", "It does not require any patient history", "It reliably predicts nutrition-related clinical outcomes and is not confounded by fluid shifts or acute-phase inflammatory changes the way serum albumin can be", "It replaces the need for anthropometric data entirely"]'::jsonb, 2, 'Because SGA relies on history and physical findings rather than serum proteins, it is not confounded by inflammation or fluid overload the way albumin is, and it has been validated as a good predictor of nutrition-related complications.', 'Pre-Council', '🎓', true),
(8601, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Body Mass Index (BMI) is calculated using which formula?', '["Weight (kg) divided by height (m)", "Weight (kg) divided by height squared (m2)", "Height (m) divided by weight (kg)", "Weight (lb) multiplied by height (in)"]'::jsonb, 1, 'BMI = weight in kilograms divided by the square of height in metres (kg/m2); it is a widely used, though imperfect, screening measure of body weight status.', 'Pre-Council', '🎓', true),
(8602, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'According to WHO classification, a BMI of less than 18.5 kg/m2 in an adult is categorised as:', '["Normal weight", "Overweight", "Underweight", "Obese class I"]'::jsonb, 2, 'A BMI below 18.5 kg/m2 is classified as underweight and may indicate undernutrition requiring further nutritional assessment.', 'Pre-Council', '🎓', true),
(8603, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Mid-upper arm circumference (MUAC) is a useful anthropometric measurement particularly when:', '["A patient has significant ascites or oedema making weight and BMI unreliable", "The patient is on mechanical ventilation only", "Serum albumin is normal", "The patient is critically dehydrated"]'::jsonb, 0, 'MUAC provides an estimate of muscle and fat stores that is less affected by fluid status than body weight, making it particularly useful in patients with oedema, ascites, or fluid overload where weight is unreliable.', 'Pre-Council', '🎓', true),
(8604, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Unintentional weight loss of what approximate percentage of usual body weight over 6 months is generally considered clinically significant and indicative of malnutrition risk?', '["1-2%", "More than 10%", "20-25%", "30-40%"]'::jsonb, 1, 'Unintentional weight loss exceeding approximately 10% of usual body weight over 6 months (or more than 5% in 1 month) is generally considered clinically significant and a marker of malnutrition risk.', 'Pre-Council', '🎓', true),
(8605, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which serum protein has the shortest half-life and is therefore considered a more sensitive marker of short-term (acute) changes in nutritional/protein status among commonly used visceral proteins?', '["Albumin (half-life ~18-21 days)", "Transferrin (half-life ~8-10 days)", "Prealbumin/transthyretin (half-life ~2-3 days)", "Immunoglobulin G (half-life ~21 days)"]'::jsonb, 2, 'Prealbumin (transthyretin) has a short half-life of about 2-3 days, making it more responsive to acute changes in nutritional status and a more useful marker for monitoring short-term response to nutrition support than albumin.', 'Pre-Council', '🎓', true),
(8606, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A major limitation of using serum albumin as a marker of nutritional status in critically ill patients is that it:', '["Is unaffected by inflammation or fluid balance", "Is a negative acute-phase reactant that falls with inflammation, sepsis, and fluid overload independent of actual nutrient intake", "Has a half-life of only a few hours", "Cannot be measured in hospital laboratories"]'::jsonb, 1, 'Albumin is a negative acute-phase reactant whose synthesis decreases and capillary leak increases during inflammation and critical illness, so low levels often reflect the severity of illness and fluid status rather than true nutritional depletion.', 'Pre-Council', '🎓', true),
(8607, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The Malnutrition Universal Screening Tool (MUST) and Nutrition Risk Screening 2002 (NRS-2002) are examples of what type of instrument?', '["Diagnostic imaging tools", "Nutrition screening tools used to identify patients at risk of malnutrition who require full nutritional assessment", "Tools used exclusively to calculate caloric requirements", "Surgical risk calculators"]'::jsonb, 1, 'MUST and NRS-2002 are validated, quick screening tools that flag patients at nutritional risk based on factors like BMI, recent weight loss, and reduced intake; a positive screen prompts a more detailed nutritional assessment such as SGA.', 'Pre-Council', '🎓', true),
(8608, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Why is early nutritional support (within 24-48 hours of admission) recommended for the critically ill trauma patient?', '["It has no effect on outcomes but is done for patient comfort", "Early feeding helps preserve gut mucosal integrity, reduces bacterial translocation and infectious complications, and attenuates the catabolic stress response", "It eliminates the need for any further nutritional monitoring", "It guarantees the avoidance of mechanical ventilation"]'::jsonb, 1, 'Evidence supports early nutrition (particularly enteral) in trauma patients because it maintains gut mucosal integrity, reduces bacterial translocation and septic complications, and helps blunt the hypermetabolic/catabolic response to injury.', 'Pre-Council', '🎓', true),
(8609, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In major trauma, delaying nutritional support significantly increases the risk of which gut-related complication?', '["Gut mucosal atrophy and increased intestinal permeability, predisposing to bacterial translocation", "Improved gut motility", "Decreased risk of stress ulceration", "Enhanced absorption of nutrients later"]'::jsonb, 0, 'Without enteral stimulation, the gut mucosa atrophies and becomes more permeable, which can allow translocation of bacteria and endotoxin across the gut wall, contributing to sepsis and multi-organ dysfunction.', 'Pre-Council', '🎓', true),
(8610, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Current critical care nutrition guidelines generally recommend that, in a haemodynamically stable trauma patient with a functioning gut, enteral nutrition should be initiated:', '["Only after 2 weeks of bowel rest", "Within 24-48 hours of ICU admission", "Only once the patient is extubated", "Only after full return of bowel sounds and flatus"]'::jsonb, 1, 'Guidelines from bodies such as ASPEN/SCCM recommend initiating enteral nutrition within 24-48 hours in haemodynamically stable critically ill patients, since a functioning gut does not require complete return of bowel sounds before feeding begins.', 'Pre-Council', '🎓', true),
(8611, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'The ''ebb and flow'' model of the metabolic response to trauma describes which sequence?', '["An initial hypometabolic ''ebb'' phase of hypoperfusion followed by a hypermetabolic ''flow'' (catabolic) phase", "A single sustained hypermetabolic phase with no early depression", "An initial anabolic phase followed by a hypometabolic phase", "A random, unpredictable pattern with no identifiable phases"]'::jsonb, 0, 'The classic Cuthbertson model describes an early ''ebb'' phase (hours after injury) marked by hypometabolism and hypoperfusion, followed by a ''flow'' phase of hypermetabolism, increased catabolism, and increased energy expenditure that nutrition support aims to counter.', 'Pre-Council', '🎓', true),
(8612, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following is a key reason early nutritional support is prioritised specifically in burn and multi-trauma patients?', '["These patients have significantly reduced energy and protein requirements compared to healthy adults", "These patients experience an exaggerated and prolonged hypermetabolic, hypercatabolic response with substantial nitrogen losses that early feeding helps offset", "These patients cannot tolerate any form of nutrition", "Early feeding prevents the need for wound care"]'::jsonb, 1, 'Burns and major trauma provoke one of the most severe hypermetabolic responses seen in medicine, with massive nitrogen and lean body mass losses; early and adequate nutrition support helps limit cumulative protein deficit and supports wound healing.', 'Pre-Council', '🎓', true),
(8613, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In the trauma patient, which route of nutrition support is generally preferred over parenteral nutrition when the gastrointestinal tract is functional, primarily because of superior outcomes related to gut integrity?', '["Intravenous dextrose alone", "Enteral nutrition", "Parenteral nutrition", "Oral rehydration solution alone"]'::jsonb, 1, 'When the GI tract is functional, enteral nutrition is preferred because it maintains gut mucosal integrity, supports gut-associated immune function, and is associated with fewer infectious complications compared with parenteral nutrition.', 'Pre-Council', '🎓', true),
(8614, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Estimated energy requirements for a critically ill adult trauma patient are commonly calculated in the range of approximately how many kcal/kg/day during the acute phase, when indirect calorimetry is unavailable?', '["5-10 kcal/kg/day", "25-30 kcal/kg/day", "60-70 kcal/kg/day", "90-100 kcal/kg/day"]'::jsonb, 1, 'In the absence of indirect calorimetry, weight-based predictive equations commonly estimate energy needs for critically ill patients at approximately 25-30 kcal/kg/day, though this should be individualised and adjusted based on clinical response.', 'Pre-Council', '🎓', true),
(8615, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Protein requirements for a critically ill or traumatised patient are typically higher than for a healthy adult, generally falling in which range?', '["0.4-0.6 g/kg/day", "0.8 g/kg/day (same as healthy adults)", "1.2-2.0 g/kg/day (higher in burns or with significant losses)", "5-6 g/kg/day"]'::jsonb, 2, 'Critical illness and trauma markedly increase protein catabolism; guidelines generally recommend 1.2-2.0 g/kg/day of protein (and even higher in major burns) to help offset nitrogen losses and support wound healing and immune function.', 'Pre-Council', '🎓', true),
(8616, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In the critically traumatised patient, the recommended proportion of non-protein calories from carbohydrate versus fat is adjusted (compared to a healthy diet) mainly to:', '["Maximise carbohydrate intake regardless of glycaemic control", "Avoid excessive carbohydrate load, which can worsen hyperglycaemia and increase CO2 production, while providing fat as a concentrated, less glycaemia-provoking energy source", "Eliminate fat entirely from the nutrition regimen", "Provide all non-protein calories as pure ethanol"]'::jsonb, 1, 'Excess carbohydrate calories in critically ill patients can worsen stress hyperglycaemia and increase CO2 production (a concern in ventilator weaning), so a portion of non-protein calories is often provided as fat to balance the regimen.', 'Pre-Council', '🎓', true),
(8617, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Overfeeding carbohydrate calories in a mechanically ventilated critically ill patient can lead to which respiratory complication?', '["Decreased CO2 production, easing ventilator weaning", "Increased CO2 production (from carbohydrate oxidation), potentially increasing the work of breathing and complicating ventilator weaning", "Improved oxygen-carrying capacity", "Reduced minute ventilation requirement"]'::jsonb, 1, 'Carbohydrate metabolism produces more CO2 per unit of oxygen consumed (higher respiratory quotient) than fat metabolism; excessive carbohydrate calories can increase CO2 production and increase ventilatory demand, complicating weaning.', 'Pre-Council', '🎓', true),
(8618, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which maximum glucose infusion rate is generally recommended to avoid the metabolic complications of overfeeding carbohydrate in critically ill patients?', '["Approximately 4-5 mg/kg/min", "Approximately 20-25 mg/kg/min", "Approximately 40 mg/kg/min", "There is no upper limit"]'::jsonb, 0, 'Glucose infusion rates are generally recommended not to exceed about 4-5 mg/kg/min in critically ill adults, as higher rates can exceed the body''s oxidative capacity and contribute to hyperglycaemia, hepatic steatosis, and increased CO2 production.', 'Pre-Council', '🎓', true),
(8619, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Intravenous lipid emulsions in nutrition support serve which important physiological purpose beyond providing calories?', '["They have no metabolic role beyond calories", "They supply essential fatty acids (linoleic and alpha-linolenic acid) that the body cannot synthesise", "They directly increase serum albumin", "They replace the need for protein intake"]'::jsonb, 1, 'Lipid emulsions provide a concentrated calorie source and, importantly, supply essential fatty acids that cannot be endogenously synthesised, preventing essential fatty acid deficiency during prolonged nutrition support.', 'Pre-Council', '🎓', true),
(8620, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In the traumatised critically ill patient, nitrogen balance studies are used to:', '["Assess fluid balance only", "Estimate whether protein intake is adequate to offset nitrogen losses (urinary urea nitrogen plus obligatory losses) and guide protein prescription", "Measure serum electrolytes", "Determine caloric needs exclusively"]'::jsonb, 1, 'Nitrogen balance compares nitrogen intake (from protein) with nitrogen losses (mainly urinary urea nitrogen plus estimated non-urinary losses); a negative balance indicates ongoing catabolism and may prompt an increase in protein provision.', 'Pre-Council', '🎓', true),
(8621, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Indirect calorimetry is considered the gold standard for estimating energy expenditure in critically ill patients because it:', '["Measures oxygen consumption and carbon dioxide production to directly calculate resting energy expenditure", "Estimates calories based solely on body weight", "Requires no specialised equipment", "Is unaffected by changes in the patient''s clinical status"]'::jsonb, 0, 'Indirect calorimetry measures a patient''s actual VO2 and VCO2 to calculate resting energy expenditure via the Weir equation, providing a more individualised and accurate estimate than predictive weight-based formulas, especially in complex critically ill patients.', 'Pre-Council', '🎓', true),
(8622, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Total Parenteral Nutrition (TPN) is defined as:', '["Feeding delivered via a nasogastric tube directly into the stomach", "The intravenous delivery of all required nutrients (carbohydrate, protein, fat, vitamins, minerals, and fluid) bypassing the gastrointestinal tract entirely", "Oral supplementation with high-calorie drinks", "A combination of oral diet and tube feeding"]'::jsonb, 1, 'TPN provides complete nutritional support intravenously, bypassing the GI tract entirely, and is typically indicated when the gut is non-functional or enteral access/tolerance cannot be achieved.', 'Pre-Council', '🎓', true),
(8623, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following is the primary indication for choosing TPN over enteral nutrition in a critically ill patient?', '["The patient prefers not to have a feeding tube", "A non-functioning or inaccessible gastrointestinal tract (e.g., prolonged ileus, bowel obstruction, severe short bowel syndrome, high-output fistula)", "The patient is haemodynamically stable with a normal functioning gut", "The patient has mild nausea only"]'::jsonb, 1, 'TPN is reserved for patients who cannot use their GI tract adequately, such as those with bowel obstruction, prolonged ileus, severe malabsorption, or high-output enterocutaneous fistulae, since enteral nutrition is preferred whenever the gut is functional.', 'Pre-Council', '🎓', true),
(8624, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Because TPN solutions are highly hyperosmolar, long-term administration typically requires infusion via which type of venous access?', '["A peripheral IV cannula in the hand", "A central venous catheter placed in a large, high-flow vein", "Subcutaneous infusion", "Intramuscular injection"]'::jsonb, 1, 'Standard TPN solutions have high osmolarity that would cause thrombophlebitis in peripheral veins, so they are infused through a central venous catheter where high blood flow rapidly dilutes the solution.', 'Pre-Council', '🎓', true),
(8625, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Catheter-related bloodstream infection (CRBSI) is one of the most significant risks associated with TPN primarily because:', '["TPN solutions are inherently sterile and infection risk is zero", "TPN requires prolonged central venous catheter access and the dextrose-rich solution can support microbial growth if contamination occurs", "TPN is always administered peripherally", "Infection risk is unrelated to catheter dwell time"]'::jsonb, 1, 'The combination of an indwelling central catheter and a glucose- and nutrient-rich infusate creates significant risk for catheter colonisation and bloodstream infection, making strict aseptic technique essential during TPN administration.', 'Pre-Council', '🎓', true),
(8626, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Hepatobiliary complications, such as hepatic steatosis and cholestasis, are recognised risks of long-term TPN and are most commonly associated with:', '["Underfeeding of protein only", "Overfeeding, particularly excess glucose calories, and lack of enteral stimulation of bile flow", "Excessive fibre intake", "Use of isotonic saline instead of TPN"]'::jsonb, 1, 'TPN-associated liver disease is linked to overfeeding (especially excess dextrose), essential fatty acid or choline deficiency, and absence of enteral stimulation, which reduces bile flow and predisposes to cholestasis and gallbladder sludge/stones.', 'Pre-Council', '🎓', true),
(8627, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Refeeding syndrome is a serious risk when initiating TPN (or aggressive enteral feeding) in severely malnourished patients and is characterised primarily by which electrolyte disturbance?', '["Severe hyperphosphataemia", "Severe hypophosphataemia, along with hypokalaemia and hypomagnesaemia, due to a sudden intracellular shift of electrolytes", "Hypernatraemia only", "Hypercalcaemia"]'::jsonb, 1, 'Refeeding triggers a surge in insulin secretion that drives phosphate, potassium, and magnesium into cells, causing severe hypophosphataemia (and hypokalaemia, hypomagnesaemia), which can precipitate cardiac arrhythmias, respiratory failure, and death if not anticipated and managed.', 'Pre-Council', '🎓', true),
(8628, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'To reduce the risk of refeeding syndrome in a severely malnourished ICU patient starting nutrition support, the recommended approach is to:', '["Begin feeding at full calculated caloric goal immediately to correct malnutrition quickly", "Start nutrition support at a reduced caloric rate, correct and closely monitor electrolytes (especially phosphate, potassium, magnesium), and advance gradually while supplementing thiamine", "Withhold all electrolytes until feeding is complete", "Give a single large bolus of intravenous glucose before starting feeds"]'::jsonb, 1, 'Best practice to prevent refeeding syndrome is to start nutrition at a low caloric rate in at-risk patients, proactively supplement thiamine and correct electrolyte deficits, monitor phosphate/potassium/magnesium closely, and advance calories gradually over several days.', 'Pre-Council', '🎓', true),
(8629, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A well-recognised benefit of TPN is that it:', '["Preserves gut mucosal integrity better than enteral nutrition", "Can provide complete, precisely titratable nutritional support when the gastrointestinal tract cannot be used at all", "Has a lower infection risk than enteral nutrition", "Eliminates the risk of hyperglycaemia"]'::jsonb, 1, 'The key benefit of TPN is that it guarantees delivery of a precisely calculated, complete nutrient prescription when the gut cannot be used, which can be lifesaving in conditions such as bowel obstruction or severe short bowel syndrome.', 'Pre-Council', '🎓', true),
(8630, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'TPN administration requires close monitoring of blood glucose primarily because:', '["TPN solutions never contain dextrose", "The high dextrose content of TPN can cause significant hyperglycaemia, and abrupt cessation can cause rebound hypoglycaemia", "TPN has no effect on blood glucose", "Hyperglycaemia from TPN cannot be treated with insulin"]'::jsonb, 1, 'TPN solutions typically contain substantial dextrose, which can cause hyperglycaemia requiring insulin therapy; because the infusion also suppresses endogenous insulin counter-regulation, abruptly stopping TPN can cause rebound hypoglycaemia, so tapering is recommended.', 'Pre-Council', '🎓', true),
(8631, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Compared with enteral nutrition, TPN is associated with a higher risk of which category of complications overall?', '["Mechanical, infectious, and metabolic complications related to central venous access and the intravenous route", "No additional complications compared to enteral feeding", "Aspiration pneumonia specifically", "Diarrhoea from feed intolerance"]'::jsonb, 0, 'TPN carries risks specific to central venous catheterisation (pneumothorax, catheter malposition), catheter-related bloodstream infection, and metabolic derangements (hyperglycaemia, electrolyte imbalance, hepatobiliary dysfunction) that are generally more frequent or severe than with enteral nutrition.', 'Pre-Council', '🎓', true),
(8632, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Essential fatty acid deficiency can occur with prolonged TPN if which component is omitted or inadequately provided?', '["Intravenous lipid (fat) emulsion", "Dextrose", "Amino acids", "Sterile water"]'::jsonb, 0, 'Because linoleic and alpha-linolenic acids cannot be synthesised endogenously, omitting or under-dosing intravenous lipid emulsion during prolonged TPN can lead to essential fatty acid deficiency, manifesting as dry scaly skin and impaired wound healing.', 'Pre-Council', '🎓', true),
(8633, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Compared with parenteral nutrition, a major benefit of enteral nutrition is that it:', '["Bypasses the gut entirely, reducing infection risk", "Maintains gut mucosal structure and function, supports gut-associated lymphoid tissue, and is associated with fewer infectious complications", "Cannot be used in patients with a functioning gut", "Always requires central venous access"]'::jsonb, 1, 'Enteral nutrition preserves the structural and functional integrity of the gut mucosa and stimulates gut-associated lymphoid tissue (GALT), which helps maintain the gut''s immune barrier function and is linked to reduced infectious morbidity compared with parenteral nutrition.', 'Pre-Council', '🎓', true),
(8634, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A nasogastric (NG) tube for enteral feeding is generally appropriate for which type of patient?', '["A patient with a short-term feeding need and normal gastric emptying with low aspiration risk", "A patient requiring lifelong home enteral nutrition", "A patient with severe gastroparesis and high aspiration risk", "A patient who has had a total gastrectomy"]'::jsonb, 0, 'Nasogastric tubes are suitable for short-term enteral feeding in patients with intact gastric emptying and low aspiration risk, as they allow feeding directly into the stomach, which tolerates bolus or intermittent feeding.', 'Pre-Council', '🎓', true),
(8635, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A post-pyloric (nasojejunal) feeding tube is generally preferred over a nasogastric tube in which clinical situation?', '["Routine feeding in a fully alert, low-risk patient", "Patients with a high risk of aspiration, severe gastroparesis, or significant gastric residual volumes", "Only when TPN is contraindicated", "Whenever bolus feeding is desired"]'::jsonb, 1, 'Post-pyloric feeding delivers formula beyond the pylorus, bypassing delayed gastric emptying and theoretically reducing (though not eliminating) the risk of reflux and aspiration, making it preferable in patients with significant gastroparesis or high aspiration risk.', 'Pre-Council', '🎓', true),
(8636, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'For patients who require enteral nutrition support for longer than approximately 4-6 weeks, which access route is generally recommended over a nasoenteric tube?', '["A percutaneous route such as gastrostomy (PEG) or jejunostomy tube", "Continued nasogastric tube indefinitely", "Oral sipping only", "Intravenous TPN as first choice"]'::jsonb, 0, 'For anticipated long-term enteral feeding, a percutaneous endoscopic gastrostomy (PEG) or jejunostomy tube is preferred over prolonged nasoenteric tubes because it is more comfortable, reduces nasal/oesophageal trauma, and is more secure for long-term use.', 'Pre-Council', '🎓', true),
(8637, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which of the following is a recognised mechanical complication of enteral feeding tubes?', '["Catheter-related bloodstream infection", "Tube displacement/dislodgement, clogging, or malposition into the trachea or lung", "Hepatic steatosis", "Refeeding syndrome"]'::jsonb, 1, 'Mechanical complications specific to enteral tubes include dislodgement, occlusion/clogging of the tube, and the serious risk of inadvertent tracheobronchial or pulmonary placement, which must be excluded by tube position verification before use.', 'Pre-Council', '🎓', true),
(8638, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Aspiration pneumonia is a major risk of enteral nutrition. Which nursing intervention most directly reduces this risk during continuous gastric tube feeding?', '["Keeping the head of the bed flat at 0 degrees during feeding", "Elevating the head of the bed to 30-45 degrees during and for a period after feeding", "Administering feeds as a rapid IV push", "Removing the tube immediately after each feed"]'::jsonb, 1, 'Elevating the head of the bed to 30-45 degrees during enteral feeding and for a period afterward reduces the risk of gastro-oesophageal reflux and subsequent aspiration of feed into the airway.', 'Pre-Council', '🎓', true),
(8639, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Diarrhoea occurring during enteral nutrition is most commonly attributed to which of the following?', '["The feeding formula itself is always sterile and never a cause", "Factors such as concurrent antibiotic therapy, sorbitol-containing medications, hyperosmolar formulas, or rapid infusion rate rather than the enteral feed alone", "Excessive fibre in all formulas causing constipation instead", "Inadequate central line placement"]'::jsonb, 1, 'Diarrhoea during enteral feeding is frequently multifactorial, commonly related to antibiotic-associated dysbiosis (including C. difficile), osmotically active liquid medications (e.g., sorbitol-based elixirs), hyperosmolar formulas, or feeding rate, rather than being an inevitable consequence of the feed itself.', 'Pre-Council', '🎓', true),
(8640, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Elemental (monomeric) enteral formulas, composed of free amino acids, simple sugars, and minimal fat, are typically indicated for patients with:', '["Normal digestive and absorptive function", "Severe malabsorption, short bowel syndrome, or significant pancreatic insufficiency where digestion is impaired", "Simple fluid restriction needs only", "No gastrointestinal disease at all"]'::jsonb, 1, 'Elemental formulas contain pre-digested nutrients requiring minimal digestive capacity, making them useful for patients with severe malabsorption, short bowel syndrome, or significant pancreatic insufficiency who cannot adequately digest polymeric formulas.', 'Pre-Council', '🎓', true),
(8641, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Standard polymeric enteral formulas differ from elemental formulas in that polymeric formulas:', '["Contain intact proteins, complex carbohydrates, and fats requiring normal digestive and absorptive capacity", "Contain only free amino acids", "Require no pancreatic enzyme activity", "Are used exclusively in infants"]'::jsonb, 0, 'Polymeric formulas contain whole/intact macronutrients (intact protein, complex carbohydrate, and fat) and are appropriate for patients with a normally functioning GI tract that can digest and absorb these nutrients.', 'Pre-Council', '🎓', true),
(8642, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Disease-specific enteral formulas (e.g., renal, pulmonary, or diabetic formulas) are designed to:', '["Provide an identical nutrient profile in every case regardless of organ dysfunction", "Modify nutrient composition (e.g., lower electrolyte/fluid load in renal formulas, or higher fat/lower carbohydrate ratio in pulmonary formulas) to suit specific organ dysfunction or metabolic needs", "Replace the need for any nutritional assessment", "Only be used for oral supplementation, never tube feeding"]'::jsonb, 1, 'Disease-specific formulas are tailored to particular pathophysiology, such as concentrated, lower-electrolyte formulas for renal failure or higher-fat/lower-carbohydrate formulas for patients with respiratory failure to reduce CO2 production.', 'Pre-Council', '🎓', true),
(8643, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Before initiating and periodically during enteral tube feeding, verification of correct nasogastric tube placement is essential primarily to prevent:', '["Hyperglycaemia", "Inadvertent instillation of feed into the respiratory tract if the tube has migrated or was malpositioned", "Refeeding syndrome", "Catheter-related bloodstream infection"]'::jsonb, 1, 'Confirming tube placement (e.g., by radiographic confirmation initially and pH testing of aspirate or other institutional protocols) before feeding is critical to avoid the potentially fatal complication of infusing feed into the lungs via a malpositioned tube.', 'Pre-Council', '🎓', true),
(8644, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'When performing a nursing assessment of nutritional status on ICU admission, which combination of findings would most strongly suggest pre-existing malnutrition?', '["Stable weight, normal appetite, and well-hydrated skin turgor", "Recent unintentional weight loss, reduced oral intake over weeks, temporal wasting, and low mid-upper arm circumference", "Elevated body mass index with no recent weight change", "Normal serum electrolytes with no other findings"]'::jsonb, 1, 'A cluster of history and physical findings — recent unintentional weight loss, reduced intake, and visible muscle wasting — together indicate a high likelihood of pre-existing malnutrition, prompting further formal assessment such as SGA.', 'Pre-Council', '🎓', true),
(8645, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'As part of ongoing nursing assessment of nutritional status in a ventilated ICU patient, which parameter is routinely monitored to assess enteral feeding tolerance?', '["Serum bilirubin only", "Gastric residual volume, abdominal distension, and bowel sounds/bowel movement pattern", "Peak inspiratory pressure alone", "Central venous pressure exclusively"]'::jsonb, 1, 'Nurses monitor gastric residual volume trends, abdominal distension, tenderness, and bowel function as bedside indicators of enteral feeding tolerance, adjusting the feeding plan as needed and reporting concerning findings to the team.', 'Pre-Council', '🎓', true),
(8646, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Daily nursing assessment of a patient receiving nutritional support should include monitoring for signs of which metabolic complication associated with overfeeding or aggressive refeeding?', '["Hypertension only", "Fluid overload, electrolyte derangement, and hyperglycaemia", "Increased urine specific gravity only", "Decreased respiratory rate only"]'::jsonb, 1, 'Nurses must monitor daily weights, fluid balance, serum electrolytes (especially phosphate, potassium, magnesium), and blood glucose to detect early signs of fluid overload, refeeding-related electrolyte shifts, or hyperglycaemia.', 'Pre-Council', '🎓', true),
(8647, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Serial anthropometric measurements (e.g., weekly weight, arm circumference) are part of ongoing nursing nutritional assessment mainly because they:', '["Are used solely to select clothing sizes", "Allow trending of nutritional status over time to evaluate whether nutrition support is achieving its intended goals", "Replace the need for any biochemical monitoring", "Are only relevant at hospital discharge"]'::jsonb, 1, 'Trending anthropometric data over time (rather than a single measurement) allows the healthcare team to assess whether nutrition interventions are effectively maintaining or improving nutritional status.', 'Pre-Council', '🎓', true),
(8648, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A critical care nurse assessing a patient''s swallowing function before initiating oral intake after extubation is primarily screening for risk of:', '["Hyperglycaemia", "Aspiration due to dysphagia", "Refeeding syndrome", "Catheter infection"]'::jsonb, 1, 'Post-extubation dysphagia is common and increases aspiration risk; a bedside swallow screen by the nurse helps determine whether it is safe to begin oral intake or whether further evaluation (e.g., by speech-language therapy) is needed first.', 'Pre-Council', '🎓', true),
(8649, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which laboratory trend, if observed by the nurse over several days in a patient receiving nutrition support, would be most reassuring of adequate nutritional repletion?', '["Steadily falling prealbumin despite adequate caloric and protein delivery", "Rising prealbumin trending toward normal alongside clinical improvement", "Rising blood urea nitrogen with worsening renal function", "Falling haemoglobin due to active bleeding"]'::jsonb, 1, 'A rising prealbumin trend, especially when correlated with clinical improvement and resolution of the acute inflammatory state, suggests that nutrition support is having the intended positive effect, whereas a falling trend in the absence of inflammation may indicate inadequate intake.', 'Pre-Council', '🎓', true),
(8650, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Assessment of a patient''s abdomen (inspection, auscultation, percussion, palpation) is an important nursing component of nutritional assessment mainly because it helps determine:', '["The patient''s psychiatric status", "Gastrointestinal function and readiness/tolerance for enteral feeding", "Blood glucose control", "Level of consciousness"]'::jsonb, 1, 'Abdominal assessment findings such as distension, tenderness, absent bowel sounds, or firmness can indicate ileus, obstruction, or feed intolerance, informing decisions about whether and how to proceed with enteral nutrition.', 'Pre-Council', '🎓', true),
(8651, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'When assessing nutritional status, why is it important for the nurse to review the patient''s medication list?', '["Medications never affect nutritional status", "Certain medications can affect appetite, nutrient absorption, or gastrointestinal motility and may interact with feeds (e.g., phenytoin with enteral formula)", "Medication review is solely the pharmacist''s responsibility and irrelevant to nursing", "Only over-the-counter medications matter for nutrition"]'::jsonb, 1, 'Some medications alter appetite, GI motility, or nutrient absorption, and certain drugs (e.g., phenytoin) have known interactions with enteral formula that can reduce drug absorption, making medication review an important part of nutritional assessment.', 'Pre-Council', '🎓', true),
(8652, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which nursing intervention is most important for ensuring optimal nutritional support during continuous enteral feeding in an ICU patient?', '["Administering the entire day''s feed volume as a single rapid bolus regardless of tolerance", "Following an institutional feeding protocol that includes head-of-bed elevation, regular residual/tolerance checks, and minimising interruptions to feeding", "Discontinuing feeds automatically overnight without documented reason", "Allowing the enteral formula to hang for more than 24 hours without changing the administration set"]'::jsonb, 1, 'Adherence to an evidence-based feeding protocol — including positioning, monitoring for tolerance, and minimising unnecessary interruptions (e.g., for procedures or transport) — helps ensure patients actually receive their prescribed nutrition and improves overall caloric delivery.', 'Pre-Council', '🎓', true),
(8653, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A key nursing intervention to reduce cumulative caloric deficit in ICU patients is to:', '["Automatically hold feeds for any diagnostic test or procedure without a defined protocol", "Use a structured protocol that limits unnecessary feeding interruptions and promptly resumes feeds after procedures", "Discontinue enteral feeding as soon as any gastric residual is measured, regardless of volume", "Restrict feeding to daytime hours only"]'::jsonb, 1, 'Studies show ICU patients often receive far less than their prescribed calories due to frequent, sometimes unnecessary interruptions; structured feeding protocols that minimise such interruptions and promptly resume feeding help reduce cumulative energy deficit.', 'Pre-Council', '🎓', true),
(8654, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which nursing action best supports optimal nutritional intake in a critically ill patient transitioning from enteral tube feeding to oral diet?', '["Immediately removing the feeding tube on the first day oral intake is attempted", "Gradually tapering tube feeds while monitoring and documenting actual oral intake to confirm adequacy before discontinuing the tube", "Providing no assistance with feeding regardless of the patient''s functional status", "Assuming oral intake is adequate without any monitoring"]'::jsonb, 1, 'A safe transition involves gradually tapering enteral tube feeding while tracking actual oral caloric/protein intake, ensuring nutritional adequacy is maintained before removing the more reliable tube feeding route.', 'Pre-Council', '🎓', true),
(8655, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'For a patient receiving TPN, which nursing intervention is essential to reduce the risk of catheter-related bloodstream infection?', '["Using strict aseptic/sterile technique for catheter site care and TPN bag/tubing changes according to protocol", "Reusing the same infusion tubing for as long as possible without changing it", "Administering TPN through a peripheral IV to avoid a central line", "Avoiding hand hygiene when the patient appears clinically stable"]'::jsonb, 0, 'Because TPN requires central venous access and a nutrient-rich infusate that can support microbial growth, meticulous aseptic technique for site care, dressing changes, and tubing/bag changes per protocol is essential to minimise catheter-related bloodstream infection risk.', 'Pre-Council', '🎓', true),
(8656, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'When a critically ill patient develops a high gastric residual volume during enteral feeding, current best-practice nursing intervention (per most ICU protocols) is to:', '["Immediately and permanently discontinue all enteral feeding", "Reassess using a defined threshold, consider a prokinetic agent, and generally continue feeding at a reduced or adjusted rate rather than automatically stopping for residuals alone", "Increase the feeding rate to compensate", "Switch immediately to TPN without further evaluation"]'::jsonb, 1, 'Current guidelines discourage automatically holding feeds for gastric residual volumes below a defined threshold (commonly around 250-500 mL) alone; instead, nurses should assess for other signs of intolerance, consider prokinetics, and generally continue feeding, reserving cessation for clear intolerance or high-risk residuals.', 'Pre-Council', '🎓', true),
(8657, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Ensuring optimal nutritional support for a critically ill patient with impaired swallowing but an intact, functional gut primarily requires the nurse to:', '["Start TPN immediately without considering enteral options", "Advocate for and assist with establishment of enteral tube feeding access rather than defaulting to parenteral nutrition", "Withhold all nutrition until swallowing recovers completely", "Provide only intravenous fluids indefinitely"]'::jsonb, 1, 'When the gut is functional but oral intake is unsafe due to dysphagia, enteral tube feeding is the preferred route over parenteral nutrition, and the nurse plays a key role in facilitating timely tube placement and feeding initiation.', 'Pre-Council', '🎓', true),
(8658, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which patient outcome is most directly used as evidence that nutritional support has been adequate in a critically ill patient?', '["Progressive wound healing, preservation of lean body mass, and improved functional status", "A decrease in the patient''s respiratory rate to zero", "An increase in serum creatinine", "A rising body temperature"]'::jsonb, 0, 'Positive indicators that nutrition support is adequate include timely wound healing, preservation (rather than continued loss) of lean body mass, improved strength/functional status, and stabilisation or improvement of visceral protein trends alongside clinical recovery.', 'Pre-Council', '🎓', true),
(8659, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Adequate nutritional support in critically ill patients has been associated with which of the following outcome benefits, according to critical care nutrition evidence?', '["Increased rates of infection and prolonged ventilator dependence", "Reduced infectious complications, shorter ICU length of stay, and improved wound healing", "No measurable effect on any clinical outcome", "Universal need for permanent TPN"]'::jsonb, 1, 'Adequate, appropriately timed nutrition support in critical illness has been linked in the literature to reduced infectious complications, better preservation of immune function, improved wound healing, and shorter ICU and hospital length of stay.', 'Pre-Council', '🎓', true),
(8660, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In trauma patients, achieving adequate protein and caloric intake supports which important outcome related to skeletal muscle?', '["Accelerated muscle wasting despite feeding", "Attenuation of lean body mass and muscle protein loss, supporting preservation of strength and earlier mobilisation", "Complete prevention of any muscle catabolism regardless of injury severity", "Immediate return to pre-injury muscle mass within 48 hours"]'::jsonb, 1, 'While critical illness catabolism cannot be entirely eliminated by nutrition alone, adequate protein/caloric provision helps attenuate the rate of lean body mass loss, supporting preservation of strength, easier ventilator weaning, and earlier mobilisation.', 'Pre-Council', '🎓', true),
(8661, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Failure to provide adequate nutritional support in a critically ill patient is most closely associated with which negative outcome?', '["Improved immune competence", "Increased risk of infection, impaired wound healing, prolonged mechanical ventilation, and increased mortality risk", "Decreased length of hospital stay", "Enhanced respiratory muscle strength"]'::jsonb, 1, 'Malnutrition and inadequate nutrition support in critical illness are associated with impaired immune function, poor wound healing, respiratory muscle weakness prolonging ventilator dependence, and increased morbidity and mortality.', 'Pre-Council', '🎓', true),
(8662, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A positive nitrogen balance in a recovering critically ill patient receiving nutritional support indicates:', '["Ongoing severe catabolism with net protein loss", "That protein intake now exceeds nitrogen losses, suggesting an anabolic state favouring tissue repair", "Inadequate caloric intake", "Acute kidney injury"]'::jsonb, 1, 'A positive nitrogen balance means nitrogen intake exceeds nitrogen output, indicating the body is in an anabolic state where protein synthesis exceeds breakdown — a favourable outcome supporting tissue repair and recovery.', 'Pre-Council', '🎓', true),
(8663, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which functional outcome measure is increasingly used in critical care to evaluate whether nutritional and rehabilitative interventions have been effective, beyond simple survival?', '["Post-ICU physical function and ability to perform activities of daily living", "Room temperature during the ICU stay", "Number of visitors per day", "Colour of the patient''s bed linens"]'::jsonb, 0, 'Beyond mortality, functional outcomes such as physical strength, ability to perform activities of daily living, and quality of life after ICU discharge are important measures of whether nutrition and rehabilitation support were effective.', 'Pre-Council', '🎓', true),
(8664, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In the context of critical illness, why might achieving 100% of calculated caloric goals within the first week NOT necessarily correlate with the best patient outcomes?', '["Because permissive underfeeding or moderate protein-focused feeding early in critical illness has been associated in some trials with outcomes comparable to or better than full early caloric feeding, possibly by avoiding overfeeding complications", "Because calories have no relationship to outcomes whatsoever", "Because critically ill patients never need any calories", "Because achieving caloric goals always causes immediate death"]'::jsonb, 0, 'Some clinical trials have shown that early full caloric feeding is not clearly superior to and may be inferior to slightly hypocaloric, protein-adequate feeding in the acute phase of critical illness, likely because overfeeding drives hyperglycaemia, increased CO2 production, and other complications that offset caloric benefit.', 'Pre-Council', '🎓', true),
(8665, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Preventing refeeding syndrome-related cardiac and respiratory complications during nutrition support is an important patient safety outcome achieved primarily through:', '["Ignoring baseline electrolyte levels before starting feeding", "Identifying at-risk patients, starting nutrition support cautiously, and correcting/monitoring electrolytes proactively", "Feeding all patients at maximal caloric goals immediately", "Delaying electrolyte correction until after symptoms of arrhythmia appear"]'::jsonb, 1, 'The desired outcome of avoiding refeeding syndrome complications (cardiac arrhythmia, respiratory failure) is achieved through proactive risk identification, cautious initial caloric dosing, and close electrolyte monitoring/correction rather than reactive management after complications occur.', 'Pre-Council', '🎓', true),
(8666, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Assessing nutritional status in a critically ill, severely malnourished patient is complicated primarily because:', '["Critical illness and fluid resuscitation alter body weight, serum protein levels, and inflammatory markers, making standard nutritional indices less reliable", "Malnutrition never occurs in critically ill patients", "Laboratory tests are unaffected by critical illness", "Physical examination findings are always normal in critical illness"]'::jsonb, 0, 'Aggressive fluid resuscitation, third-spacing, and the systemic inflammatory response in critical illness can mask or exaggerate weight changes and depress serum proteins independent of true nutritional status, complicating interpretation of standard nutritional indices.', 'Pre-Council', '🎓', true),
(8667, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In a critically ill malnourished patient with significant oedema from fluid resuscitation, which assessment approach is most reliable for estimating true nutritional status?', '["Relying solely on current admission body weight", "Combining pre-illness weight history, mid-upper arm circumference, and clinical/functional history (as in SGA) rather than relying on current weight or albumin alone", "Using serum albumin alone as the sole indicator", "Ignoring nutritional assessment until oedema resolves completely"]'::jsonb, 1, 'Because fluid shifts distort current weight and inflammation lowers albumin independent of nutrition, a reliable assessment in this setting combines historical weight trends, physical exam/functional history (as used in SGA), and measurements less affected by fluid status such as MUAC.', 'Pre-Council', '🎓', true),
(8668, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Which historical feature, when present in a critically ill patient''s history, should heighten suspicion for pre-existing severe malnutrition requiring careful nutrition planning?', '["A history of chronic alcoholism, malignancy with weight loss, or prolonged poor oral intake before admission", "A history of well-controlled hypertension only", "Normal BMI with no comorbidities", "Recent completion of a routine annual physical exam"]'::jsonb, 0, 'Chronic conditions such as alcoholism, malignancy, and prolonged poor intake are strongly associated with pre-existing malnutrition, and identifying such history on admission should trigger careful nutritional assessment and cautious, monitored refeeding.', 'Pre-Council', '🎓', true),
(8669, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'A critically ill malnourished patient is identified as being at high risk for refeeding syndrome based on which of the following criteria (per commonly used risk criteria such as NICE)?', '["BMI greater than 30 kg/m2 with no other risk factors", "BMI less than 16 kg/m2, or unintentional weight loss greater than 15% in the past 3-6 months, or little/no nutritional intake for more than 10 days", "Normal serum electrolytes with recent consistent oral intake", "A single episode of mild nausea"]'::jsonb, 1, 'Widely used risk criteria (e.g., NICE guidance) identify high refeeding risk based on factors such as very low BMI, substantial recent unintentional weight loss, prolonged minimal intake, or pre-existing low levels of potassium, phosphate, or magnesium.', 'Pre-Council', '🎓', true),
(8670, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In assessing a critically ill patient with kwashiorkor-type protein-energy malnutrition, which classic clinical finding may be observed on physical examination?', '["Severe generalised wasting with no oedema", "Oedema, a distended abdomen, and skin/hair changes despite sometimes preserved or normal body weight due to fluid retention", "Excessive muscle bulk", "Hypertension as the primary presenting sign"]'::jsonb, 1, 'Kwashiorkor, a form of severe protein malnutrition, classically presents with oedema (which can mask weight loss), a distended abdomen (sometimes due to hepatomegaly/ascites), and dermatological and hair changes, distinguishing it from the pure wasting seen in marasmus.', 'Pre-Council', '🎓', true),
(8671, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Marasmus, as a form of severe malnutrition, is primarily characterised by:', '["Severe oedema with preserved fat and muscle stores", "Severe deficiency of both calories and protein leading to marked wasting of fat and muscle without significant oedema", "Isolated vitamin C deficiency", "Excess adipose tissue with normal muscle mass"]'::jsonb, 1, 'Marasmus results from chronic overall energy and protein deficiency, producing severe wasting of both fat and muscle mass, typically without the oedema characteristic of kwashiorkor.', 'Pre-Council', '🎓', true),
(8672, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'When assessing a critically ill malnourished patient''s readiness to begin nutrition support, which baseline laboratory panel is essential before initiating feeding to reduce refeeding syndrome risk?', '["Baseline serum phosphate, potassium, magnesium, and glucose", "Baseline urine culture only", "Baseline lipid panel only", "Baseline thyroid function tests only"]'::jsonb, 0, 'Checking baseline phosphate, potassium, magnesium, and glucose before starting nutrition support in an at-risk malnourished patient allows correction of pre-existing deficits and establishes values against which to monitor for the electrolyte shifts of refeeding syndrome.', 'Pre-Council', '🎓', true),
(8673, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'Functional assessment (e.g., hand-grip strength testing) is sometimes incorporated into nutritional assessment of critically ill patients because it:', '["Directly measures caloric intake", "Provides an objective indicator of muscle strength/function that can reflect the functional impact of malnutrition beyond static body measurements", "Replaces the need for any dietary or biochemical assessment", "Is used only to assess cognitive function"]'::jsonb, 1, 'Hand-grip strength is a simple, objective functional measure that correlates with muscle mass and function; declining grip strength can indicate the functional consequences of malnutrition and catabolism, complementing static measures like weight and albumin.', 'Pre-Council', '🎓', true),
(8674, 'Nutrition Fundamentals and Assessment', 'CCN Curriculum — Applied Nutrition', 'In a critically ill malnourished patient, why is a multidisciplinary approach (nurse, dietitian, physician, and pharmacist) particularly important for nutritional assessment and planning?', '["Because nutritional care in complex, malnourished critically ill patients requires integration of clinical assessment, metabolic calculation, medication review, and ongoing bedside monitoring that no single discipline can fully provide alone", "Because nurses have no role in nutritional care", "Because only physicians are permitted to discuss nutrition with patients", "Because dietitians alone can prescribe all ICU medications"]'::jsonb, 0, 'Complex critically ill malnourished patients benefit from a multidisciplinary approach where the dietitian calculates requirements, the physician manages the overall clinical picture and access, the pharmacist reviews interactions/additives, and the bedside nurse performs ongoing assessment, monitoring, and delivery of the nutrition plan.', 'Pre-Council', '🎓', true),
(8675, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Total parenteral nutrition (TPN) is best defined as:', '["Administration of a complete nutrient solution (carbohydrate, protein, fat, vitamins, minerals, water) directly into the venous circulation, bypassing the GI tract", "Administration of blenderized food through a nasogastric tube", "Supplemental oral nutritional drinks given between meals", "Administration of isotonic fluids only through a peripheral IV line"]'::jsonb, 0, 'TPN delivers a complete nutritional formulation intravenously, bypassing the gastrointestinal tract entirely, and is used when the gut cannot be used safely or adequately.', 'Pre-Council', '🎓', true),
(8676, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which of the following is the most appropriate indication for initiating TPN in a critically ill patient?', '["A patient who is NPO for a same-day minor procedure", "A patient with mild dysphagia who can tolerate a modified oral diet", "A patient with a prolonged paralytic ileus and non-functioning bowel expected to last more than 7 days", "A patient with stable vital signs who is able to swallow safely after a stroke"]'::jsonb, 2, 'TPN is indicated when the GI tract is non-functional or cannot be safely used for a prolonged period (generally more than 5-7 days), as in prolonged ileus, bowel obstruction, or severe malabsorption.', 'Pre-Council', '🎓', true),
(8677, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which patient is the LEAST appropriate candidate for enteral nutrition and would most likely require TPN instead?', '["A patient with a functioning gut who is intubated and sedated", "A patient recovering from an uncomplicated appendectomy", "A patient with a high-output enterocutaneous fistula and short bowel syndrome", "A patient with dysphagia after a stroke but an otherwise normal GI tract"]'::jsonb, 2, 'A high-output enterocutaneous fistula with short bowel syndrome severely limits the functional absorptive surface of the gut, making TPN the more appropriate route until the gut can be used.', 'Pre-Council', '🎓', true),
(8678, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Because standard TPN solutions have a high osmolarity (often greater than 900 mOsm/L), they must be infused through:', '["A small-gauge peripheral IV catheter in the hand", "A central venous catheter with the tip positioned in the superior vena cava/right atrial junction", "A subcutaneous infusion port", "Any peripheral vein as long as the infusion rate is slow"]'::jsonb, 1, 'The high osmolarity of standard TPN solutions causes phlebitis and vein damage if infused peripherally, so a central line with tip placement near the cavoatrial junction is required.', 'Pre-Council', '🎓', true),
(8679, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Peripheral parenteral nutrition (PPN) differs from TPN in that PPN:', '["Is a more concentrated, higher-osmolarity solution meant for long-term use", "Is a lower-osmolarity solution used for short-term nutritional support through a peripheral vein", "Can only be administered through a subclavian central line", "Provides more total calories per day than TPN"]'::jsonb, 1, 'PPN uses a more dilute, lower-osmolarity formulation suitable for peripheral veins and is intended for short-term, supplemental nutritional support rather than long-term complete nutrition.', 'Pre-Council', '🎓', true),
(8680, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'After insertion of a central venous catheter for TPN, correct catheter tip placement is confirmed by:', '["Auscultating for bowel sounds", "A chest X-ray showing the tip at the superior vena cava/right atrial junction", "Aspirating gastric contents", "Checking the pH of blood return only"]'::jsonb, 1, 'A chest X-ray is the standard method to confirm that the central line tip is correctly positioned before TPN infusion begins, reducing the risk of arrhythmia or vessel injury.', 'Pre-Council', '🎓', true),
(8681, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which insertion site for a central venous catheter is generally associated with the LOWEST risk of catheter-related bloodstream infection?', '["Femoral vein", "Subclavian vein", "Internal jugular vein with a dressing changed daily", "Any site is equally low-risk once inserted"]'::jsonb, 1, 'The subclavian site is associated with a lower infection risk compared with the femoral or internal jugular sites, which is why it is often preferred for longer-term central access when feasible.', 'Pre-Council', '🎓', true),
(8682, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A key advantage of TPN over enteral nutrition is that TPN:', '["Preserves gut mucosal integrity better than enteral feeding", "Can provide complete nutrition when the gastrointestinal tract cannot be used at all", "Has a lower risk of catheter-related bloodstream infection", "Is significantly less expensive than enteral nutrition"]'::jsonb, 1, 'The principal advantage of TPN is that it allows delivery of complete nutrition even when the GI tract is completely non-functional, unlike enteral nutrition which requires a working gut.', 'Pre-Council', '🎓', true),
(8683, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A major disadvantage of TPN compared with enteral nutrition is that TPN:', '["Cannot be adjusted to meet individual caloric needs", "Is associated with a higher risk of catheter-related infection, is more costly, and does not preserve gut mucosal integrity", "Requires the patient to have a functioning gastrointestinal tract", "Cannot be used in patients with renal failure"]'::jsonb, 1, 'TPN carries higher costs and greater risk of catheter-related bloodstream infection than enteral nutrition, and because it bypasses the gut, it does not maintain gut mucosal integrity, increasing the risk of bacterial translocation.', 'Pre-Council', '🎓', true),
(8684, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Loss of gut mucosal integrity with prolonged exclusive use of TPN is clinically significant because it may lead to:', '["Improved immune function", "Bacterial translocation across the gut wall, increasing risk of systemic infection", "Decreased risk of catheter infection", "Enhanced absorption of enteral nutrients"]'::jsonb, 1, 'When the gut is not used, the intestinal mucosa can atrophy, weakening the mucosal barrier and allowing bacteria to translocate from the gut lumen into the bloodstream, increasing septic risk.', 'Pre-Council', '🎓', true),
(8685, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'The most important nursing measure to prevent catheter-related bloodstream infection (CRBSI) in a patient receiving TPN is:', '["Changing the TPN bag every 48 hours", "Using strict aseptic technique for all TPN line insertions, dressing changes, and tubing manipulations, and dedicating the lumen solely to TPN", "Infusing TPN through the same lumen used for blood draws and medication administration", "Applying a gauze dressing that is changed weekly regardless of condition"]'::jsonb, 1, 'Strict aseptic technique and dedicating one catheter lumen exclusively to TPN (not used for blood draws, CVP monitoring, or other infusions) are the cornerstones of CRBSI prevention.', 'Pre-Council', '🎓', true),
(8686, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A transparent semipermeable dressing over a central venous catheter site used for TPN should be changed:', '["Every 24 hours regardless of condition", "Every 7 days, or sooner if it becomes loose, damp, or visibly soiled", "Only when the TPN therapy is discontinued", "Every 2 days without exception"]'::jsonb, 1, 'Transparent semipermeable dressings are typically changed every 7 days, or immediately if they become non-occlusive, damp, or soiled, to reduce infection risk while minimizing unnecessary site disruption.', 'Pre-Council', '🎓', true),
(8687, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'According to standard infection-control practice, IV administration tubing used to deliver a lipid-containing (3-in-1) TPN admixture should be changed:', '["Every 96 hours", "Only when visibly contaminated", "Within 24 hours of starting the infusion", "Once a week"]'::jsonb, 2, 'Because lipid emulsions support rapid microbial growth, administration sets used for lipid-containing TPN admixtures should be changed within 24 hours of initiating the infusion to reduce infection risk.', 'Pre-Council', '🎓', true),
(8688, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A 3-in-1 (total nutrient admixture) TPN solution containing lipid emulsion should be administered through an in-line filter of:', '["0.22 micron", "5 micron", "1.2 micron", "No filter is required for lipid-containing admixtures"]'::jsonb, 2, 'A 1.2 micron filter is used for lipid-containing (3-in-1) admixtures because the smaller 0.22 micron filter would occlude the lipid particles; 0.22 micron filters are reserved for lipid-free (2-in-1) dextrose/amino acid solutions.', 'Pre-Council', '🎓', true),
(8689, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'The nurse notes that a TPN bag containing a lipid emulsion has visible "cracking" or an oily layer separating from the solution. The appropriate action is to:', '["Shake the bag vigorously and hang it as prescribed", "Warm the bag in a basin of warm water before infusing", "Discard the bag and obtain a new one, as this indicates emulsion instability", "Filter the solution through a 5 micron filter before infusing"]'::jsonb, 2, 'Cracking or oiling out of a lipid emulsion indicates destabilization of the emulsion and the solution must not be infused; a new bag should be obtained from pharmacy.', 'Pre-Council', '🎓', true),
(8690, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A nurse retrieves a bag of TPN from the refrigerator. Before hanging it, the nurse should:', '["Infuse it directly from the refrigerator to keep it stable", "Warm it in a microwave to body temperature", "Allow it to reach room temperature and inspect it for particulate matter, discoloration, or separation before infusing", "Add a multivitamin bolus directly into the bag at the bedside"]'::jsonb, 2, 'TPN bags should be allowed to warm to room temperature and be visually inspected for precipitates, cloudiness, or separation before administration; cold infusion can cause patient discomfort and vasoconstriction.', 'Pre-Council', '🎓', true),
(8691, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Medications should generally NOT be injected directly into a hanging TPN bag primarily because:', '["It is more time-consuming than giving medications separately", "TPN bags are opaque and medications cannot be seen once added", "Of the risk of drug-nutrient incompatibility, precipitation, or destabilization of the admixture", "TPN bags do not have injection ports"]'::jsonb, 2, 'Many medications are physically or chemically incompatible with TPN components and can cause precipitation or destabilize the lipid emulsion, so medications should be given through a separate line or lumen rather than added to the TPN bag.', 'Pre-Council', '🎓', true),
(8692, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'During the initiation of TPN, blood glucose should be monitored:', '["Once daily only, since TPN does not affect glucose", "Frequently (e.g., every 4-6 hours or per protocol) because of the risk of hyperglycemia from the dextrose load", "Only if the patient has a prior diagnosis of diabetes", "Only at the end of the TPN infusion"]'::jsonb, 1, 'The high dextrose concentration in TPN combined with stress-induced insulin resistance places patients at risk for hyperglycemia, so frequent glucose monitoring is essential, especially during initiation and rate changes.', 'Pre-Council', '🎓', true),
(8693, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Hyperglycemia in a patient receiving TPN is most directly caused by:', '["The lipid emulsion component of the solution", "The high dextrose (carbohydrate) concentration of the TPN solution combined with stress-related insulin resistance", "Excess protein content in the solution", "Dehydration from the infusion"]'::jsonb, 1, 'TPN solutions are dextrose-rich, and critically ill patients often have stress-induced insulin resistance, making hyperglycemia the most common metabolic complication of TPN therapy.', 'Pre-Council', '🎓', true),
(8694, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'If TPN must be discontinued, the nurse should:', '["Stop the infusion abruptly at any rate without tapering", "Taper the infusion rate down gradually (or per protocol) to prevent rebound hypoglycemia from hyperinsulinemia", "Increase the rate briefly before stopping", "Disconnect the tubing and flush with normal saline at the full TPN rate"]'::jsonb, 1, 'Abrupt cessation of TPN can cause rebound hypoglycemia because the body has been producing increased insulin in response to the continuous high dextrose load; tapering allows insulin levels to normalize.', 'Pre-Council', '🎓', true),
(8695, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A severely malnourished patient is started on aggressive TPN feeding. The nurse should monitor closely for refeeding syndrome, which is characterized by:', '["Hyperphosphatemia, hyperkalemia, and hypermagnesemia", "Hypophosphatemia, hypokalemia, hypomagnesemia, and fluid retention", "Hypernatremia and severe hypertension", "Hypercalcemia and metabolic alkalosis"]'::jsonb, 1, 'Refeeding syndrome occurs when aggressive nutrition is reintroduced after prolonged starvation, causing an insulin-driven intracellular shift of phosphate, potassium, and magnesium, resulting in dangerous hypophosphatemia, hypokalemia, hypomagnesemia, and fluid retention.', 'Pre-Council', '🎓', true),
(8696, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'The single most characteristic laboratory finding used to identify refeeding syndrome is:', '["Hypophosphatemia", "Hyperglycemia", "Hypercalcemia", "Elevated blood urea nitrogen"]'::jsonb, 0, 'Hypophosphatemia is the hallmark biochemical abnormality of refeeding syndrome, resulting from an intracellular shift of phosphate driven by insulin release once carbohydrate feeding resumes.', 'Pre-Council', '🎓', true),
(8697, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'To reduce the risk of refeeding syndrome in a severely malnourished critically ill patient starting nutrition support, the nurse anticipates that the plan of care will include:', '["Starting TPN at the full calculated caloric goal immediately to correct malnutrition quickly", "Starting nutrition at a low caloric rate, advancing gradually, and repleting electrolytes (phosphate, potassium, magnesium) and thiamine before and during feeding", "Withholding all electrolyte supplementation until feeding is complete", "Restricting fluids to less than 500 mL per day regardless of feeding rate"]'::jsonb, 1, 'Prevention of refeeding syndrome involves initiating feeding cautiously at a low caloric rate with gradual advancement, along with proactive electrolyte and thiamine repletion, rather than aggressive early full-calorie feeding.', 'Pre-Council', '🎓', true),
(8698, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'During a TPN tubing change, the nurse observes the patient suddenly become dyspneic, anxious, and hypotensive with a churning heart murmur. The nurse suspects an air embolism and should immediately:', '["Place the patient in high Fowler''s position and call for a chest X-ray", "Clamp the catheter and place the patient in the Trendelenburg position on the left side (Durant''s maneuver), then notify the provider", "Flush the catheter rapidly with normal saline to clear the air", "Disconnect the catheter completely and apply a dry dressing"]'::jsonb, 1, 'For suspected air embolism, the catheter should be clamped immediately and the patient placed in the Trendelenburg, left lateral decubitus position (Durant''s maneuver) to trap air in the right atrium away from the pulmonary outflow tract, followed by prompt provider notification and oxygen administration.', 'Pre-Council', '🎓', true),
(8699, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'During insertion of a subclavian central line for TPN, the patient suddenly develops sharp chest pain, dyspnea, and decreased breath sounds on the affected side. The nurse should suspect:', '["Air embolism", "Pneumothorax", "Catheter occlusion", "Hyperglycemia"]'::jsonb, 1, 'Pneumothorax is a recognized mechanical complication of subclavian or internal jugular central line placement, presenting with sudden chest pain, dyspnea, and diminished breath sounds on the affected side.', 'Pre-Council', '🎓', true),
(8700, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Long-term TPN administration, particularly with excessive dextrose (overfeeding), is most associated with which hepatic complication?', '["Acute viral hepatitis", "Hepatic steatosis (fatty liver) and TPN-associated liver disease", "Hepatorenal syndrome", "Hepatitis B reactivation"]'::jsonb, 1, 'Prolonged TPN, especially with excess dextrose/caloric overfeeding, is a well-known cause of hepatic steatosis and TPN-associated liver disease, so caloric intake should be carefully calculated rather than overfed.', 'Pre-Council', '🎓', true),
(8701, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient receiving prolonged TPN without any oral or enteral intake is at increased risk for which biliary complication?', '["Acute cholecystitis and gallbladder sludge from bile stasis due to lack of enteral stimulation", "Choledocholithiasis caused by excess bile acid synthesis", "Pancreatic pseudocyst formation", "Gastric ulcer perforation"]'::jsonb, 0, 'Without oral or enteral intake to stimulate cholecystokinin release and gallbladder contraction, bile stasis and gallbladder sludge/stones can develop during prolonged exclusive TPN use.', 'Pre-Council', '🎓', true),
(8702, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient receiving TPN without any lipid emulsion for an extended period is at risk for developing:', '["Essential fatty acid deficiency", "Vitamin K toxicity", "Hypertriglyceridemia", "Iron overload"]'::jsonb, 0, 'Lipid emulsions supply essential fatty acids; prolonged TPN administration without lipids can result in essential fatty acid deficiency, manifesting as dry, scaly skin and impaired wound healing.', 'Pre-Council', '🎓', true),
(8703, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient receiving a lipid-containing TPN infusion should have which laboratory value monitored to detect a potential metabolic complication of the lipid emulsion?', '["Serum triglyceride level", "Serum uric acid level", "Serum bilirubin level only", "Serum amylase level only"]'::jsonb, 0, 'Lipid emulsions can cause hypertriglyceridemia, particularly if infused too rapidly, so serum triglyceride levels should be monitored periodically during lipid administration.', 'Pre-Council', '🎓', true),
(8704, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A central venous catheter used for TPN becomes difficult to flush and there is no blood return, suggesting catheter occlusion. The nurse''s FIRST action should be to:', '["Forcefully flush the catheter with a small syringe to clear the occlusion", "Assess the catheter and notify the provider; avoid forceful flushing, which can dislodge a clot or rupture the catheter", "Remove the catheter immediately without further assessment", "Increase the TPN infusion rate to push the occlusion through"]'::jsonb, 1, 'Forceful flushing of an occluded catheter risks dislodging a thrombus (causing embolism) or rupturing the catheter; occlusion should be assessed and managed per protocol, often with a declotting agent ordered by the provider, not forced clearance.', 'Pre-Council', '🎓', true),
(8705, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'As a patient''s enteral or oral intake increases and becomes adequate, the nurse anticipates that TPN will be:', '["Stopped abruptly on the same day oral intake begins", "Gradually tapered down as enteral or oral intake increases, to avoid overfeeding and to allow smooth transition", "Increased in rate to supplement the new oral intake", "Continued unchanged indefinitely regardless of oral intake"]'::jsonb, 1, 'TPN should be weaned gradually as enteral or oral intake becomes sufficient to meet nutritional needs, preventing overfeeding while ensuring a safe transition and avoiding rebound hypoglycemia.', 'Pre-Council', '🎓', true),
(8706, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Cyclic TPN, in which the infusion is given over a shortened period (e.g., 12-16 hours, often overnight) rather than continuously over 24 hours, is most commonly used for:', '["Patients in acute hemodynamic instability", "Long-term or home TPN patients, to allow greater mobility and reduce hepatic complications", "Patients who are NPO for a same-day procedure", "Patients with acute pancreatitis in the first 24 hours of ICU admission"]'::jsonb, 1, 'Cyclic TPN is typically used for stable, long-term or home TPN patients because infusing over a shorter period (often overnight) allows greater freedom of movement during the day and may reduce the risk of TPN-associated liver complications.', 'Pre-Council', '🎓', true),
(8707, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient receiving TPN should have body weight measured:', '["Only once at initiation of TPN", "Daily, using the same scale and time of day, to help assess fluid balance and nutritional response", "Only after TPN is discontinued", "Weekly, regardless of clinical status"]'::jsonb, 1, 'Daily weights, obtained consistently, help the care team assess fluid status and evaluate the effectiveness of nutritional support in a patient receiving TPN.', 'Pre-Council', '🎓', true),
(8708, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which combination of laboratory values should be monitored most closely, especially during the first several days of TPN therapy?', '["Serum electrolytes (including phosphate, potassium, magnesium), blood glucose, and triglycerides", "Serum bilirubin only", "Hemoglobin A1c only, checked weekly", "Urine specific gravity only"]'::jsonb, 0, 'Electrolytes, glucose, and triglycerides can shift rapidly with TPN initiation, particularly in malnourished or critically ill patients, so close laboratory monitoring is essential in the early days of therapy.', 'Pre-Council', '🎓', true),
(8709, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Compared with enteral nutrition, one of the primary disadvantages of TPN that affects healthcare resource use is that TPN:', '["Is generally less expensive to prepare and administer", "Requires more complex compounding, specialized administration equipment, and is significantly more costly overall", "Requires no pharmacy involvement in preparation", "Can be prepared safely at the bedside without sterile technique"]'::jsonb, 1, 'TPN solutions require sterile pharmacy compounding, specialized central venous access, infusion pumps, and more intensive monitoring, making it considerably more resource-intensive and costly than enteral nutrition.', 'Pre-Council', '🎓', true),
(8710, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A nurse caring for a patient receiving TPN understands that organisms commonly implicated in catheter-related bloodstream infection in TPN patients include:', '["Coagulase-negative staphylococci and Candida species (the latter related to the high dextrose content)", "Mycobacterium tuberculosis exclusively", "Influenza virus", "Clostridioides difficile exclusively"]'::jsonb, 0, 'Coagulase-negative staphylococci are common skin-flora contaminants of central lines, and the high glucose content of TPN solutions also increases the risk of catheter-related candidemia.', 'Pre-Council', '🎓', true),
(8711, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which nursing action best supports early identification of a TPN-related infection?', '["Assessing the catheter insertion site for redness, warmth, swelling, or drainage at each shift, along with monitoring temperature trends", "Assessing the insertion site only once weekly during dressing changes", "Relying solely on the patient''s subjective report of pain", "Checking the site only if the patient develops hypotension"]'::jsonb, 0, 'Regular, frequent assessment of the catheter site for signs of local infection, combined with ongoing temperature monitoring, allows early detection of catheter-related infection before systemic sepsis develops.', 'Pre-Council', '🎓', true),
(8712, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient on long-term home TPN develops fever, chills, and hypotension shortly after the TPN infusion is started, with no other clear source of infection. The nurse should suspect:', '["A normal expected reaction to TPN that requires no action", "Catheter-related bloodstream infection and should notify the provider promptly, obtaining blood cultures as ordered", "Hypoglycemia from TPN discontinuation", "An allergic reaction to the feeding tube"]'::jsonb, 1, 'Fever, chills, and hypotension temporally related to a central line infusion strongly suggest catheter-related bloodstream infection, requiring prompt provider notification and blood cultures, often drawn from the catheter and a peripheral site.', 'Pre-Council', '🎓', true),
(8713, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which statement about TPN administration equipment is CORRECT?', '["A dedicated infusion pump should be used to deliver TPN at a precisely controlled rate", "TPN may be infused by gravity drip without a pump to save time", "Any general-purpose non-dedicated IV pump setting is acceptable without rate verification", "TPN does not require a pump because the rate is not clinically significant"]'::jsonb, 0, 'Because of the metabolic risks of both underfeeding and overfeeding, and the risk of rebound hypoglycemia with abrupt rate changes, TPN must be delivered via a dedicated infusion pump with a precisely controlled rate.', 'Pre-Council', '🎓', true),
(8714, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'The rationale for reserving one lumen of a multi-lumen central catheter exclusively for TPN administration is to:', '["Increase the total infusion rate available", "Reduce the risk of contamination and catheter-related bloodstream infection by minimizing manipulation of that lumen", "Allow blood to be drawn more easily from that lumen", "Comply with insurance billing requirements"]'::jsonb, 1, 'Dedicating a single lumen to TPN and avoiding its use for blood draws, medication administration, or CVP monitoring reduces the frequency of line manipulation and the associated risk of introducing pathogens.', 'Pre-Council', '🎓', true),
(8715, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Enteral nutrition (EN) is best defined as:', '["Delivery of nutrients directly into the venous circulation", "Delivery of nutrients into the gastrointestinal tract via a feeding tube (or orally) when a patient has a functioning gut but cannot meet nutritional needs by mouth alone", "Delivery of nutrients exclusively by mouth in small frequent meals", "Delivery of intravenous fluids and electrolytes without any caloric content"]'::jsonb, 1, 'Enteral nutrition uses the gastrointestinal tract, typically via a feeding tube (nasogastric, orogastric, gastrostomy, or jejunostomy), to deliver nutrition when the gut is functional but oral intake is inadequate or unsafe.', 'Pre-Council', '🎓', true),
(8716, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'The guiding clinical principle for choosing between enteral and parenteral nutrition in a critically ill patient is best summarized as:', '["\"If the gut works, use it\" \u2014 enteral nutrition is preferred whenever the GI tract is functional", "Parenteral nutrition should always be used first regardless of GI function", "Enteral and parenteral nutrition are equally preferred with no clinical rationale for choosing one over the other", "Oral intake should always be attempted before any tube feeding is considered, regardless of aspiration risk"]'::jsonb, 0, 'The core principle of nutrition support is that enteral feeding should be used whenever the gastrointestinal tract is functional, because it is safer, more physiologic, and less costly than parenteral nutrition.', 'Pre-Council', '🎓', true),
(8717, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which of the following patients is the MOST appropriate candidate for enteral rather than parenteral nutrition?', '["A patient with a functioning GI tract who is intubated and cannot swallow safely due to sedation", "A patient with a complete bowel obstruction", "A patient with severe, uncontrolled upper GI hemorrhage", "A patient in septic shock requiring escalating vasopressor doses with signs of bowel ischemia"]'::jsonb, 0, 'An intubated, sedated patient with an otherwise functional gastrointestinal tract is an ideal candidate for enteral nutrition via a feeding tube, since the barrier to oral intake is the inability to swallow safely, not a non-functional gut.', 'Pre-Council', '🎓', true),
(8718, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A major advantage of enteral nutrition over parenteral nutrition is that enteral feeding:', '["Helps preserve gut mucosal integrity and reduces the risk of bacterial translocation", "Requires central venous access", "Has a higher risk of catheter-related bloodstream infection", "Bypasses the need for a functioning gastrointestinal tract"]'::jsonb, 0, 'Using the gut maintains villous architecture and mucosal immune function, reducing bacterial translocation and the associated risk of septic complications compared with bowel rest and TPN.', 'Pre-Council', '🎓', true),
(8719, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Compared with parenteral nutrition, enteral nutrition is generally associated with:', '["Higher cost and higher infection risk", "Lower cost, lower infection risk, and more physiologic nutrient metabolism", "The same cost and the same infection risk", "A requirement for central venous access"]'::jsonb, 1, 'Enteral nutrition is less expensive, carries a lower risk of serious infectious complications than central line-associated TPN, and allows more physiologic processing of nutrients through the portal circulation.', 'Pre-Council', '🎓', true),
(8720, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Current critical care nutrition guidelines generally recommend initiating enteral nutrition in a hemodynamically stable, critically ill patient:', '["Only after 7-10 days of ICU admission", "Within 24-48 hours of ICU admission once the patient is hemodynamically stable", "Only after the patient is extubated", "Only if the patient specifically requests it"]'::jsonb, 1, 'Early enteral nutrition, typically initiated within 24-48 hours of ICU admission in hemodynamically stable patients, is associated with improved outcomes by preserving gut integrity and reducing infectious complications.', 'Pre-Council', '🎓', true),
(8721, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which of the following is an appropriate CONTRAINDICATION to enteral nutrition?', '["Mechanical ventilation with sedation", "Mild dysphagia after a stroke", "Complete bowel obstruction or severe paralytic ileus", "A stable postoperative patient after minor surgery"]'::jsonb, 2, 'Enteral nutrition requires a patent, functioning gastrointestinal tract; complete bowel obstruction or severe ileus are contraindications because feeding cannot pass through or be absorbed appropriately.', 'Pre-Council', '🎓', true),
(8722, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Enteral nutrition should generally be held or approached with caution in a patient who has:', '["Stable vital signs on no vasopressor support", "Severe hemodynamic instability requiring escalating vasopressor doses, due to risk of bowel ischemia", "A nasogastric tube in the correct position confirmed by X-ray", "Normal bowel sounds and passage of flatus"]'::jsonb, 1, 'In patients with severe hemodynamic instability or escalating vasopressor requirements, enteral feeding is approached cautiously or held because of the risk of non-occlusive bowel ischemia from reduced splanchnic perfusion.', 'Pre-Council', '🎓', true),
(8723, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'The gold-standard method for confirming initial placement of a blindly inserted nasogastric or orogastric feeding tube before starting feeds is:', '["Auscultation of air insufflation over the epigastrium (the \"whoosh test\")", "Abdominal or chest X-ray", "Observing the patient for coughing during insertion only", "Checking that the external tube length looks approximately correct"]'::jsonb, 1, 'Radiographic confirmation (X-ray) is the gold standard for verifying correct placement of a blindly inserted feeding tube before the first feeding or medication is given, since auscultation alone is unreliable and can miss tracheobronchial placement.', 'Pre-Council', '🎓', true),
(8724, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Why is the auscultatory "whoosh test" (injecting air and listening over the epigastrium) NOT considered a reliable sole method for confirming feeding tube placement?', '["It requires specialized equipment not available at the bedside", "Sounds transmitted from a misplaced tube in the lung or esophagus can mimic gastric placement, leading to false reassurance", "It takes too long to perform in an emergency", "It can only be performed by a physician"]'::jsonb, 1, 'Auscultation can be misleading because sounds may be transmitted across the chest and abdomen even when the tube is malpositioned in the esophagus or respiratory tract, so it should not be relied upon alone; radiographic confirmation is the gold standard.', 'Pre-Council', '🎓', true),
(8725, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'For a patient expected to need enteral tube feeding for only 2-3 weeks, the most appropriate feeding access is:', '["A percutaneous endoscopic gastrostomy (PEG) tube", "A short-term nasogastric or orogastric tube", "A surgically placed jejunostomy", "Total parenteral nutrition"]'::jsonb, 1, 'Short-term nasogastric or orogastric tubes are appropriate when enteral access is needed for less than approximately 4 weeks; longer-term needs are better served by a gastrostomy or jejunostomy.', 'Pre-Council', '🎓', true),
(8726, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient is expected to require long-term (greater than 4 weeks) enteral feeding after a severe stroke with persistent dysphagia. The most appropriate feeding access for this patient is:', '["A nasogastric tube left in place indefinitely", "A percutaneous endoscopic gastrostomy (PEG) tube", "An orogastric tube", "Oral supplements only"]'::jsonb, 1, 'For anticipated long-term enteral nutrition (generally more than 4 weeks), a PEG tube is preferred over a long-term nasogastric tube because it is more comfortable, has a lower risk of nasal/sinus complications, and is more secure.', 'Pre-Council', '🎓', true),
(8727, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient with a suspected basilar skull fracture requires enteral tube feeding. The nurse should anticipate that the provider will avoid a nasogastric tube and instead choose:', '["An orogastric tube, because a nasally inserted tube risks intracranial passage through the fracture", "A peripheral IV for TPN only", "A nasogastric tube inserted very gently", "Withholding all nutrition until the fracture heals"]'::jsonb, 0, 'In suspected basilar skull fracture, blind nasal insertion of a tube risks passage through the fracture into the cranial vault; an orogastric route is used instead to avoid this catastrophic complication.', 'Pre-Council', '🎓', true),
(8728, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A jejunal (post-pyloric) feeding tube is generally preferred over a gastric feeding tube in which situation?', '["A patient with normal gastric emptying and low aspiration risk", "A patient with gastroparesis or a high risk of aspiration", "A patient who will be extubated within 24 hours", "A patient with a normal swallow evaluation"]'::jsonb, 1, 'Post-pyloric (jejunal) feeding bypasses the stomach and is associated with a lower risk of reflux and aspiration, making it preferable in patients with delayed gastric emptying (gastroparesis) or a high aspiration risk.', 'Pre-Council', '🎓', true),
(8729, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'To reduce the risk of aspiration during enteral tube feeding, the nurse should maintain the head of the bed at:', '["0 degrees (flat) at all times", "30-45 degrees during feeding and for a period afterward (or continuously with continuous feeds)", "90 degrees only during medication administration", "10-15 degrees, which is sufficient for all patients"]'::jsonb, 1, 'Elevating the head of the bed to 30-45 degrees during enteral feeding and for a period after intermittent feeds (or continuously during continuous feeds) is a key aspiration-prevention measure.', 'Pre-Council', '🎓', true),
(8730, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'The single most serious complication of enteral tube feeding that nursing care aims to prevent through positioning and placement checks is:', '["Constipation", "Aspiration pneumonia", "Mild abdominal bloating", "Tube discoloration"]'::jsonb, 1, 'Aspiration pneumonia is the most serious and potentially life-threatening complication of enteral nutrition, which is why HOB elevation, placement verification, and gastric residual monitoring are emphasized in nursing care.', 'Pre-Council', '🎓', true),
(8731, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Per current evidence-based critical care nutrition guidance, gastric residual volume (GRV) monitoring should generally prompt the nurse to hold or reassess feeding when the volume exceeds approximately:', '["50 mL", "500 mL", "1500 mL", "GRV should never be checked regardless of volume"]'::jsonb, 1, 'Current guidance from major critical care nutrition societies suggests holding or reassessing feeds when GRV exceeds approximately 500 mL, since routinely stopping feeds at lower volumes has not been shown to reduce aspiration risk and can lead to unnecessary underfeeding.', 'Pre-Council', '🎓', true),
(8732, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A nurse checks the gastric residual volume of a critically ill patient receiving continuous enteral feeding and obtains 150 mL. The MOST appropriate action is to:', '["Stop the enteral feeding permanently", "Return the aspirate to the stomach (per protocol) and continue the feeding, since this volume alone does not indicate intolerance", "Discard the aspirate and switch the patient immediately to TPN", "Call a rapid response for suspected bowel obstruction"]'::jsonb, 1, 'A gastric residual volume of 150 mL is not considered high enough to warrant stopping feeds under current guidance; the aspirate is typically returned and feeding continues while the patient is monitored for other signs of intolerance.', 'Pre-Council', '🎓', true),
(8733, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient receiving continuous enteral feeding has an elevated gastric residual volume along with abdominal distension and vomiting. In addition to notifying the provider, the nurse should anticipate that management may include:', '["Immediately increasing the feeding rate to \"push through\" the intolerance", "Considering a prokinetic agent (e.g., metoclopramide) and reassessing tube position and feeding tolerance rather than automatically discontinuing all nutrition support", "Removing the feeding tube permanently without further evaluation", "Placing the patient supine to reduce reflux"]'::jsonb, 1, 'When true feeding intolerance is present (elevated GRV with distension and vomiting), providers may order a prokinetic agent to improve gastric motility and further assess the situation, rather than reflexively stopping all enteral nutrition or worsening aspiration risk with a supine position.', 'Pre-Council', '🎓', true),
(8734, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Before administering an intermittent (bolus) enteral feeding, the nurse should verify tube placement and gastric residual volume, and should also:', '["Lower the head of the bed to flat to ease tube insertion", "Confirm the head of the bed is elevated to at least 30-45 degrees before beginning the feeding", "Administer the feeding as rapidly as possible to save time", "Skip placement verification if the tube was checked the previous day"]'::jsonb, 1, 'Prior to each intermittent feeding, the nurse should reconfirm tube placement, check gastric residual per protocol, and ensure the head of the bed is elevated to reduce aspiration risk.', 'Pre-Council', '🎓', true),
(8735, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Continuous enteral feeding delivered via an infusion pump over 24 hours is generally preferred over bolus feeding in critically ill ICU patients because continuous feeding:', '["Is more physiologic and mimics normal meal patterns", "Is typically better tolerated, associated with lower gastric residual volumes, and reduces aspiration risk in unstable patients", "Requires less nursing supervision than bolus feeding", "Delivers more total calories per day than bolus feeding for the same formula"]'::jsonb, 1, 'Continuous pump-delivered feeding is generally better tolerated by critically ill patients, producing steadier gastric filling with lower gastric residual volumes and reduced aspiration risk compared with bolus feeding.', 'Pre-Council', '🎓', true),
(8736, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Bolus (intermittent) enteral feeding, in which a set volume is given over a short period several times a day, is most commonly used for:', '["Hemodynamically unstable ICU patients on multiple vasopressors", "Stable patients, often via gastrostomy, who tolerate feeds well and benefit from a more normal meal-like pattern", "Jejunal tube feeding exclusively", "Patients with active severe GI bleeding"]'::jsonb, 1, 'Bolus feeding mimics a normal meal pattern and is generally reserved for more stable patients (often those with a gastrostomy) who tolerate the larger volume delivered over a short time without significant residuals or reflux.', 'Pre-Council', '🎓', true),
(8737, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'To help prevent clogging of a small-bore enteral feeding tube, the nurse should:', '["Flush the tube with 30 mL of water before and after feedings and medication administration", "Avoid flushing the tube to conserve fluid intake", "Flush only once per day regardless of feeding frequency", "Use only carbonated beverages to flush the tube"]'::jsonb, 0, 'Routine flushing with approximately 30 mL of water before and after feedings, and before and after each medication, helps prevent tube occlusion from formula or medication residue.', 'Pre-Council', '🎓', true),
(8738, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'When administering multiple crushed medications through an enteral feeding tube, the nurse should:', '["Mix all medications together in one syringe and administer them simultaneously", "Administer each medication separately, flushing the tube with water between each medication", "Add the medications directly into the feeding formula bag", "Give all medications as fast as possible without flushing"]'::jsonb, 1, 'Medications should be given separately with water flushes between each one to reduce the risk of drug-drug or drug-formula interactions and to reduce the risk of tube occlusion.', 'Pre-Council', '🎓', true),
(8739, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'Which type of medication formulation should generally NOT be crushed for administration through an enteral feeding tube without consulting pharmacy?', '["Immediate-release tablets", "Enteric-coated or sustained/extended-release formulations", "Liquid formulations", "Chewable tablets"]'::jsonb, 1, 'Enteric-coated and sustained/extended-release medications are designed for a specific release pattern; crushing them can cause loss of the coating''s protective function or dangerous rapid release of the full dose, so pharmacy should be consulted for an alternative formulation.', 'Pre-Council', '🎓', true),
(8740, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A standard polymeric enteral formula is most appropriate for a patient with:', '["Severe malabsorption from short bowel syndrome", "A normally functioning gastrointestinal tract with intact digestive and absorptive capacity", "Acute pancreatitis with severe fat malabsorption", "Chylothorax requiring an extremely low-fat formula"]'::jsonb, 1, 'Standard polymeric formulas contain intact proteins, carbohydrates, and fats requiring normal digestive and absorptive function, making them appropriate for patients with a normally functioning GI tract.', 'Pre-Council', '🎓', true),
(8741, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'An elemental or semi-elemental (peptide-based) enteral formula is most appropriate for a patient with:', '["Normal digestive function requiring standard caloric support", "Significant malabsorption, such as short bowel syndrome or severe pancreatic insufficiency", "Well-controlled type 2 diabetes without GI disease", "Mild constipation only"]'::jsonb, 1, 'Elemental and semi-elemental formulas contain pre-digested nutrients (free amino acids or peptides, simple sugars) that require minimal digestion, making them useful for patients with significant malabsorption.', 'Pre-Council', '🎓', true),
(8742, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient receiving enteral feeding develops diarrhea. Which of the following is a common contributing cause the nurse should assess for?', '["Feeding rate that is too slow", "High formula osmolality, rapid infusion rate, formula/tubing contamination, or concurrent antibiotic therapy (e.g., leading to C. difficile)", "Head of bed elevation above 30 degrees", "Use of a calorically dense formula only"]'::jsonb, 1, 'Diarrhea with enteral feeding can result from several factors including high osmolality formulas, feeding rate advanced too quickly, bacterial contamination, sorbitol-containing liquid medications, or antibiotic-associated diarrhea such as C. difficile infection.', 'Pre-Council', '🎓', true),
(8743, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'For a patient experiencing enteral feeding-associated diarrhea without evidence of infection, the care team may consider changing to a formula that:', '["Contains added fiber to help normalize stool consistency", "Has an even higher osmolality than the current formula", "Is infused as a rapid bolus rather than continuously", "Contains no protein"]'::jsonb, 0, 'Fiber-containing enteral formulas can help normalize bowel function and may reduce diarrhea in appropriate patients once infectious causes have been ruled out.', 'Pre-Council', '🎓', true),
(8744, 'Feeding Methods', 'CCN Curriculum — Applied Nutrition', 'A patient with a percutaneous endoscopic gastrostomy (PEG) tube requires site care. The nurse should assess the site for:', '["Redness, drainage, leakage of gastric contents, and correct position of the external bumper against the skin", "Only the color of the feeding formula", "Bowel sounds in all four quadrants", "Peripheral pulses distal to the site"]'::jsonb, 0, 'PEG site care includes daily assessment for signs of local infection (redness, drainage), leakage around the tube, and confirming the external bumper is positioned appropriately (not too tight, which risks buried bumper syndrome, or too loose, which risks leakage).', 'Pre-Council', '🎓', true);
